-- Poems batch 377
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f358223a-d024-4b7c-a4df-7a4b0f827a1e','去歲道巴陵登岳陽樓以望洞庭真天下之壯觀也因誦孟浩然氣蒸雲夢澤波撼岳陽城之句追古今絕唱用以爲韻賦詩十篇  其五','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','江湖渺無涯，悵然懷震澤。',48,'全唐诗/poet.song.89000.json','["江湖渺無涯，悵然懷震澤。", "地分吳楚遠，天共雲水白。", "鱸魚正堪膾，蟹螯亦可擘。", "何日歸去來，秋風思遷客。"]'),
('a45ff35f-16b5-46a5-a055-b35a39f65f7e','去歲道巴陵登岳陽樓以望洞庭真天下之壯觀也因誦孟浩然氣蒸雲夢澤波撼岳陽城之句追古今絕唱用以爲韻賦詩十篇  其六','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','西風木葉脫，洞庭水層波。',48,'全唐诗/poet.song.89000.json','["西風木葉脫，洞庭水層波。", "蘋芷滿洲渚，有懷憂思多。", "眇眇帝子愁，欲降山之阿。", "蘭蒸奠桂酒，浩唱聞九歌。"]'),
('bbe9ae07-5b0d-4c12-8902-4f6fbb848d66','去歲道巴陵登岳陽樓以望洞庭真天下之壯觀也因誦孟浩然氣蒸雲夢澤波撼岳陽城之句追古今絕唱用以爲韻賦詩十篇  其七','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','湖光如鏡平，風雨一搖蕩。',48,'全唐诗/poet.song.89000.json','["湖光如鏡平，風雨一搖蕩。", "蜿蜒舞翠蛟，洶湧疊銀浪。", "帆檣走陣馬，勢出霄漢上。", "吾生幸可惜，何事魚腹葬。"]'),
('d2227b8a-0afb-4cc7-9e01-c1f973b6ee3d','去歲道巴陵登岳陽樓以望洞庭真天下之壯觀也因誦孟浩然氣蒸雲夢澤波撼岳陽城之句追古今絕唱用以爲韻賦詩十篇  其八','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','濯足洞庭波，秋髙翠增岳。',48,'全唐诗/poet.song.89000.json','["濯足洞庭波，秋髙翠增岳。", "美人渺何在，使我懷抱惡。", "悠悠江湖深，坐阻關山邈。", "採蘭亦寄之，終朝不盈握。"]'),
('4a7efc10-e71d-41f9-b84c-b6987c402ac6','去歲道巴陵登岳陽樓以望洞庭真天下之壯觀也因誦孟浩然氣蒸雲夢澤波撼岳陽城之句追古今絕唱用以爲韻賦詩十篇  其九','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','重湖望不極，秋色藹殘陽。',48,'全唐诗/poet.song.89000.json','["重湖望不極，秋色藹殘陽。", "洲渚雲沙白，菰蒲霜葉黄。", "飛帆適沅澧，迴鴈過瀟湘。", "楚客經行處，依然蘭芷香。"]'),
('722b7e8d-4f76-4231-9f68-9e40bd4e4f80','去歲道巴陵登岳陽樓以望洞庭真天下之壯觀也因誦孟浩然氣蒸雲夢澤波撼岳陽城之句追古今絕唱用以爲韻賦詩十篇  其一○','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','江湖秋日暮，遠客若爲情。',48,'全唐诗/poet.song.89000.json','["江湖秋日暮，遠客若爲情。", "宿舸沙邊纜，征鴻雲外聲。", "星河搖倒景，鼓角起江城。", "去國同王粲，登臨百感生。"]'),
('26135801-02f5-4716-b6b8-677ea77149e9','促織','李綱','宋','宋诗','song-poetry','','[]','促織哀吟不自勞，草根牀下夜蕭騷。',32,'全唐诗/poet.song.89000.json','["促織哀吟不自勞，草根牀下夜蕭騷。", "我爲逐客宜無寐，何事齁齁至日髙。"]'),
('4722a050-3f9a-4b83-9347-4c83de287819','秋風二首次子美韻  其一','李綱','宋','宋诗','song-poetry','','[]','秋風淅淅吹南山，胡騎憑陵窺漢關。',64,'全唐诗/poet.song.89000.json','["秋風淅淅吹南山，胡騎憑陵窺漢關。", "金輿玉輦幸沙漠，兩載于今猶未還。", "中原道路盡豺虎，擇肉漸覺來荆蠻。", "運籌帷幄策安在，毋事推注移文間。"]'),
('96f7ee3a-c811-44dd-8822-8034df2c060a','秋風二首次子美韻  其二','李綱','宋','宋诗','song-poetry','','[]','秋風淅淅吹客衣，日光奄奄寖已微。',64,'全唐诗/poet.song.89000.json','["秋風淅淅吹客衣，日光奄奄寖已微。", "自我行吟楚澤畔，三月不通家問稀。", "清霜冷落歲將暮，僕御借問何時歸。", "我今萍梗任飄泊，懷土却悟從來非。"]'),
('3140bd05-debb-4457-aa79-b87a34e34513','次韻艾宣畫四首 竹鶴','李綱','宋','宋诗','song-poetry','','[]','磊落胎仙誰最宜，此君節操凛霜威。',32,'全唐诗/poet.song.89000.json','["磊落胎仙誰最宜，此君節操凛霜威。", "琴心試與彈三疊，從看婆娑舞羽衣。"]'),
('ee7bc1cb-a911-4457-9f43-63c619b59072','次韻艾宣畫四首 黄精鹿','李綱','宋','宋诗','song-poetry','','[]','黄精苗盛雪初融，疊疊峰巒紫翠重。',32,'全唐诗/poet.song.89000.json','["黄精苗盛雪初融，疊疊峰巒紫翠重。", "巖前雙鹿臥底事，秪應眷日長新茸。"]'),
('675badef-47c6-442c-9302-1dcde6eb3c29','次韻艾宣畫四首 杏花白鷼','李綱','宋','宋诗','song-poetry','','[]','春入羣芳此最妍，露枝煙蘂褭成團。',32,'全唐诗/poet.song.89000.json','["春入羣芳此最妍，露枝煙蘂褭成團。", "不知閑客來何處，獨傍花枝仔細看。"]'),
('b1ecce03-8616-42d1-a70f-a592144b05c9','次韻艾宣畫四首 蓮龜','李綱','宋','宋诗','song-poetry','','[]','紅粧翠蓋曉參差，水面浮游有戲龜。',32,'全唐诗/poet.song.89000.json','["紅粧翠蓋曉參差，水面浮游有戲龜。", "誰道千年解巢葉，也知曳尾已多時。"]'),
('b05c448b-b191-4a28-92ef-53eb005f21c3','西風行','李綱','宋','宋诗','song-poetry','','[]','西風隕髙梧，秋暑退殘熱。',216,'全唐诗/poet.song.89000.json','["西風隕髙梧，秋暑退殘熱。", "豈不欣微凉，寤歎驚急節。", "歲華聿云暮，露氣繁霜結。", "干戈随凝陰，虜騎壯勝鐵。", "邊防久凋殘，河洛據戎羯。", "中原無長城，何以限逸越。", "傳聞今年春，關輔已蹀血。", "强兵健馬區，乘間肆陵蔑。", "况兹柔脆鄉，豈復勞齕齧。", "江漢非不深，天險爲人設。", "要害無重兵，一葦自可絕。", "恬然不爲備，廟筭豈有說。", "翠華果何從，大計宜早决。", "緬懷沙漠寒，矯首望漢月。", "杳無鴻鴈來，寧不野鼠掘。", "何時金鳳輦，復返蒼龍闕。", "羣生有安堵，國恥稍一雪。", "努力肉食謀，傍觀心已折。"]'),
('008fb77b-c26f-42b1-ae97-f6fd33cee9db','畫草蟲八物 蚊','李綱','宋','宋诗','song-poetry','','[]','所志惟一飽，聚聲如雷車。',24,'全唐诗/poet.song.89000.json','["所志惟一飽，聚聲如雷車。", "秋來腹長饑，撲撲喙作花。"]'),
('c9d2b4ad-bfe8-46a1-90b4-b41c4444f4c1','畫草蟲八物 蠅','李綱','宋','宋诗','song-poetry','','[]','情態真可憎，畫成因誤墨。',24,'全唐诗/poet.song.89000.json','["情態真可憎，畫成因誤墨。", "薨薨亂雞鳴，慘慘變白黑。"]'),
('e010a215-431b-40f8-a58c-99689013120f','畫草蟲八物 蜂','李綱','宋','宋诗','song-poetry','','[]','杪忽腰如壺，聯綿窠若屋。',24,'全唐诗/poet.song.89000.json','["杪忽腰如壺，聯綿窠若屋。", "毋輕懷袖間，防此蠆尾毒。"]'),
('a9203de4-12c8-4571-81f5-e8999a9f01a2','畫草蟲八物 蝶','李綱','宋','宋诗','song-poetry','','[]','粉翅搖春暉，翩翾自來往。',24,'全唐诗/poet.song.89000.json','["粉翅搖春暉，翩翾自來往。", "勿貪花草香，觸此饑蛛網。"]'),
('821bae3a-28cf-4096-a7c0-8c54f2e3aafe','畫草蟲八物 螳螂','李綱','宋','宋诗','song-poetry','','[]','飄飄綠衣郎，怒臂欲當轍。',24,'全唐诗/poet.song.89000.json','["飄飄綠衣郎，怒臂欲當轍。", "君王求勇士，嘉爾能仗節。"]'),
('ed829c04-4456-476d-9832-09100d1ec239','畫草蟲八物 蜻蜓','李綱','宋','宋诗','song-poetry','','[]','雙睛碧珠瑩，四翅青羅薄。',24,'全唐诗/poet.song.89000.json','["雙睛碧珠瑩，四翅青羅薄。", "但知逐飛蚊，不復顧黄雀。"]'),
('13cf6266-de57-45d8-b9af-1effa924520d','畫草蟲八物 蟪蛅','李綱','宋','宋诗','song-poetry','','[]','戚戚鳴歲暮，不知有春秋。',24,'全唐诗/poet.song.89000.json','["戚戚鳴歲暮，不知有春秋。", "肯信鯤與鵬，同作逍遥遊。"]'),
('a48c01a1-1992-41f3-a003-d32d97236d5e','畫草蟲八物 絡緯','李綱','宋','宋诗','song-poetry','','[]','露下草根冷，戞然長悲鳴。',24,'全唐诗/poet.song.89000.json','["露下草根冷，戞然長悲鳴。", "誰知兩股間，能作無窮聲。"]'),
('0adfdb5e-c43c-4ce0-b3c0-f401fe761b3c','讀二疏傳','李綱','宋','宋诗','song-poetry','','[]','都門供張設祖道，冠蓋如雲聲浩浩。',176,'全唐诗/poet.song.89000.json','["都門供張設祖道，冠蓋如雲聲浩浩。", "送車百兩知爲誰，太傅少傅同歸老。", "道傍觀者爲泣下，賢哉大夫能自保。", "酒酣禮畢辭决去，脫若林泉放魚鳥。", "當時宣帝重法律，視遇公卿同隸皂。", "楊惲所坐秪語言，趙韓之誅亦草草。", "故令二傅動歸心，未必筋骸果衰稿。", "父子相隨出漢關，歸來自覺故鄉好。", "黄金散盡宴親賓，日治酒殽供灑掃。", "肯將田宅遺子孫，清白傳家最堪寶。", "寂寥千載想風流，知止不辱何其早。"]'),
('67ab38bd-e0aa-4727-af50-1b81c12638c5','著迂論有感','李綱','宋','宋诗','song-poetry','','[]','長笑梁谿翁，平生有餘拙。',288,'全唐诗/poet.song.89000.json','["長笑梁谿翁，平生有餘拙。", "於今欲行古，無乃亦癡絕。", "施之廊廟間，放步足已跌。", "下帷更潛思，又復廣陳說。", "從來坐言語，得謗今未歇。", "曾不少創懲，譊譊祇强聒。", "惟堪覆醬瓿，詎足議往轍。", "掉頭謂不然，此理君未察。", "立言與行事，垂世初不别。", "身窮言乃彰，貽範有前哲。", "周文拘羑里，易象乃成列。", "仲尼道不行，褒貶代賞罰。", "屈原困椒蘭，澤畔採薇蕨。", "離騷體風雅，光可争日月。", "虞卿罷趙相，梁魏頗屑屑。", "世亦傳春秋，端爲窮愁設。", "聖賢垂簡編，往往因憤發。", "避謗不著書，陸子良已黠。", "區區禍福間，何足議宏達。", "泛覽古人心，一一可坐閲。", "大略觀規模，微情析毫髪。", "幽光發干將，潛慝戮饕餮。", "會有知我人，玩味爲擊節。", "安知千載後，觀樂無季札。"]'),
('24bd3104-b882-49f9-9c07-22a1f966d0e9','建炎行','李綱','宋','宋诗','song-poetry','','[]','金寇初犯闕，太歲在丙午。',288,'全唐诗/poet.song.89000.json','["金寇初犯闕，太歲在丙午。", "殊恩擢樞廷，愧乏涓埃補。", "兩河未奠枕，杖鉞出宣撫。", "乞身緣謗讒，竄謫旅湘溆。", "明年丁未夏，被命尹天府。", "頗聞環京畿，四面盡豺虎。", "金湯雖可恃，憂在人不禦。", "見危思致命，入援裒義旅。", "旌麾亘江湄，畏景觸隆暑。", "忽傳元帥檄，果有城破語。", "鑾輿幸沙漠，妃后辭禁籞。", "皇孫與帝子，取索及稚乳。", "禮文包旂裳，樂器載筍簴。", "金繒罄公私，技巧到機杼。", "空餘宗廟存，無復薦簋簠。", "凄凉蒼龍闕，寂寞玉華廡。", "疇能供衘粟，誰與獻肥羜。", "無從執羈靮，安得生翅羽。", "號慟絕復蘇，灑淚作翻雨。", "繼聞宣赦書，寶位居九五。", "神明有依歸，率土盡呼舞。", "皆言湯武姿，勇智天所與。", "向來使賊營，英氣讋驕虜。", "建牙出危城，帝命纉鴻緒。"]'),
('e89117ac-76a5-4344-8d65-32be813cfa20','中秋望月有感寄叔易季言并簡仲輔弟','李綱','宋','宋诗','song-poetry','','[]','前年河內中秋月，玉帳初寒鐵衣滑。',256,'全唐诗/poet.song.89000.json','["前年河內中秋月，玉帳初寒鐵衣滑。", "羽書狎至不成眠，坐伴清光到明發。", "是時季弟在幕中，病隔紗窗共談說。", "出師未捷身已危，繼被宸章召還闕。", "去年中秋寓宋都，金針篆字看除書。", "夜同叔弟坐月下，仰望赤氣環斗樞。", "經營兩河初就緒，斥罷將帥良非圖。", "陵晨廷争不可得，上還印綬歸東吳。", "今年謫官旅湖外，又值中秋有佳氣。", "纖雲四卷天無河，月色滿庭如潑水。", "緬懷諸季會合難，但與阿宗相勞慰。", "舉杯邀月應笑人，處處相逢萬餘里。", "我生端遇國步艱，出入將相三年間。", "功名富貴亦何有，慨念四海悲汍瀾。", "心馳沙漠關塞遠，身墮江湖風露寒。", "不須更問世間事，但願對月身常閑。"]'),
('1d5d5c7c-0257-48ac-83ab-495ece3c98d2','張子公再得湖倅因書寄之','李綱','宋','宋诗','song-poetry','','[]','吳興别去久飄蓬，清夢時遊苕霅中。',64,'全唐诗/poet.song.89000.json','["吳興别去久飄蓬，清夢時遊苕霅中。", "十里荷開生色畫，四圍波泛水晶宫。", "喜君再擁朱轓貳，顧我今成白髪翁。", "儻幸寛恩聽歸去，定須相訪五湖東。"]'),
('8a4c0dcc-9996-46c1-b411-5ca92c77db1f','膠山蘭若幽勝予寓梁谿久而未之到聞翁士特攜家居其間賦詩見意','李綱','宋','宋诗','song-poetry','','[]','聞道膠山寺，幽深過惠山。',144,'全唐诗/poet.song.89000.json','["聞道膠山寺，幽深過惠山。", "僧房穿窈窕，石溜落孱顔。", "地僻車馬絕，山空松桂環。", "鐘聲清靄外，刹影白雲間。", "旅泊君得計，飄流吾念還。", "時危暫安適，景勝且躋攀。", "耿耿寸心赤，蕭蕭雙鬢斑。", "搶攘憫甌越，寂寞墮荆蠻。", "風月三千首，軒裳五兩綸。", "戎車傷浩蕩，綵服羨斒斕。", "天地旌麾滿，江湖鷗鷺閑。", "何時共樽酒，世路正多艱。"]'),
('ec3d79b2-7582-4bb9-a379-0e95fd213ff5','依韻和提刑張太傅寄梅','范仲淹','宋','宋诗','song-poetry','','[]','數枝梅寄寂寥人，多謝韶華次第均。',32,'全唐诗/poet.song.9000.json','["數枝梅寄寂寥人，多謝韶華次第均。", "穰下此花留未發，待君同賞後池春。"]'),
('b77fe282-76ec-48a8-b5ca-70af2b709b63','又和賞梅','范仲淹','宋','宋诗','song-poetry','','[]','故人爲使富天才，相與抽毫賦早梅。',64,'全唐诗/poet.song.9000.json','["故人爲使富天才，相與抽毫賦早梅。", "氣艷未勞横玉笛，風光先合倒金罍。", "隴頭欲寄交情遠，林下初逢病眼開。", "必若和羮有遺味，花王應亦命公台。"]'),
('33d2fe13-7331-4ac3-afa2-034088854982','依韻答王源叔憶百花洲見寄','范仲淹','宋','宋诗','song-poetry','','[]','芳洲名冠古南都，最惜塵埃一點無。',64,'全唐诗/poet.song.9000.json','["芳洲名冠古南都，最惜塵埃一點無。", "樓閣春深來海鷰，池塘人静下仙鳬。", "花情柳意憑誰問，月彩波光豈易圖。", "漢上山公發新詠，許昌何必詫申湖。"]'),
('165dc90c-ad1e-4d13-a8a7-b3e0a8a41ce1','獻百花洲圖上陳州晏相公','范仲淹','宋','宋诗','song-poetry','','[]','穰下勝遊少，此洲聊入詩。',168,'全唐诗/poet.song.9000.json','["穰下勝遊少，此洲聊入詩。", "百花争窈窕，一水自漣漪。", "潔白憐翹鷺，優游羡戲龜。", "闌干紅屈曲，亭宇碧參差。", "倒影澄波底，横煙落照時。", "月明魚競躍，春静柳閑垂。", "萬竹排霜仗，千荷卷翠旗。", "菊分潭上近，梅比漢南遲。", "岸鵲依人喜，汀鷗不我疑。", "綵絲穿石節，羅襪踏青期。", "素髪頻來醉，滄浪減去思。", "步隨芳草遠，歌逐畫船移。", "繪寫求真賞，緘藏獻已知。", "相君那肯愛，家有鳯皇池。"]'),
('fc3154ba-f474-4bf1-93e7-28ae448d85f1','依韻答青州富資政見寄','范仲淹','宋','宋诗','song-poetry','','[]','樞府當年日贊襄，隱然一柱在明堂。',96,'全唐诗/poet.song.9000.json','["樞府當年日贊襄，隱然一柱在明堂。", "親逢英主開前席，力與皇家正舊章。", "直道豈求安富貴，純誠惟欲助清光。", "龔黄政事追千載，齊魯風謠及萬箱。", "偉望能令中國重，奇謀曾壓北方强。", "故人待看調元後，乞取優游老洛陽。"]'),
('ef54806a-e9c0-40d2-8cdc-fcc8d78d49c3','依韻答并州鄭大資政見寄','范仲淹','宋','宋诗','song-poetry','','[]','制節重并汾，淹留又見春。',48,'全唐诗/poet.song.9000.json','["制節重并汾，淹留又見春。", "年高成國老，道在樂天真。", "風韻應如舊，精明迥絕倫。", "致君心未展，寧是式微人。"]'),
('b1d22746-f84e-49c6-8402-86166f195981','過陳州上晏相公','范仲淹','宋','宋诗','song-poetry','','[]','曩由清舉玉宸知，今覺光榮冠一時。',64,'全唐诗/poet.song.9000.json','["曩由清舉玉宸知，今覺光榮冠一時。", "曾入黄扉陪國論，重求絳帳就師資。", "談文講道渾無倦，養浩存真絕不衰。", "獨愧鑄顔恩未報，捧觴爲壽獻聲詩。"]'),
('9e880f92-c009-4e25-a37b-ec45f3f4e3e0','和運使舍人觀潮  其一','范仲淹','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','何處潮偏盛，錢唐無與儔。',120,'全唐诗/poet.song.9000.json','["何處潮偏盛，錢唐無與儔。", "誰能問天意，獨此見濤頭。", "海浦吞來盡，江城打欲浮。", "勢雄驅島嶼，聲怒戰貔貅。", "萬疊雲纔起，千尋練不收。", "長風方破浪，一氣自横秋。", "高岸驚先裂，羣源怯倒流。", "騰凌大鯤化，浩蕩六鼇遊。", "北客觀猶懼，吳兒弄弗憂。", "子胥忠義者，無覆巨川舟。"]'),
('5d0d4a2a-fb91-4744-a96e-669c4f366cdb','和運使舍人觀潮  其二','范仲淹','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','把酒問東溟，潮從何代生。',120,'全唐诗/poet.song.9000.json','["把酒問東溟，潮從何代生。", "寧非天吐納，長逐月虧盈。", "暴怒中秋勢，雄豪半夜聲。", "堂堂雲陣合，屹屹雪山行。", "海面雷霆聚，江心瀑布横。", "巨防連地震，羣檝望風迎。", "踊若蛟龍鬭，奔如雨雹驚。", "來知千古信，迴見百川平。", "破浪功難敵，驅山力可并。", "伍胥神不泯，憑此發威名。"]'),
('9c2a2820-6fbf-4ee0-849e-27fa73b61f42','依韻和蘇州蔣密學','范仲淹','宋','宋诗','song-poetry','','[]','餘杭偶得借麾來，山態雲情病眼開。',32,'全唐诗/poet.song.9000.json','["餘杭偶得借麾來，山態雲情病眼開。", "此樂無涯誰可共，詩仙今日在蘇臺。"]'),
('b336cc6c-d370-4c94-ae2a-e52bd7fc77b9','依韻和孫之翰對雪','范仲淹','宋','宋诗','song-poetry','','[]','江干往往臘不雪，今喜紛紛纔孟冬。',64,'全唐诗/poet.song.9000.json','["江干往往臘不雪，今喜紛紛纔孟冬。", "乃知王澤寖及遠，益明天意先在農。", "有年預可慰四海，大瑞且當聞九重。", "况此湖山滿清思，與君交唱若爲慵。"]'),
('d0c6bc92-dd2d-4754-9c66-0d7f59d57995','依韻和并州鄭宣徽見寄二首  其一','范仲淹','宋','宋诗','song-poetry','','[]','錢唐作守不爲輕，况是全家住翠屏。',64,'全唐诗/poet.song.9000.json','["錢唐作守不爲輕，况是全家住翠屏。", "名品久參卿士月，部封全屬斗牛星。", "仁君未報頭先白，故老相看眼倍青。", "最愛湖山清絕處，晚來雲破雨初停。"]'),
('1a16422b-0403-4b1b-9f93-1413458ac7f8','依韻和并州鄭宣徽見寄二首  其二','范仲淹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖載客恣游從，湖上參差半佛宫。',64,'全唐诗/poet.song.9000.json','["西湖載客恣游從，湖上參差半佛宫。", "迴顧隙駒曾不息，沉思樽酒可教空。", "層臺累榭皆清曠，萬戶千門盡鬱蔥。", "向此行春無限樂，却慚何道繼文翁。"]'),
('c3f75d39-f9c0-46f8-8251-11b71ea602ba','依韻答蔣密學見寄','范仲淹','宋','宋诗','song-poetry','','[]','東南爲守慰衰顔，憂事渾祛樂事還。',64,'全唐诗/poet.song.9000.json','["東南爲守慰衰顔，憂事渾祛樂事還。", "鼓吹夜歸湖上月，樓臺晴望海中山。", "奮飛每羡冥鴻遠，馳騁那慚老驥閑。", "此日共君方偃息，是非榮辱任循環。"]'),
('78d7915b-22f8-455a-8b2f-ba72b0d2017d','依韻和同年朱兵部王賓客交贈之什','范仲淹','宋','宋诗','song-poetry','','[]','鶴禁蘭宫達了身，高居南闕重爲鄰。',64,'全唐诗/poet.song.9000.json','["鶴禁蘭宫達了身，高居南闕重爲鄰。", "西園冠蓋時時會，北海樽罍日日親。", "共棄榮華抛世態，同歸清静復天真。", "一如劉白東都下，更得裴公作主人。"]'),
('7676f75f-e78a-4117-a352-6c58c6abe724','登表海樓','范仲淹','宋','宋诗','song-poetry','','[]','一带林巒秀復奇，每來凭檻即開眉。',32,'全唐诗/poet.song.9000.json','["一带林巒秀復奇，每來凭檻即開眉。", "好山深會詩人意，留得夕陽無限時。"]'),
('4796cabc-75cd-4a4e-9cb8-5756d8b21853','石子澗二首  其一','范仲淹','宋','宋诗','song-poetry','','[]','鑿開奇勝翠微間，車騎笙歌暮未還。',32,'全唐诗/poet.song.9000.json','["鑿開奇勝翠微間，車騎笙歌暮未還。", "彦國才如謝安石，他時即此是東山。"]'),
('30650c83-d9b3-444f-926d-4d314f6c7638','石子澗二首  其二','范仲淹','宋','宋诗','song-poetry','','[]','飛泉落處滿潭雷，一道蒼然石壁開。',32,'全唐诗/poet.song.9000.json','["飛泉落處滿潭雷，一道蒼然石壁開。", "故老相傳應可信，此山雲出雨須來。"]'),
('95e2df21-9113-4dac-88a1-e75c8d26738b','依韻答韓侍御','范仲淹','宋','宋诗','song-poetry','','[]','雖叨世契與鄰藩，東道瞻風御史尊。',64,'全唐诗/poet.song.9000.json','["雖叨世契與鄰藩，東道瞻風御史尊。", "鄭館昔時延下客，于家今日見高門。", "我居方面榮爲懼，君向臺端直且温。", "彼此中懷藴金石，不須銷黯動離魂。"]'),
('9805468a-6f21-4485-8e74-b4d0bb0845db','謝柳太博惠鶴','范仲淹','宋','宋诗','song-poetry','','[]','新詩遺鶴指真經，對此仙標詎敢輕。',64,'全唐诗/poet.song.9000.json','["新詩遺鶴指真經，對此仙標詎敢輕。", "萬里華亭思去伴，千年遼海識歸程。", "雞羣與處曾非辱，鵬路將翔孰謂榮。", "獨愛九臯嘹唳好，聲聲天地謂之清。"]'),
('2f07e96e-ddd7-44b3-9302-4b117a9d36c0','知府孫學士見示和終南監宫太保道懷五首因以綴篇  其一','范仲淹','宋','宋诗','song-poetry','','[]','玉皇近侍請脩真，賜得南山十里雲。',64,'全唐诗/poet.song.9000.json','["玉皇近侍請脩真，賜得南山十里雲。", "樽有聖賢聊自慰，鼎多龍虎復誰分。", "謝家山色朝晡見，陶隱松風寤寐聞。", "萬物已齊無一事，獨醒惟笑衆醺醺。"]'),
('f801db34-ab0f-4b63-ad2f-083cc630340c','知府孫學士見示和終南監宫太保道懷五首因以綴篇  其二','范仲淹','宋','宋诗','song-poetry','','[]','要路抛來自寡尤，高懷卷去白雲收。',64,'全唐诗/poet.song.9000.json','["要路抛來自寡尤，高懷卷去白雲收。", "玉緣祕寶須藏密，蘭爲奇香却在幽。", "仙骨豈曾移静節，帝心終是竭嘉猷。", "紅霞綠竹忘機地，未免天家下詔求。"]'),
('9066163d-f95a-46e4-964d-8e3936231374','知府孫學士見示和終南監宫太保道懷五首因以綴篇  其三','范仲淹','宋','宋诗','song-poetry','','[]','漢陂高興自飄飄，何必天台渡石橋。',64,'全唐诗/poet.song.9000.json','["漢陂高興自飄飄，何必天台渡石橋。", "潭上藥靈多餌菊，林間詩逸半書蕉。", "勤歌蘭珮招逋隱，懶事塵纓逐宷僚。", "客有赤松盟約在，異時猿鶴不相遼。"]'),
('f409cea1-058d-4da1-aee6-fac5f051817b','知府孫學士見示和終南監宫太保道懷五首因以綴篇  其四','范仲淹','宋','宋诗','song-poetry','','[]','瑤壇日月静中長，詩思時時逸謝塘。',64,'全唐诗/poet.song.9000.json','["瑤壇日月静中長，詩思時時逸謝塘。", "神枕自成仙島夢，朝衣猶有御爐香。", "三元祕簡侵星奏，五嶺靈芽待雪甞。", "金闕九重留不住，高風何處是嚴光。"]'),
('dca90c81-2922-439f-904e-dc3cb26f9482','知府孫學士見示和終南監宫太保道懷五首因以綴篇  其五','范仲淹','宋','宋诗','song-poetry','','[]','門外煙嵐紫閣横，九衢風土更何情。',64,'全唐诗/poet.song.9000.json','["門外煙嵐紫閣横，九衢風土更何情。", "籬邊醉傲淵明飲，隴上歌隨桀溺耕。", "三樂放懷千古重，萬鍾回首一毫輕。", "鵬鷦共適逍遙理，誰復人間問不平。"]'),
('0821f19f-0512-4dbb-9b70-e4d10d5ac61f','贈方秀才','范仲淹','宋','宋诗','song-poetry','','[]','高尚繼先君，巖居與俗分。',48,'全唐诗/poet.song.9000.json','["高尚繼先君，巖居與俗分。", "有泉皆潄石，無地不生雲。", "鄰里多垂釣，兒孫半屬文。", "幽蘭在深處，終日自清芬。"]'),
('0c75306e-1263-4068-80d4-bac74aa533a6','寄石學士','范仲淹','宋','宋诗','song-poetry','','[]','家有清白志，所寶甑中塵。',60,'全唐诗/poet.song.9000.json','["家有清白志，所寶甑中塵。", "休去無生涯，老來猶苦辛。", "一麾了婚嫁，萬事蠧精神。", "與君嘗大言，定作青山鄰。", "蹭蹬未攜手，得無羞故人。"]'),
('2300387a-91df-4daa-8dea-b4a424b078b8','江樓寄希元上人','范仲淹','宋','宋诗','song-poetry','','[]','清言一以遙，默默江樓上。',24,'全唐诗/poet.song.9000.json','["清言一以遙，默默江樓上。", "安得如白雲，無心兩相忘。"]'),
('8d5254d1-2607-4040-9896-87fd78c7993b','酬和黄太博','范仲淹','宋','宋诗','song-poetry','','[]','古籍東南美，蔚蔚幙中議。',204,'全唐诗/poet.song.9000.json','["古籍東南美，蔚蔚幙中議。", "懿行希聖賢，尚文粲游賜。", "伊余髮已禿，偶繼立朝士。", "何以宣王政，甘爲時所棄。", "酌以廣州泉，不易伯夷志。", "直哉心如絃，安慮道邊斃。", "竊嘗力於古，秉筆庶幾至。", "孰爲末聞達，聊以道幽秘。", "夫君鏘以名，尤爲世之器。", "贈我百餘言，升堂出而示。", "土木朽且陋，黼黻謬增賁。", "毌鹽煩刻畫，返朴吾所愧。", "華勛愛士心，蓬壺延才地。", "何人薦於子，當彼得言位。", "吐以胸中奇，落落金玉繼。", "九虚高可游，凌厲垂天翅。", "吾將退而隐，尚得榮其視。"]'),
('23165706-267a-40b4-a6c3-d6e023958596','滕子京以真籙相示因以贈之','范仲淹','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','泰山采芝人，吏隱清淮濱。',168,'全唐诗/poet.song.9000.json','["泰山采芝人，吏隱清淮濱。", "金函祕寶籙，奉之如高真。", "謂子有仙志，興言一相示。", "叩頭鳴天鼔，玉書粲然異。", "白雲引輕素，朱絲聞靈篇。", "題云天寶歲，傳於任鳳仙。", "兵火換九州，于兹三百年。", "非有靈物持，此書安得全。", "綠字起龍蛇，丹文掛星斗。", "六甲當奉行，百神迺奔走。", "密密天上語，忽忽人間有。", "與君置青山，解冠松桂間。", "服此上淸籙，上淸庶可攀。", "無爲塵土中，草草凋朱顔。"]'),
('71c766b1-4858-4605-9c38-871f9642309f','送徐登山人','范仲淹','宋','宋诗','song-poetry','','[]','重君愛詩書，孜孜不知老。',120,'全唐诗/poet.song.9000.json','["重君愛詩書，孜孜不知老。", "白髮末理生，惟談聖人道。", "愛君妙山水，所得是神氣。", "尺素寫林巒，邈有千里意。", "今日江南行，孤雲無繋程。", "直指九華峰，去掃先君塋。", "却來華陽川，與我溪上盟。", "行歌紫芝秀，坐嘯清風生。", "鍊真變金骨，飄飄朝玉京。", "結成物外遊，忘此天下情。"]'),
('e523b8f5-6c11-48d7-9534-cb11b46bf6bd','匣劍','范仲淹','宋','宋诗','song-poetry','','[]','靈劍經年匣，决雲誰爲高。',24,'全唐诗/poet.song.9000.json','["靈劍經年匣，决雲誰爲高。", "報人如有道，何忍問吹毛。"]'),
('a28df455-8a2f-4b47-8706-bd79debb6c48','南園','范仲淹','宋','宋诗','song-poetry','','[]','南園萬樹花，極目春芳麗。',24,'全唐诗/poet.song.9000.json','["南園萬樹花，極目春芳麗。", "林下老成人，相招植松桂。"]'),
('b4b824a2-3657-405d-b1f5-d7d03a543571','行歌','范仲淹','宋','宋诗','song-poetry','','[]','行歌春滿路，坐歌春滿園。',24,'全唐诗/poet.song.9000.json','["行歌春滿路，坐歌春滿園。", "花前人自樂，桃李豈須言。"]'),
('72df2abe-fbcc-4010-801d-eab5a5068a96','明月','范仲淹','宋','宋诗','song-poetry','','[]','明月照前墀，朱絃奏流水。',24,'全唐诗/poet.song.9000.json','["明月照前墀，朱絃奏流水。", "春風如未回，敢望無雲起。"]'),
('fd0b7ad7-47e4-4784-a6b3-847d1c9a3a32','南樓','范仲淹','宋','宋诗','song-poetry','','[]','南樓百尺餘，淸夜微埃歇。',24,'全唐诗/poet.song.9000.json','["南樓百尺餘，淸夜微埃歇。", "天會詩人情，遺此高高月。"]'),
('4a9b54ea-3896-4c75-894e-4aef5de9d922','送陳瓌秀才遊金陵','范仲淹','宋','宋诗','song-poetry','','[]','君有江南行，爲君歌以喜。',120,'全唐诗/poet.song.9000.json','["君有江南行，爲君歌以喜。", "龍盤山萬曲，練静江千里。", "江山不可空，台星照吳中。", "古來王謝地，今有周召風。", "而間楊與鄭，萬丈光相映。", "煌煌聚宰府，金陵一何盛。", "此去知已賢，雅客情無邊。", "白雲起江樹，明月逐江船。", "雲月共徘徊，優哉如游仙。", "歸來笑春風，白日登青天。"]'),
('7d7979f0-227b-49cb-a51e-6e416dcdb2b4','送歐伯起','范仲淹','宋','宋诗','song-poetry','','[]','天與神交忽解攜，一溪風月更同誰。',32,'全唐诗/poet.song.9000.json','["天與神交忽解攜，一溪風月更同誰。", "自慚瀟灑如猿鶴，却向周郎怨別離。"]'),
('863c286b-37be-4fea-8a35-29df9d1f0f5e','九日','范仲淹','宋','宋诗','song-poetry','','[]','欲賦前賢九日詩，茱萸相鬭一枝枝。',64,'全唐诗/poet.song.9000.json','["欲賦前賢九日詩，茱萸相鬭一枝枝。", "可憐宋玉情無限，爭似陶潛醉不知。", "綠鬢愛隨風景變，黄華能與歲寒期。", "登高逈處狂多少，笑殺襄陽拍手兒。"]'),
('45eb2663-e575-45f9-b042-376666bd4093','送虎丘長老','范仲淹','宋','宋诗','song-poetry','','[]','暫向天台參衆真，虎丘風月遠隨身。',32,'全唐诗/poet.song.9000.json','["暫向天台參衆真，虎丘風月遠隨身。", "瓊臺肯便長棲去，無限人間未度人。"]'),
('6261d540-f669-48ad-8384-69895725f03f','寄潤州龐籍','范仲淹','宋','宋诗','song-poetry','','[]','北固高棲海氣寒，使君應此凭闌干。',32,'全唐诗/poet.song.9000.json','["北固高棲海氣寒，使君應此凭闌干。", "春山雨後青無限，借與淮南洗眼看。"]'),
('5d0eea2e-5015-424b-b1fc-0c715f1a0bce','送湛公歸四明講席','范仲淹','宋','宋诗','song-poetry','','[]','滿面南風指四明，山長水曲不勝情。',32,'全唐诗/poet.song.9000.json','["滿面南風指四明，山長水曲不勝情。", "自言此去雲林下，惟講華嚴報太平。"]'),
('84597e4f-edb3-44d2-966b-122f9627f0ad','和龐醇之見寄','范仲淹','宋','宋诗','song-poetry','','[]','北樓千尺午猶寒，冉冉飛塵不可干。',32,'全唐诗/poet.song.9000.json','["北樓千尺午猶寒，冉冉飛塵不可干。", "横望滄溟了無際，貴人休向畵圖看。"]'),
('b32743e2-4417-46f7-9f2e-b00e8ca6d62f','依韻和胡使君書事','范仲淹','宋','宋诗','song-poetry','','[]','都督再臨横海鎮，集仙遙輟內朝班。',64,'全唐诗/poet.song.9000.json','["都督再臨横海鎮，集仙遙輟內朝班。", "清風又振東南美，好夢多親咫尺顔。", "坐嘯樓臺凌皓月，行春鼓吹入青山。", "太平天子尊耆舊，八十王祥未賜閑。"]'),
('cda35236-53be-438b-b46b-1c4d449b2ee7','贈吳秀才','范仲淹','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','萬户侯家幾葉孫，弟兄紅斾獨烏巾。',32,'全唐诗/poet.song.9000.json','["萬户侯家幾葉孫，弟兄紅斾獨烏巾。", "攜琴人入廬山去，誰信朱門有逸人。"]'),
('dfca1123-b30e-47b0-9bd3-1477ac0b8e7a','依韻和魏介之同遊玉仙壇','范仲淹','宋','宋诗','song-poetry','','[]','雲壇共上百神清，碧塢紅霞相照明。',64,'全唐诗/poet.song.9000.json','["雲壇共上百神清，碧塢紅霞相照明。", "幽草欲迷丹井處，亂峰依舊白雲生。", "亭亭翠纛高杉矗，險險狂雷落石轟。", "待得九霄鸞鶴馭，玉書應改地仙名。"]'),
('63fb2768-1eed-4c4c-907f-d1cfdccb588b','依韻和介之未開菊','范仲淹','宋','宋诗','song-poetry','','[]','本非桃李色，佳節敢先開。',48,'全唐诗/poet.song.9000.json','["本非桃李色，佳節敢先開。", "席上無言晚，霜前幸未摧。", "芳心應有待，真賞直須催。", "願上金樽壽，何傷蝶不來。"]'),
('5b37d385-3c0d-497c-9895-7dd4ae24d430','依韻酬池州錢綺翁','范仲淹','宋','宋诗','song-poetry','','[]','天涯彼此勿冲冲，內樂何須位更崇。',64,'全唐诗/poet.song.9000.json','["天涯彼此勿冲冲，內樂何須位更崇。", "白髮監州身各健，青山遶郭景多同。", "日高窗外眠方起，月到樽前宴未終。", "况在江南佳麗地，重陽猶見牡丹紅。"]'),
('4b339f23-b07f-4b99-b168-f391b7107a7a','寄題溪口廣慈院','范仲淹','宋','宋诗','song-poetry','','[]','越中山水絕纖塵，溪口風光歩步新。',32,'全唐诗/poet.song.9000.json','["越中山水絕纖塵，溪口風光歩步新。", "若得會稽藏拙去，白雲深處亦行春。"]'),
('5f457e82-6ed4-4f20-b6ab-2e5ab2694ce5','釣臺詩','范仲淹','宋','宋诗','song-poetry','','[]','漢包六合罔英豪，一箇冥鴻惜羽毛。',32,'全唐诗/poet.song.9000.json','["漢包六合罔英豪，一箇冥鴻惜羽毛。", "世祖功臣三十六，雲臺爭似釣臺高。"]'),
('dc2cebd0-b2fd-40f3-a50c-401a9d4ff2f2','送饒州董博士','范仲淹','宋','宋诗','song-poetry','','[]','番國英豪富魯儒，同時舉送起鄉閭。',64,'全唐诗/poet.song.9000.json','["番國英豪富魯儒，同時舉送起鄉閭。", "文章恥學揚雄賦，議論羞談賈誼書。", "喜得明珠三十六，恨遺壮士二千餘。", "送君直上青霄去，行看歸乘駟馬車。"]'),
('fda0f74a-4924-46b2-892e-e980c28ca7dc','無題','范仲淹','宋','宋诗','song-poetry','','[]','十口相將泛巨川，來時暖熟去凄然。',32,'全唐诗/poet.song.9000.json','["十口相將泛巨川，來時暖熟去凄然。", "關津若要知名姓，定是孤兒寡婦船。"]'),
('00059f6e-6913-47b6-ae72-ec5cf31406d9','無題','范仲淹','宋','宋诗','song-poetry','','[]','江南有美人，別後長相憶。',24,'全唐诗/poet.song.9000.json','["江南有美人，別後長相憶。", "何以慰相思，贈汝好顔色。"]'),
('2723a25e-681c-401a-87b3-d33af1d33443','劍聯句','范仲淹','宋','宋诗','song-poetry','','[]','聖人作神兵，以定天下厄。',288,'全唐诗/poet.song.9000.json','["聖人作神兵，以定天下厄。", "蚩尤發靈機，干將構雄績。", "槖籥天地開，鑪治陰陽闢。", "南帝輸火精，西皇降金液。", "炎炎崑岡熒，洶洶洪河擘。", "雷霆助意氣，日月淪精魄。", "神氣不在大，錯落就三尺。", "直淬靈溪泉，横磨太行石。", "雄雌威並立，晝夜光相射。", "提攜風雲生，指顧烟霞寂。", "堅剛正人心，耿介志士跡。", "初疑成夏鼎，魑魅世所適。", "又若引吳刀，犀象謂無隔。", "截波虬尾滑，脱浪鯨牙直。", "頑冰挂陰霤，皓月乘孤隙。", "河角起彗氣，雲罅露秋碧。", "曉鐔星斗爛，夜匣飛龍宅。", "舞酣霰雪回，彈俊球琳擊。", "鮮摇霅水光，膩刮湘山色。", "青蛟渴雨瘦，素虺蟠霜瘠。", "清音鏘以鳴，寒姿堅且澤。", "鬼類喪影響，佞黨摧肝腸。", "一旦會神武，四海屠兇逆。", "周王奉天討，商郊千里赤。"]'),
('0e738e28-2bec-48ff-a312-5d1af41fc302','鶴聯句','范仲淹','宋','宋诗','song-poetry','','[]','上霄降靈氣，鍾此千年禽。',288,'全唐诗/poet.song.9000.json','["上霄降靈氣，鍾此千年禽。", "幽閑靖節性，孤高伯夷心。", "頡頏紫霄垠，飄颻滄浪潯。", "岳湛有仙姿，鈞韶無俗音。", "毛滋月華淡，頂粹霞光深。", "目流泉客淚，翅垂羽人襟。", "騰漢雪千丈，點溪霜半尋。", "纖喙礪青鐵，修脛雕碧琳。", "巖棲干溪樹，澤飲卑蹄涔。", "鸞皇自塤箎，燕雀徒商參。", "獨翅聳瓊枝，羣舞傾瑤林。", "病餘霞雲叚，夢回松吹吟。", "靜嫌鸚鵡言，高笑鴛鴦淫。", "金精冷澄澈，玉格寒蕭森。", "潔白不我恃，腥羶非所任。", "稻粱不得已，蟣虱胡爲侵。", "天池憶鵬遊，雲羅傷鳯沈。", "風流超縞素，雅淡絕規箴。", "相親長道情，偶見銷煩襟。", "西漢惜馮唐，華皓欲投簪。", "南朝仰衛玠，清羸疑不禁。", "端如方直臣，處羣良足欽。", "介如廉退士，驚秋猶在陰。", "幾誚鷹隼鷙，覊韝俄見臨。"]'),
('ec56ba40-6040-4bdb-ab53-870970c279ee','寄鄉人','范仲淹','宋','宋诗','song-poetry','','[]','長白一寒儒，登榮三紀餘。',48,'全唐诗/poet.song.9000.json','["長白一寒儒，登榮三紀餘。", "百花春滿地，二麥雨初車。", "鼓吹前迎道，煙霞指舊廬。", "鄉人莫相羨，教子讀詩書。"]'),
('1fe8c281-787b-4b66-aa64-572bf7ee619a','咏蚊','范仲淹','宋','宋诗','song-poetry','','[]','飽去櫻桃重，饑來柳絮輕。',24,'全唐诗/poet.song.9000.json','["飽去櫻桃重，饑來柳絮輕。", "但知離此去，不用問前程。"]'),
('e2f0e518-f72a-4580-afa4-4189cb7670db','留題雲門山雍熙院','范仲淹','宋','宋诗','song-poetry','','[]','一路入嵐堆，還驚禹鑿開。',48,'全唐诗/poet.song.9000.json','["一路入嵐堆，還驚禹鑿開。", "林無惡獸住，巖有好泉來。", "雲陣藏雷去，山根到海回。", "莫辭登絕頂，南望即天台。"]'),
('667c2bf8-7343-4a8a-a533-73fcf96d94dd','落星寺','范仲淹','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江萬里來，古寺中流起。',24,'全唐诗/poet.song.9000.json','["長江萬里來，古寺中流起。", "何如天上星，汩汩波濤裏。"]'),
('73d52ae8-1a21-4a79-9a9b-094c78abcab6','風水洞','范仲淹','宋','宋诗','song-poetry','','[]','神仙一去幾千年，自遣秦人不得還。',32,'全唐诗/poet.song.9000.json','["神仙一去幾千年，自遣秦人不得還。", "春盡桃花無處覓，空餘流水到人間。"]'),
('60753d49-c162-4961-adbc-4c91d9580842','留題小隱山書室','范仲淹','宋','宋诗','song-poetry','','[]','小徑小桃深，紅光隱翠陰。',48,'全唐诗/poet.song.9000.json','["小徑小桃深，紅光隱翠陰。", "是非不到耳，名利本無心。", "筍迸饒當戶，雲歸半在林。", "何須聽絲竹，山水有清音。"]'),
('7bf14d07-6130-4306-8eee-b85622c00659','桐廬方正父家藏書翰林畫白芍藥予來領郡事因獲一見感嘆久之題二十八字景祐元年十月七日','范仲淹','宋','宋诗','song-poetry','','[]','治亂興衰甚可嗟，徒憐水調訴榮華。',32,'全唐诗/poet.song.9000.json','["治亂興衰甚可嗟，徒憐水調訴榮華。", "開元盛事今何在，尚有霓裳寄此花。"]'),
('e9cd21e4-78d1-4db3-8757-aa21566c4624','書酒家壁','范仲淹','宋','宋诗','song-poetry','','[]','當罏一曲竹枝歌，腸斷江南奈爾何。',32,'全唐诗/poet.song.9000.json','["當罏一曲竹枝歌，腸斷江南奈爾何。", "遊子未歸春又老，夜來風雨落花多。"]'),
