('c9cc5314-ea91-4dd2-81d7-fa2abc2f2395','送本如上人歸四明','釋尚能','宋','宋诗','song-poetry','','[]','隨緣離舊隱，秋後卻思歸。',48,'全唐诗/poet.song.9000.json','["隨緣離舊隱，秋後卻思歸。", "古寺山光滿，重城海氣圍。", "道孤愁作客，年長重忘機。", "此去何人見，雲根掩竹扉。"]'),
('76ccac1d-7126-4aca-8e80-5f793564f3df','送秀登上人','釋尚能','宋','宋诗','song-poetry','','[]','又負空囊出，都城難久居。',48,'全唐诗/poet.song.9000.json','["又負空囊出，都城難久居。", "西風隨雁急，寒柳向人疏。", "野宿燈分燒，船齋磬動魚。", "如逢北來客，應寄社中書。"]'),
('3a710587-4a65-4bb6-af9f-d7bec2e7b633','京口僧院','釋尚能','宋','宋诗','song-poetry','','[]','渺漠人煙外，禪居靜趣多。',48,'全唐诗/poet.song.9000.json','["渺漠人煙外，禪居靜趣多。", "山遙天接樹，江闊日生波。", "鳴櫓時鄰響，征車舊絕過。", "清風數聲磬，應不入漁歌。"]'),
('144e44a1-1415-4125-8755-f86f6a709d7e','金山寓居','釋尚能','宋','宋诗','song-poetry','','[]','風霜千里未歸身，古跡遲留外俗羣。',64,'全唐诗/poet.song.9000.json','["風霜千里未歸身，古跡遲留外俗羣。", "月到天心當剎見，濤分山脊在樓聞。", "倚吟老樹栖沙鳥，寄臥虛巖貯海雲。", "唯恐雪晴行興動，迢迢楚路與吳分。"]'),
('6fb0ed4f-3905-457a-860b-46b6a36d4564','五言四十字奉寄四明禮師道人','釋尚能','宋','宋诗','song-poetry','','[]','昔年慚不識，今日羨仍頻。',48,'全唐诗/poet.song.9000.json','["昔年慚不識，今日羨仍頻。", "造疏傳他域，談空聚遠人。", "龕燈孤敵暗，庭柏瘦無春。", "漸老思山甚，相逢會有因。"]'),
('eec98bd1-32e7-4f5c-bc11-a0ff6400f0f8','中秋旅懷','釋尚能','宋','宋诗','song-poetry','','[]','所畜惟騷雅，兼之得固窮。',48,'全唐诗/poet.song.9000.json','["所畜惟騷雅，兼之得固窮。", "望鄉連北斗，聽雨带西風。", "稼穡村坊遠，煙波路逕通。", "冥搜清絕句，恰似有神功。"]'),
('d9337958-aa6b-4307-8f02-82c9ec68683e','句  其一','釋尚能','宋','宋诗','song-poetry','','[]','關河虎符重，殿閣獸樽閑。',12,'全唐诗/poet.song.9000.json','["關河虎符重，殿閣獸樽閑。"]'),
('74e5c7f2-a304-4278-a5b5-25ead6ea94f0','句  其二','釋尚能','宋','宋诗','song-poetry','','[]','泣珠泉路通關市，種玉僊翁寄版圖。',16,'全唐诗/poet.song.9000.json','["泣珠泉路通關市，種玉僊翁寄版圖。"]'),
('05eb96de-a761-4334-903b-eb6ccd726386','句  其一','邵煥','宋','宋诗','song-poetry','','[]','船官風破浪，關吏鼓通晨。',12,'全唐诗/poet.song.9000.json','["船官風破浪，關吏鼓通晨。"]'),
('51c2a64c-41f7-4201-a04a-ceb64054dd58','句  其二','邵煥','宋','宋诗','song-poetry','','[]','玉腕枕香腮，紅蓮藕上開。',12,'全唐诗/poet.song.9000.json','["玉腕枕香腮，紅蓮藕上開。"]'),
('bf0e767b-f095-4255-8ae9-2a0a154c3346','和范公希文懷慶朔堂','畢京','宋','宋诗','song-poetry','','[]','花木還依舊徑栽，春園不惜爲誰開。',32,'全唐诗/poet.song.9000.json','["花木還依舊徑栽，春園不惜爲誰開。", "幾多民俗熙熙樂，似到老聃臺上來。"]'),
('c67a52f4-c872-47da-aca8-4700a0cd7aa1','風水洞','許元祐','宋','宋诗','song-poetry','','[]','野寺依山立，松橋避石斜。',49,'全唐诗/poet.song.9000.json','["野寺依山立，松橋避石斜。", "壞梁飛但是蟻，枯木掛青蛇。", "道路悲蓬轉，功名惜鬢華。", "聊將洞中水，試洗眼前花。"]'),
('e34118d9-4da5-4395-9e3a-0514d36769af','御溝柳','陳執中','宋','宋诗','song-poetry','','[]','一度春來一度新，翠光長得照龍津。',32,'全唐诗/poet.song.9000.json','["一度春來一度新，翠光長得照龍津。", "君王自愛天然態，恨殺昭陽學舞人。"]'),
('d32a1ff7-16b1-463d-9387-5b22d2869069','題蒼梧部','陳執中','宋','宋诗','song-poetry','','[]','莫訝南方景物疏，爲君聊且話蒼梧。',320,'全唐诗/poet.song.9000.json','["莫訝南方景物疏，爲君聊且話蒼梧。", "地傾二面城池壯，江迸三流氣色麄。", "山畜火光因政出，石藏牛影爲仙呼。", "官廳傳自唐丞相，民頌思從漢大夫。", "龍母廟堂神鬼集，鰐魚池近介鱗趨。", "朝臺望斷歸岐路，冰井頻窺爽髪膚。", "膾美不堪全用鯉，果珍何忍命爲奴。", "雲歸上國名終遠，郡带□藩勢未孤。", "銅鼓聲浮翻霹靂，桄榔林靜露真珠。", "溪平花檻饒桃李，疆壓鶯歌盡鷓鴣。", "三足吉祥文上載，獨峰爲盛事元無。", "封疆自覺隨時廣，飲食從分過嶺殊。", "行伍戢威遵下武，兒童知學樂從儒。", "風輕別墅來漁唱，人到閑坊戀酒壚。", "服尚鮮華幾兩蜀，市相交易類全吳。", "營希賢帥偏栽柳，扇慕良規各製蒲。", "春聳門闌多列戟，雪從絃管舞雙奴。", "只因談笑評風俗，僭用詩謠和袴襦。", "萬里無媒休促蹙，數年從宦弄斯須。", "卻憂別後牽吟想，欲寫幽期入畫圖。"]'),
('a6611159-1d5f-4dfa-b093-9f1abcd8bc56','惠安縣齋咏梅','陳執中','宋','宋诗','song-poetry','','[]','去年邊上見梅花，醉眼淹留未到家。',32,'全唐诗/poet.song.9000.json','["去年邊上見梅花，醉眼淹留未到家。", "今日嶺南攀折得，忽驚身又在天涯。"]'),
('8a9e0887-752e-496e-b70d-d35e94a6c95b','贈陳執中','胡僧','宋','宋诗','song-poetry','','[]','虎目猿身形最貴，只因攀附即升高。',32,'全唐诗/poet.song.9000.json','["虎目猿身形最貴，只因攀附即升高。", "知君今向端溪去，助子清風泛怒濤。"]'),
('93f3e0e5-05f6-49f9-b8fe-97c705493e7c','句  其一','胡僧','宋','宋诗','song-poetry','','[]','何年飲著聲聞酒，直到而今醉不醒。',16,'全唐诗/poet.song.9000.json','["何年飲著聲聞酒，直到而今醉不醒。"]'),
('a888df73-49b6-488f-8356-4e35e9341123','句  其二','胡僧','宋','宋诗','song-poetry','','[]','何事將軍封萬戶，卻教紅粉去和戎。',16,'全唐诗/poet.song.9000.json','["何事將軍封萬戶，卻教紅粉去和戎。"]'),
('f0c6c2dc-a439-48ec-b57a-0ec9eff1f6b6','句  其一','掌禹錫','宋','宋诗','song-poetry','','[]','風定落花深一寸，日高啼鳥度千聲。',16,'全唐诗/poet.song.9000.json','["風定落花深一寸，日高啼鳥度千聲。"]'),
('fb520a78-69bd-46c0-b53e-723f0347bfdb','句  其二','掌禹錫','宋','宋诗','song-poetry','','[]','曉鶯林外千聲囀，芳草階前一尺長。',16,'全唐诗/poet.song.9000.json','["曉鶯林外千聲囀，芳草階前一尺長。"]'),
('e5d43c8b-974f-440b-857a-62ad5a8a17e0','題西溪無相院','張先','宋','宋诗','song-poetry','','[]','積水涵虛上下清，幾家門靜巖痕平。',64,'全唐诗/poet.song.9000.json','["積水涵虛上下清，幾家門靜巖痕平。", "浮萍破處見山影，小艇歸時聞棹聲。", "入郭僧尋塵裏去，過橋人似鑑中行。", "已憑暫雨添秋色，莫放修林礙月生。"]'),
('596a6d7f-f41f-446b-aabe-1b9a282a0a83','巢烏','張先','宋','宋诗','song-poetry','','[]','烏啼東南枝，危巢雛五六。',48,'全唐诗/poet.song.9000.json','["烏啼東南枝，危巢雛五六。", "心在安巢枝，一日千往復。", "脫網得羣食，入口不入腹。", "窮生俾反哺，豈能報成育。"]'),
('42b30757-3ab7-4cb8-a3a4-5a7f57ee9933','潤州甘露寺','張先','宋','宋诗','song-poetry','','[]','丞相高齋半草萊，舊時風月滿亭臺。',64,'全唐诗/poet.song.9000.json','["丞相高齋半草萊，舊時風月滿亭臺。", "地從日月生時見，眼到江山盡處回。", "三國是非春夢斷，六朝城闕野花開。", "心隨潮水漫漫去，流徧煙邨半日來。"]'),
('09c4c1fe-e658-4061-bab9-792678584906','吳江','張先','宋','宋诗','song-poetry','','["\u592a\u6e56"]','春後銀魚霜後鱸，遠人曾到合思吳。',64,'全唐诗/poet.song.9000.json','["春後銀魚霜後鱸，遠人曾到合思吳。", "欲圖江色不上筆，靜覓鳥聲深在蘆。", "落日未昏聞市散，青天都凈見山孤。", "橋南水漲虹垂影，清夜澄光照太湖。"]'),
('4e7711db-a8ad-4b74-8b7e-60b47c9e14d9','贈妓兜娘','張先','宋','宋诗','song-poetry','','[]','十載芳港澳臺撫白蘋，移舟弄水賞青春。',34,'全唐诗/poet.song.9000.json','["十載芳港澳臺撫白蘋，移舟弄水賞青春。", "當時自倚青春力，不信東風解誤人。"]'),
('d1ab751b-00ff-4805-8b6f-f60c686e74a4','醉眠亭','張先','宋','宋诗','song-poetry','','[]','醉翁家有醉眠亭，爲愛江堤亂草春。',64,'全唐诗/poet.song.9000.json','["醉翁家有醉眠亭，爲愛江堤亂草春。", "不聽耳邊啼鳥喚，任教風外雜花零。", "欲酣未必過此舍，樂甚應宜造大庭。", "五柳北窗知此趣，三閭南儗漫孤醒。"]'),
('edea7e40-589b-49da-a2de-fd4264df5f51','醉眠亭','張先','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','松陵江畔客，築室從何年。',140,'全唐诗/poet.song.9000.json','["松陵江畔客，築室從何年。", "世俗徒紛紛，不知李子賢。", "在彼既不知，不如醉且眠。", "聲名衮衮誰知命，醉非愛酒眠非病。", "長江渾渾無古今，羣山回合來相應。", "呼奴沽酒不可遲，買魚斫膾煩老妻。", "何必紉繩繫飛兔，百年長短空自知。", "直將褌蝨視天地，冥冥支枕窮四時。", "九衢足塵土，朱門多是非。", "秋風老蓴鱸，扁舟何日歸。"]'),
('ba29d2fe-4ee2-451f-aff9-af59aac94e34','營妓張溫卿黄子思愛姬宜哥皆葬宿州東過而題詩','張先','宋','宋诗','song-poetry','','[]','好物難留古亦嗟，人生無物不塵沙。',32,'全唐诗/poet.song.9000.json','["好物難留古亦嗟，人生無物不塵沙。", "何時宰樹連雙冢，結就人間並蒂花。"]'),
('d0b55302-0d58-4143-a41b-84bb9971f53e','和元居中風水洞上祖龍圖韻','張先','宋','宋诗','song-poetry','','[]','水色風光近使君，浥塵輕雨逐車輪。',32,'全唐诗/poet.song.9000.json','["水色風光近使君，浥塵輕雨逐車輪。", "暫來不宿宜無恨，多少行春不到人。"]'),
('1b6aecb0-cf25-4aa6-a959-4e451b2c7ed2','酬周開祖示長調見索詩集','張先','宋','宋诗','song-poetry','','[]','辯玉當看破石詩，泥沙有寶即山輝。',32,'全唐诗/poet.song.9000.json','["辯玉當看破石詩，泥沙有寶即山輝。", "都廛往往無真璞，誤使人評鼠臘歸。"]'),
('d1bb0d3c-50e0-4ac3-a61d-7c4c930f06d7','次韻清明日西湖','張先','宋','宋诗','song-poetry','','["\u897f\u6e56"]','新火飛煙上柳梢，天供好景助詩豪。',64,'全唐诗/poet.song.9000.json','["新火飛煙上柳梢，天供好景助詩豪。", "江湖一處逢嘉月，溟海同時得巨鼇。", "白水更隨春雨長，青雲不及畫樓高。", "千橈插羽鼙聲動，十里驚雷奪暮濤。"]'),
('f0c037cc-4159-4116-aa07-084d3cbc56cb','次韻蔡君謨侍郎寒食西湖','張先','宋','宋诗','song-poetry','','["\u897f\u6e56"]','飛飛畫檝繞花洲，霽雨浮花出岸流。',64,'全唐诗/poet.song.9000.json','["飛飛畫檝繞花洲，霽雨浮花出岸流。", "誰廣金明爲水戰，自來銀漢有霓舟。", "行從使節春尤盛，住買吳山老未由。", "人遲歸軒香接路，一分新月管絃樓。"]'),
('7251ab19-dd4b-41f6-b45e-9629e69e946c','九月望日同君謨侍郎泛西湖夜飲','張先','宋','宋诗','song-poetry','','["\u897f\u6e56"]','清歌曲曲酒巡巡，一舉金蕉五十分。',64,'全唐诗/poet.song.9000.json','["清歌曲曲酒巡巡，一舉金蕉五十分。", "山影與天都在水，風光爲月不留雲。", "節回路口千門待，樂過湖心四岸聞。", "莫笑閑官奉歡席，自來蒿艾近蘭薰。"]'),
('b4158bde-b636-49ab-b0c2-4e4342caee32','酬發運馬子山少卿惠與詩','張先','宋','宋诗','song-poetry','','[]','貢餘應惜點爲山，絕唱兼遺致政官。',32,'全唐诗/poet.song.9000.json','["貢餘應惜點爲山，絕唱兼遺致政官。", "嵰地雪甜多不識，吳人未食齒先寒。"]'),
('0e7a50a6-63c9-4a8f-84b2-21f20e48b683','子山再惠詩見和因又續成子山不以予不才兩發章薦','張先','宋','宋诗','song-poetry','','[]','清卿恩德重鼇山，詩寄閑棲白首官。',32,'全唐诗/poet.song.9000.json','["清卿恩德重鼇山，詩寄閑棲白首官。", "須信夜光誰可得，玉龍沉睡玉淵寒。"]'),
('8bcdecd0-3ba2-49e7-90f5-8ff351199396','冬日郡齋書事','張先','宋','宋诗','song-poetry','','[]','鈴索聲閑按牒稀，怯寒肌骨望春暉。',64,'全唐诗/poet.song.9000.json','["鈴索聲閑按牒稀，怯寒肌骨望春暉。", "凝雲垂地雪欲下，高樹無風葉自飛。", "水落淺沙魚隊聚，草枯幽隴鹿羣歸。", "安人不信彤襜貴，上相還家是錦衣。"]'),
('0929c1a1-9024-40d0-b55d-698402228220','失題','張先','宋','宋诗','song-poetry','','[]','花落春禽啼晚枝，有時香蒂點人衣。',32,'全唐诗/poet.song.9000.json','["花落春禽啼晚枝，有時香蒂點人衣。", "多情盡不如蝴蝶，欲起遺紅貼地飛。"]'),
('f2a04cfa-8c2a-444e-b7c7-643f88cb2276','李少卿宅除夜催妝','張先','宋','宋诗','song-poetry','','[]','裴李門頭車馬盛，斗杓臨曉欲東迴。',64,'全唐诗/poet.song.9000.json','["裴李門頭車馬盛，斗杓臨曉欲東迴。", "天真都說妝前好，春色偷從夜半來。", "園裏花枝燈樹合，月中人影鑑奩開。", "詩家無自矜吟筆，不惜鉛華不用催。"]'),
('96508a60-834e-48aa-abab-b65c86668dd4','飛石巖','張先','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','石破重巖萬客疑，不堪攻玉不支機。',32,'全唐诗/poet.song.9000.json','["石破重巖萬客疑，不堪攻玉不支機。", "長江風雨來無定，時學零陵燕子飛。"]'),
('30ba222b-8fe7-4531-9c7a-55a7720e57e7','漫天嶺','張先','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','不獨高明不可謾，仍知不似泰山安。',32,'全唐诗/poet.song.9000.json','["不獨高明不可謾，仍知不似泰山安。", "五丁破道秦通蜀，卻被行人脚下看。"]'),
('2d224f55-e4b7-4d7e-ae9a-a6d816e94de7','飛仙嶺','張先','宋','宋诗','song-poetry','','[]','路接曉天人近月，真仙去後只雲歸。',32,'全唐诗/poet.song.9000.json','["路接曉天人近月，真仙去後只雲歸。", "嶺頭舊曰上昇日，空有山禽自在飛。"]'),
('560bb94a-3b56-4585-bc95-bd92f0d9d181','將赴南平宿龍門洞','張先','宋','宋诗','song-poetry','','[]','此心常欲老林丘，去意徘徊夜更留。',96,'全唐诗/poet.song.9000.json','["此心常欲老林丘，去意徘徊夜更留。", "萬客只貪門外過，少人知有洞中遊。", "春來猶見龍孫出，靜裏微聞石乳流。", "澗水送花通閣底，寺鐘催月落巖頭。", "暫時清夢生危枕，明日濃塵擁敝輈。", "南是符陽北長舉，所嗟不屬古江州。"]'),
('a03f1369-6026-415f-ac9f-a1c086745d8d','吳興元夕','張先','宋','宋诗','song-poetry','','[]','朱屋雕屏展，紅筵繡箔遮。',72,'全唐诗/poet.song.9000.json','["朱屋雕屏展，紅筵繡箔遮。", "傍雲燈作斗，近樹綵成花。", "風月勝千夜，笙歌如一家。", "人叢妨過馬，天色誤啼鴉。", "銅漏春聲換，銀潢曉影斜。", "樓前山未缷，火氣烘朝霞。"]'),
('482da1ac-e758-41d0-9087-5eeea8abcf56','韻和上先頓首','張先','宋','宋诗','song-poetry','','[]','池上飛橋亭外山，野禽偷靜上鈎欄。',64,'全唐诗/poet.song.9000.json','["池上飛橋亭外山，野禽偷靜上鈎欄。", "晚花露重香偏細，春女衣輕體尚寒。", "曲水略殊今日事，南湖曾奉昔人歡。", "郡圖可許增新致，幾處模傳畫樣看。"]'),
('7e5091f2-a54f-418d-bfae-b37db755d9d9','射','張先','宋','宋诗','song-poetry','','[]','射藝功多暮未疲，欲將庭火繼西暉。',64,'全唐诗/poet.song.9000.json','["射藝功多暮未疲，欲將庭火繼西暉。", "弦聲應手裂竹響，旗影翻風戲鳥飛。", "竟日中支矜互勝，傍人如堵見終稀。", "不知雙燭沙河上，誰得牛心一割歸。"]'),
('0ab597b2-b339-4639-a101-edeccf10ebb9','句  其一','張先','宋','宋诗','song-poetry','','[]','愁似鰥魚知夜永，懶同蝴蝶爲春忙。',16,'全唐诗/poet.song.9000.json','["愁似鰥魚知夜永，懶同蝴蝶爲春忙。"]'),
('a6b73add-0342-452b-8687-0aa695e4c81b','句  其二','張先','宋','宋诗','song-poetry','','[]','霓舟忽艤鱸魚鄉，槎閣卻凌雲漢域。',16,'全唐诗/poet.song.9000.json','["霓舟忽艤鱸魚鄉，槎閣卻凌雲漢域。"]'),
('e777c893-a65e-4f3b-8715-073476444d32','句  其三','張先','宋','宋诗','song-poetry','','[]','白怪鱸鄉一旦成，分卻松江半秋色。',16,'全唐诗/poet.song.9000.json','["白怪鱸鄉一旦成，分卻松江半秋色。"]'),
('70fac6b1-40b0-4c03-94fb-097acb06f75b','句  其四','張先','宋','宋诗','song-poetry','','[]','湖山隱後家空在，煙雨詞亡草自青。',16,'全唐诗/poet.song.9000.json','["湖山隱後家空在，煙雨詞亡草自青。"]'),
('a8f728ca-0a3d-483f-9207-344c390beb16','春集東園賦得葉字','王舉正','宋','宋诗','song-poetry','','[]','芳辰聊命駕，郊野賞心愜。',72,'全唐诗/poet.song.9000.json','["芳辰聊命駕，郊野賞心愜。", "亭幽路鬰紆，樹密花重疊。", "暫紓朝紱勞，喜與朋簪接。", "談麈逗松枝，宴賞澄竹葉。", "含和寄蕭散，選勝窮登躡。", "行樂且躊躇，此遊非日涉。"]'),
('aebf7ab3-9839-4fd5-805e-69b84687fc55','留題越州石氏山齋','晏殊','宋','宋诗','song-poetry','','[]','書仙十閣壯儒宮，靈越山川寶勢雄。',64,'全唐诗/poet.song.9000.json','["書仙十閣壯儒宮，靈越山川寶勢雄。", "岫柏亞香侵几席，巖花迴影入簾櫳。", "千秋碧鎖東南竹，一水清含旦暮風。", "文酒雅宜頻讌集，謝家蘭玉有新叢。"]'),
('f501220b-9cb6-4f24-a910-2a0f07a653bd','贈會稽道士','晏殊','宋','宋诗','song-poetry','','[]','藐姑容化現陰館，句漏砂封六乙泥。',64,'全唐诗/poet.song.9000.json','["藐姑容化現陰館，句漏砂封六乙泥。", "五練夜窮青玉枕，七明晨採碧雲梯。", "冠霞高扡浮丘袂，握體深藏鬼谷奚。", "知有山西駐齡藥，何妨相贈一刀圭。"]'),
('e6452fc2-4bb7-4d9d-bd6b-591456bfdc6b','憶越州  其一','晏殊','宋','宋诗','song-poetry','','[]','鑑湖清澈秦望高，涵虛逗碧供吟毫。',32,'全唐诗/poet.song.9000.json','["鑑湖清澈秦望高，涵虛逗碧供吟毫。", "當日醉眼倚空闊，三江七澤才容舠。"]'),
('9912ad40-d25b-40a8-b9b6-86240d80d1fc','憶越州  其二','晏殊','宋','宋诗','song-poetry','','[]','湖山杳渺不可狀，登覽幽求無所遺。',32,'全唐诗/poet.song.9000.json','["湖山杳渺不可狀，登覽幽求無所遺。", "高僧伴吟足清覽，見盡白蓮開落時。"]'),
('df4bb648-fcbb-4b9f-862c-a8083871f2a2','弔蘇哥','晏殊','宋','宋诗','song-poetry','','[]','蘇哥風味逼天真，恐是文君向上人。',32,'全唐诗/poet.song.9000.json','["蘇哥風味逼天真，恐是文君向上人。", "何日九原芳草綠，大家攜酒哭青春。"]'),
('9d7e820a-7553-4a65-a533-1aeef6c84195','正月十八夜','晏殊','宋','宋诗','song-poetry','','[]','槿戶茅齋雅自便，京華風味入新年。',64,'全唐诗/poet.song.9000.json','["槿戶茅齋雅自便，京華風味入新年。", "樓臺冷落收燈夜，門巷蕭條掃雪天。", "病酒不聞花外漏，放朝仍得日高眠。", "何妨靜習閑中趣，欲問林僧結凈緣。"]'),
('8f943d4e-a896-4c10-b57e-202d99da2e1c','寄遠','晏殊','宋','宋诗','song-poetry','','["\u79bb\u522b", "\u7231\u60c5", "\u56de\u5fc6", "\u76f8\u601d"]','寶轂香輪不再逢，峽雲巫雨杳無蹤。',64,'全唐诗/poet.song.9000.json','["寶轂香輪不再逢，峽雲巫雨杳無蹤。", "梨花院落溶溶月，柳絮池塘淡淡風。", "幾日寂寥傷酒後，一番蕭索禁煙中。", "魚書欲寄無由達，水遠山長處處同。"]'),
('805dae7e-329b-4552-81b4-1f8c57edfffb','詠上竿伎','晏殊','宋','宋诗','song-poetry','','[]','百尺竿頭褭褭身，足騰跟掛駭傍人。',32,'全唐诗/poet.song.9000.json','["百尺竿頭褭褭身，足騰跟掛駭傍人。", "漢陰有叟君知否，抱甕區區亦未貧。"]'),
('86e96860-bf29-4d3e-8525-5d2926e42f7e','煮茶','晏殊','宋','宋诗','song-poetry','','[]','稽山新茗綠如煙，靜挈都藍煮惠泉。',31,'全唐诗/poet.song.9000.json','["稽山新茗綠如煙，靜挈都藍煮惠泉。", "未向人間殺風景，更持醪醉花前。"]'),
('bb229b17-4e36-44a4-8ea6-76ae816c3c9c','題太祖廟','晏殊','宋','宋诗','song-poetry','','[]','炎宋肇英主，初九方潛鱗。',36,'全唐诗/poet.song.9000.json','["炎宋肇英主，初九方潛鱗。", "嘗因蓍蔡占，地決天地屯。", "庚庚大橫兆，謦咳如有聞。"]'),
('70b442b2-2913-4fd2-8556-10033c2d20c2','中書即事','晏殊','宋','宋诗','song-poetry','','[]','慘慘高槐落，凄凄餘菊寒。',24,'全唐诗/poet.song.9000.json','["慘慘高槐落，凄凄餘菊寒。", "粉牆多記墨，聊爲拂塵看。"]'),
('b0599d8d-a932-4bfa-9b22-ed3ca7d25a2f','和宋子京召還學士院  其一','晏殊','宋','宋诗','song-poetry','','[]','網索軒窻邃，鑾坡羽衛重。',48,'全唐诗/poet.song.9000.json','["網索軒窻邃，鑾坡羽衛重。", "鷁舟還下瀨，星使出飛龍。", "賦待三英集，詞須五吏供。", "會看邊燧息，橫霈紫泥封。"]'),
('99a43da2-7104-4ecf-8797-e5349f7426c6','和宋子京召還學士院  其二','晏殊','宋','宋诗','song-poetry','','[]','暮召三山峻，晨趨一節回。',48,'全唐诗/poet.song.9000.json','["暮召三山峻，晨趨一節回。", "乍維青雀舫，還直右銀臺。", "陟降丹塗密，論思武帳開。", "欲談當世務，元藉軼羣才。"]'),
('2b78f5a2-421a-4c34-9b80-f962aa0d2315','竹醉日','晏殊','宋','宋诗','song-poetry','','[]','苒苒渭濱族，蕭蕭塵外姿。',24,'全唐诗/poet.song.9000.json','["苒苒渭濱族，蕭蕭塵外姿。", "如能樂封殖，何必醉中移。"]'),
('491d091c-80cb-4abb-8efa-807299127f20','列子有力命王充論衡有命祿極言必定之致覽之有感','晏殊','宋','宋诗','song-poetry','','[]','大鈞播羣物，零茂歸自然。',108,'全唐诗/poet.song.9000.json','["大鈞播羣物，零茂歸自然。", "默定既有初，不爲智力遷。", "籞寇導其流，仲任派其源。", "智愚信自我，通塞當由天。", "宰世曰臯伊，迷邦有顔原。", "吾道誠一概，彼途鍾百端。", "卷之入纖毫，舒之盈八埏。", "進退得其宜，夸榮非所先。", "朝聞可夕隕，吾奉聖師言。"]'),
('6a2245fe-fdb8-438c-8026-54d38912373d','和王校勘中夏東園','晏殊','宋','宋诗','song-poetry','','[]','東園何所樂，所樂非塵事。',84,'全唐诗/poet.song.9000.json','["東園何所樂，所樂非塵事。", "野竹亂無行，幽花晚多思。", "閑窺魚尾赤，暗辨蜂腰細。", "樹影密遮林，籐梢狂罥袂。", "潘蔬足登膳，陶秫徑取醉。", "幸獲我汝交，都忘今昔世。", "歡言捧瑤佩，願以疏麻繼。"]'),
('acc04e8e-7499-47f1-8095-d33a628d7c77','初秋宿直','晏殊','宋','宋诗','song-poetry','','[]','絳河星斗夜闌干，禁署沈沈閉九關。',64,'全唐诗/poet.song.9000.json','["絳河星斗夜闌干，禁署沈沈閉九關。", "上帝冊書羣玉府，仙人宮闕巨鰲山。", "涼蟾影度秋陰薄，促漏聲來夜唱閑。", "擁鼻吟多欲愁絕，嚴鐘凄斷樹鳥還。"]'),
('2ba4f15b-4619-4e0d-b857-88328efc9365','安昌侯','晏殊','宋','宋诗','song-poetry','','[]','蓮勺移家近七遷，魯儒章句世相傳。',64,'全唐诗/poet.song.9000.json','["蓮勺移家近七遷，魯儒章句世相傳。", "關中沃壞通涇渭，堂上繁聲逐管絃。", "身服儒衣同蔡義，日將卮酒對彭宣。", "高墳丈五陽陵外，千古朱雲氣凜然。"]'),
('0ffa2534-b36f-4732-a715-560e822ce861','假中示判官張寺丞王校勘','晏殊','宋','宋诗','song-poetry','','[]','元巳清明例未開，小園幽徑獨徘徊。',64,'全唐诗/poet.song.9000.json','["元巳清明例未開，小園幽徑獨徘徊。", "春寒不定斑斑雨，宿醉難禁灧灧杯。", "無可奈何花落去，似曾相識燕歸來。", "遊梁賦客多風味，莫惜青錢萬選才。"]'),
('07146e67-89e3-43a8-a0d9-ba0bb5b4539f','雪中','晏殊','宋','宋诗','song-poetry','','[]','平臺千里渴商霖，內史憂民望最深。',32,'全唐诗/poet.song.9000.json','["平臺千里渴商霖，內史憂民望最深。", "衣上六花非所好，畝間盈尺是吾心。"]'),
('8a53a661-4e8c-48ab-92fb-a8b500690ead','盂蘭盆','晏殊','宋','宋诗','song-poetry','','[]','紅白薇英落，朱黄槿艷殘。',24,'全唐诗/poet.song.9000.json','["紅白薇英落，朱黄槿艷殘。", "家人愁溽暑，計是望盂蘭。"]'),
('106aa5b8-ad5a-4fd1-8e58-9d8f400fb147','古瓦硯詩  其一','晏殊','宋','宋诗','song-poetry','','[]','鄴城宮殿久荒涼，縹瓦隨波出禁牆。',32,'全唐诗/poet.song.9000.json','["鄴城宮殿久荒涼，縹瓦隨波出禁牆。", "誰約蘚文成古硯，放閑裁破碧鴛鴦。"]'),
('cf6964fc-4591-463f-885e-f0903d03715d','古瓦硯詩  其二','晏殊','宋','宋诗','song-poetry','','[]','已恣玉鋒磨蘚骨，更持蟾淚濕雲根。',32,'全唐诗/poet.song.9000.json','["已恣玉鋒磨蘚骨，更持蟾淚濕雲根。", "欲知千載凄涼意，尚有昭陽夜雨痕。"]'),
('07c430fe-88cb-4738-9301-14b1aa8c7ac9','送董信州','晏殊','宋','宋诗','song-poetry','','[]','鳳闕承丹詔，麟符得舊鄉。',48,'全唐诗/poet.song.9000.json','["鳳闕承丹詔，麟符得舊鄉。", "雨中吳岫碧，村罅楚梅黄。", "使節江湖外，城樓翼軫旁。", "吾知召南樹，從此接維桑。"]'),
('c35cb3a0-dc1a-4c0c-96d3-8f6c73714b40','建茶','晏殊','宋','宋诗','song-poetry','','[]','北苑中春岫幌開，里民清曉駕肩來。',32,'全唐诗/poet.song.9000.json','["北苑中春岫幌開，里民清曉駕肩來。", "豐隆已助新芽出，更作讙聲動地催。"]'),
('13fc6ea3-6ef4-4851-bc72-b9c12fef41cf','禁苑','晏殊','宋','宋诗','song-poetry','','[]','風回玉宇簫聲遠，日下瓊林佩影閑。',32,'全唐诗/poet.song.9000.json','["風回玉宇簫聲遠，日下瓊林佩影閑。", "待得年光遍天下，始教春色到人間。"]'),
('842e732e-34f4-4078-ac39-38642c920837','題鞏縣西門周襄王廟','晏殊','宋','宋诗','song-poetry','','[]','人來人去市朝變，山後山前煙霧凝。',32,'全唐诗/poet.song.9000.json','["人來人去市朝變，山後山前煙霧凝。", "縈带二川河洛水，寂寥千古帝王陵。"]'),
('b9f0d878-1f22-4215-a5e8-14e8e6308e47','鹿葱花','晏殊','宋','宋诗','song-poetry','','[]','宮后扇開青雉尾，羽人衣剪赤霜文。',32,'全唐诗/poet.song.9000.json','["宮后扇開青雉尾，羽人衣剪赤霜文。", "農皇藥錄真無謂，不向萱叢辯糾紛。"]'),
('de526761-1639-4504-85c6-2e3aa0da2a67','送僧歸護國寺','晏殊','宋','宋诗','song-poetry','','[]','海嶠黄金剎，安禪不記秋。',48,'全唐诗/poet.song.9000.json','["海嶠黄金剎，安禪不記秋。", "來膺臣宰召，歸泛越人舟。", "達性融三界，隨緣極四流。", "還持雙股錫，拂蘚坐巖幽。"]'),
('7b9dd89b-1f28-4377-8dff-40392c154c99','麻姑山','晏殊','宋','宋诗','song-poetry','','[]','昔年權暫領軍城，靜愛仙山詠過春。',64,'全唐诗/poet.song.9000.json','["昔年權暫領軍城，靜愛仙山詠過春。", "天下雲車曾祖駕，城中鼇海幾生塵。", "明知綠髪升真籍，堪笑蒼顔預憲臣。", "我若粗成忠國事，赤松曾羨漢廷人。"]'),
('b79309f2-bee3-4d7a-890b-b689d55d1757','牡丹','晏殊','宋','宋诗','song-poetry','','[]','水昌宮殿接龍津，碧樹陽春曉色新。',32,'全唐诗/poet.song.9000.json','["水昌宮殿接龍津，碧樹陽春曉色新。", "朱戶曲房能駐日，酥盤金勝自生春。"]'),
('ad8ab871-80ce-40c7-8ade-5beaf6f0e005','迎春花','晏殊','宋','宋诗','song-poetry','','[]','淺艷侔鶯羽，纖條結兔絲。',24,'全唐诗/poet.song.9000.json','["淺艷侔鶯羽，纖條結兔絲。", "偏凌早春發，應誚衆芳遲。"]'),
('afb40a32-d916-47ac-b5ec-078ccdf16387','金燈花  其一','晏殊','宋','宋诗','song-poetry','','[]','煌煌五枝燈，下有玉蟠螭。',36,'全唐诗/poet.song.9000.json','["煌煌五枝燈，下有玉蟠螭。", "漢宮已荆棘，此地生何爲。", "既無膏火用，虛名徒自欺。"]'),
