('70184536-d72a-42c6-8753-01ce14a1f048','椿','晏殊','宋','宋诗','song-poetry','','[]','峨峨楚南樹，杳杳含風韻。',24,'全唐诗/poet.song.9000.json','["峨峨楚南樹，杳杳含風韻。", "何用八千秋，騰凌詫朝菌。"]'),
('4b9d2c99-bced-46f3-84ff-24911c15166e','柳','晏殊','宋','宋诗','song-poetry','','[]','河柳擅佳名，青條發紅穗。',24,'全唐诗/poet.song.9000.json','["河柳擅佳名，青條發紅穗。", "因愁百卉嬌，強作芳菲意。"]'),
('97ca16b5-fc6b-4f30-984f-b73b6b55a675','金鳳花','晏殊','宋','宋诗','song-poetry','','[]','九苞顔色春霞萃，丹穴威儀秀氣殫。',32,'全唐诗/poet.song.9000.json','["九苞顔色春霞萃，丹穴威儀秀氣殫。", "題品直須名最上，昂昂驤首倚朱欄。"]'),
('ae173e91-afb7-4f91-917c-64e001247ae9','金柅園','晏殊','宋','宋诗','song-poetry','','[]','臨川樓上柅園中，十五年前此會同。',32,'全唐诗/poet.song.9000.json','["臨川樓上柅園中，十五年前此會同。", "一曲清歌滿樽酒，人生何處不相逢。"]'),
('ac370c33-fb59-46cf-8f48-416590123843','上元','晏殊','宋','宋诗','song-poetry','','[]','金翠光中寶焰繁，山樓高下鼓聲喧。',32,'全唐诗/poet.song.9000.json','["金翠光中寶焰繁，山樓高下鼓聲喧。", "兩軍伎女輕如鶻，百尺竿頭電線翻。"]'),
('21426e29-2961-436f-bf50-355c8c4ea28f','七夕','晏殊','宋','宋诗','song-poetry','','[]','雲幕無多斗柄移，鵲慵烏慢得橋遲。',32,'全唐诗/poet.song.9000.json','["雲幕無多斗柄移，鵲慵烏慢得橋遲。", "若教精衛填河漢，一水還應有盡時。"]'),
('f9cecf4c-e7e6-4a29-a2c8-f3a49bf483e8','奉和真宗御製後苑雜花海棠','晏殊','宋','宋诗','song-poetry','','[]','太液波才綠，靈和絮未飄。',48,'全唐诗/poet.song.9000.json','["太液波才綠，靈和絮未飄。", "霞文光啟旦，珠琲密封條。", "積潤涵仙露，濃英奪海綃。", "九陽資造化，天意屬喬繇。"]'),
('a5ea4e87-0efe-4794-9985-100e8a7e6a22','海棠  其一','晏殊','宋','宋诗','song-poetry','','[]','輕盈千結亂櫻叢，占得年芳近碧櫳。',64,'全唐诗/poet.song.9000.json','["輕盈千結亂櫻叢，占得年芳近碧櫳。", "逐處間勻高下萼，幾番分破淺深紅。", "煙晴始覺香纓綻，日極猶疑蠟蔕融。", "數夕朱欄未飄落，再三珍重石尤風。"]'),
('6e7a402c-62ee-433a-b303-ae044326afaf','海棠  其二','晏殊','宋','宋诗','song-poetry','','[]','杳靄何驚目，鮮妍欲蕩魂。',48,'全唐诗/poet.song.9000.json','["杳靄何驚目，鮮妍欲蕩魂。", "向人無限思，當晝不勝繁。", "浩露晴方浥，遊蜂暖更喧。", "只應春有意，留贈子山園。"]'),
('996a0999-0dc1-4158-a6df-41d5e8e8e4ce','海棠  其三','晏殊','宋','宋诗','song-poetry','','[]','昔聞遊客話芳菲，濯錦江頭幾萬枝。',32,'全唐诗/poet.song.9000.json','["昔聞遊客話芳菲，濯錦江頭幾萬枝。", "縱使許昌詩筆健，可能終古絕妍辭。"]'),
