('5dd5c69f-d299-4471-b27c-5f5d686220b5','元日詞 東宮閣 其二','晏殊','宋','宋诗','song-poetry','','[]','條風發動協初辰，玄圃瑤山景象新。',32,'全唐诗/poet.song.9000.json','["條風發動協初辰，玄圃瑤山景象新。", "千載百靈資介福，滄溟重潤月重輪。"]'),
('b75f6501-43c2-4349-99c0-29903c1b62c2','癸酉歲元日中書致齋感事','晏殊','宋','宋诗','song-poetry','','[]','一葉春王拆瑞筇，八齋西省夕香濃。',64,'全唐诗/poet.song.9000.json','["一葉春王拆瑞筇，八齋西省夕香濃。", "多年不宿金閨署，半夜再聞長樂鐘。", "卻展舊編探史漢，更慚高步接夔龍。", "十思三省無荒豫，千載亨辰豈易逢。"]'),
('eb6c9610-94f5-475e-9305-c40510710451','壬午歲元日雪','晏殊','宋','宋诗','song-poetry','','[]','千門初曙徹星河，颯灑貂裘潤玉珂。',64,'全唐诗/poet.song.9000.json','["千門初曙徹星河，颯灑貂裘潤玉珂。", "向獸樽前飛絮早，景陽鐘後落梅多。", "無聲暗重瓊林彩，有意微藏璧沼波。", "三殿端辰得嘉瑞，不須庭燎夜如何。"]'),
('85223074-e263-4db1-a944-1e578c33f5a9','奉和聖製立春日  其一','晏殊','宋','宋诗','song-poetry','','[]','紫宙星回後，青郊斗建時。',48,'全唐诗/poet.song.9000.json','["紫宙星回後，青郊斗建時。", "上林鶯囀早，南畝雪消遲。", "雲矞千祥集，風條萬類滋。", "皇情同率土，黔首頌昌期。"]'),
('16adade6-869f-4fc8-9cbe-34d455662bfa','奉和聖製立春日  其二','晏殊','宋','宋诗','song-poetry','','[]','陰陽自協璇璣遠，和煦潛隨緹管升。',64,'全唐诗/poet.song.9000.json','["陰陽自協璇璣遠，和煦潛隨緹管升。", "十二紫關魚籥啟，九重曉闕絳煙凝。", "芳華稍變青門柳，寒凍微消北陸冰。", "宸藻下頒羲日麗，八紘民庶保年登。"]'),
('1d22d5f3-b5fc-4f5f-bd9f-89be2a95f124','登和聖製新春','晏殊','宋','宋诗','song-poetry','','[]','斗柄東回六合春，堯天曆象與時新。',96,'全唐诗/poet.song.9000.json','["斗柄東回六合春，堯天曆象與時新。", "銅壺瑞氣延疏漏，青輅祥風繞畫輪。", "雲裏樓臺高鬰鬰，雨中原隰碧鱗鱗。", "千枝彩萼梅英吐，百尺金絲柳带勻。", "秉籙調元功有序，在璿觀妙政惟醇。", "仰瞻魏闕宣和會，共識皇恩子萬民。"]'),
('601e1557-5bc4-4ea7-ad88-ee8c4501dfd0','立春祀太乙  其一','晏殊','宋','宋诗','song-poetry','','[]','紫毛雙節引青童，一片空歌韻曉風。',32,'全唐诗/poet.song.9000.json','["紫毛雙節引青童，一片空歌韻曉風。", "太昊茲辰授春令，鶯旗應在矞雲中。"]'),
('66b61222-b71f-4fcc-8b93-0b9fb9324097','立春祀太乙  其二','晏殊','宋','宋诗','song-poetry','','[]','華燈明滅羽衣攢，翠柳蕭森矮檜寒。',32,'全唐诗/poet.song.9000.json','["華燈明滅羽衣攢，翠柳蕭森矮檜寒。", "千步回廊繞金殿，水蒼瑤佩響珊珊。"]'),
('6d924e27-59ea-41e0-a311-4010897dbdaf','立春日詞 御閣 其一','晏殊','宋','宋诗','song-poetry','','[]','令月歸餘屆早春，羲舒相望協元辰。',32,'全唐诗/poet.song.9000.json','["令月歸餘屆早春，羲舒相望協元辰。", "初陽乍逐青旂動，聖壽長隨鳳曆新。"]'),
