('028b013e-53e8-44b7-9569-6be1fe968f65','端午詞 昇王閣 其一','晏殊','宋','宋诗','song-poetry','','[]','朱邸沐蘭逢令節，丹廷祝壽喜嘉辰。',32,'全唐诗/poet.song.9000.json','["朱邸沐蘭逢令節，丹廷祝壽喜嘉辰。", "兩宮榮養多延慶，百福潛隨命縷新。"]'),
('8f5b4843-63a1-4641-b57f-d8242975501e','端午詞 昇王閣 其二','晏殊','宋','宋诗','song-poetry','','[]','織組文繒載舊儀，晨朝丹扆奉天慈。',32,'全唐诗/poet.song.9000.json','["織組文繒載舊儀，晨朝丹扆奉天慈。", "六齋清素來多福，歲歲今辰侍宴私。"]'),
('91bb3f48-fab3-401e-b57f-64f1606b09e1','端午詞 御閣 其一','晏殊','宋','宋诗','song-poetry','','[]','五綵絲長繫臂初，萬年芳樹影扶疏。',32,'全唐诗/poet.song.9000.json','["五綵絲長繫臂初，萬年芳樹影扶疏。", "豈勞方士標神篆，自有真靈衛帝居。"]'),
('9522ae3d-4048-41e3-943e-7b6e2dc92234','端午詞 御閣 其二','晏殊','宋','宋诗','song-poetry','','[]','九子粽新傳楚俗，赤靈符驗出仙方。',32,'全唐诗/poet.song.9000.json','["九子粽新傳楚俗，赤靈符驗出仙方。", "漢宮盡祝如天壽，鵲尾鑪煙起瑞香。"]'),
('fefe8480-d938-43e4-999a-ce0f39b27368','端午詞 御閣 其三','晏殊','宋','宋诗','song-poetry','','[]','乍結香茅祈福壽，更纏金縷貢芳新。',32,'全唐诗/poet.song.9000.json','["乍結香茅祈福壽，更纏金縷貢芳新。", "丹臺素有延生籙，歲歲迎祥在此辰。"]'),
('e963dd02-b0dc-47e0-ae7a-fbc4f5a42b8c','端午詞 御閣 其四','晏殊','宋','宋诗','song-poetry','','[]','仙家既有靈符術，越俗兼爲競渡遊。',32,'全唐诗/poet.song.9000.json','["仙家既有靈符術，越俗兼爲競渡遊。", "三十六宮遲日永，綺窗朱戶彩雲浮。"]'),
('b5533765-6f41-434f-bf85-bbacfe9c7cbd','端午詞 東宮閣 其一','晏殊','宋','宋诗','song-poetry','','[]','揚子江心鑄鑑成，俗傳茲日最標靈。',32,'全唐诗/poet.song.9000.json','["揚子江心鑄鑑成，俗傳茲日最標靈。", "宣猷視學通文史，問膳多歡奉帝廷。"]'),
('3b435977-6464-40b8-b8a3-740fb1c64c25','端午詞 東宮閣 其二','晏殊','宋','宋诗','song-poetry','','[]','百藥初收味最良，玉函仍啟太清方。',32,'全唐诗/poet.song.9000.json','["百藥初收味最良，玉函仍啟太清方。", "扇裁葵葉風頻度，漏轉金胥日更長。"]'),
('32583ff1-bb8f-4ccb-9e5f-a3c0d66b4055','端午作','晏殊','宋','宋诗','song-poetry','','[]','汩渚沉沉不可追，楚人猶自弔湘累。',32,'全唐诗/poet.song.9000.json','["汩渚沉沉不可追，楚人猶自弔湘累。", "靈均未免爭瓊糈，卻道蛟龍畏色絲。"]'),
('31d8ce1a-f27f-4711-9856-9645d6944edd','七夕','晏殊','宋','宋诗','song-poetry','','[]','百子池深漲綠苔，九光燈迥綠浮埃。',64,'全唐诗/poet.song.9000.json','["百子池深漲綠苔，九光燈迥綠浮埃。", "天孫寶駕何年駐，阿母飈輪此夜來。", "空外粉筵和露濕，靜中珠幌徹明開。", "秋河不斷長相望，豈獨人間事可哀。"]'),
('356fff90-88d6-4315-8c30-f86ede532910','社日戲題呈任副樞','晏殊','宋','宋诗','song-poetry','','[]','開樽幸有治聾醖，把葉能無送燕章。',32,'全唐诗/poet.song.9000.json','["開樽幸有治聾醖，把葉能無送燕章。", "所惜近停司飲會，不如村叟醉秋光。"]'),
('66cdb9cc-3edf-4834-8220-e6eb80e3eee1','丙寅中秋詠月','晏殊','宋','宋诗','song-poetry','','[]','玉籥秋初半，冰輪歲有期。',120,'全唐诗/poet.song.9000.json','["玉籥秋初半，冰輪歲有期。", "苦吟含翰久，清宴下樓遲。", "雁怯波光動，蛩愁葉影危。", "烘簾頻卷押，溫酎旋凝澌。", "皎外蟾生滴，寒中桂有枝。", "星文藏熠燿，露彩見華滋。", "苑靜疏螢濕，巢空驚鶴移。", "漸穿鳴瑟幌，偏鑒讀書帷。", "濛谷徒催曉，纖阿莫放虧。", "陳王收妙舞，疑待仲宣辭。"]'),
('565e1924-bb32-4b42-8c99-5924b8079621','次韻和王校勘中秋月','晏殊','宋','宋诗','song-poetry','','[]','廣寒仙署愜心期，秋半梧臺木葉稀。',64,'全唐诗/poet.song.9000.json','["廣寒仙署愜心期，秋半梧臺木葉稀。", "有客正吟星北共，何人重賦鵲南飛。", "光含綺席傳三雅，影逗蘭房撤九微。", "趨府逸才過鮑掾，不辭終夕賞清暉。"]'),
('d6bd157b-31f8-463b-a924-0634077cce37','中秋月','晏殊','宋','宋诗','song-poetry','','[]','三十六旬內，此時心賞並。',48,'全唐诗/poet.song.9000.json','["三十六旬內，此時心賞並。", "中分九秋夜，占斷百宵明。", "冷照蘭閨澈，光含綺席清。", "誰知滄海曲，珠蚌最盈盈。"]'),
('822e92ab-dd92-4b7f-89eb-ef22d50c9ac4','中秋月  其一','晏殊','宋','宋诗','song-poetry','','["\u7f81\u65c5", "\u4e2d\u79cb\u8282", "\u8d4f\u6708", "\u5b64\u5bc2", "\u60c6\u6005"]','一輪霜影轉庭梧，此夕羈人獨向隅。',32,'全唐诗/poet.song.9000.json','["一輪霜影轉庭梧，此夕羈人獨向隅。", "未必素娥無悵恨，玉蟾清冷桂華孤。"]'),
('015c1baa-f8f9-4faf-8ff1-cee4d55e6768','中秋月  其二','晏殊','宋','宋诗','song-poetry','','[]','天時與人意，齟齬舊無疑。',48,'全唐诗/poet.song.9000.json','["天時與人意，齟齬舊無疑。", "坐久翻遺恨，光來已後期。", "行雲凝黛色，見跋費金枝。", "況復輸來夜，笙歌繼夕曦。"]'),
('abf6ca01-982a-415d-a360-131c6d9de828','次韻和司空相公閏秋重九中書對菊','晏殊','宋','宋诗','song-poetry','','[]','兩掖儀臺峻，珍叢應序黄。',72,'全唐诗/poet.song.9000.json','["兩掖儀臺峻，珍叢應序黄。", "積分迴令節，伏檻賞幽芳。", "昧谷重延律，仙州剩借霜。", "冒寒知薏苦，逾分得荃香。", "漢幄羣生遂，虞廷萬事康。", "與人同所樂，留翫屬澄觴。"]'),
('e734f1af-33c1-44e1-a191-2803cbe4e46a','九日北郡登高見寄','晏殊','宋','宋诗','song-poetry','','[]','前日登高泛玉卮，擊銅賡唱有新辭。',66,'全唐诗/poet.song.9000.json','["前日登高泛玉卮，擊銅賡唱有新辭。", "如何偶作銷魂別，又復重吟發報機菊詩。", "上苑盍簪延景刻，北都投轄盛官儀。", "煩君見想懽言者，可奈衡門絕貢綦。"]'),
('0f52e907-6537-4f10-a3fe-e3ed22b3ca9c','九日宴集和徐通判韻','晏殊','宋','宋诗','song-poetry','','[]','散插黄花兩佩萸，粉饘蓬餌釂觴初。',64,'全唐诗/poet.song.9000.json','["散插黄花兩佩萸，粉饘蓬餌釂觴初。", "清歌咽後雲生袂，妙舞翻時雪滿裾。", "上客采香逢木密，佳人投釣得王餘。", "秋光屈指猶三七，莫向賓朋綺宴疏。"]'),
('c595f6c0-0ed0-4a34-930f-f6412b6726a4','次韻和史館呂相公九日偶成','晏殊','宋','宋诗','song-poetry','','[]','鳳闕千門制不奢，上公精意在朝家。',64,'全唐诗/poet.song.9000.json','["鳳闕千門制不奢，上公精意在朝家。", "重陽蜜餌承班詔，西苑璆樽輟泛花。", "蕭相未央功已半，漢皇宣室宴非賒。", "由來位極妨行樂，目斷黄壚酒旆斜。"]'),
('da22464a-5695-484e-81b0-00aedcf647c9','八日菊','晏殊','宋','宋诗','song-poetry','','[]','瑞蓂才半折，金蕊已爭妍。',48,'全唐诗/poet.song.9000.json','["瑞蓂才半折，金蕊已爭妍。", "幸得重陽近，貪爲一日先。", "登高謀宿約，泛酒試芳筵。", "詰旦尋餘馥，明知賞愛偏。"]'),
('d8b7bcec-479d-4641-a697-046f2825cc40','重陽夕內宿','晏殊','宋','宋诗','song-poetry','','[]','把菊醒陶酒，揚鞭入漢闈。',48,'全唐诗/poet.song.9000.json','["把菊醒陶酒，揚鞭入漢闈。", "聚蚊秋未息，獨鳥暮先歸。", "世有涼暄隔，人無今昨非。", "悠然倒冠佩，頻夢北山薇。"]'),
('dc3aa397-c98c-4bfa-bc67-e327dd13d8d6','九月八日游渦','晏殊','宋','宋诗','song-poetry','','[]','黄花夾徑疑無路，紅葉臨流巧勝春。',33,'全唐诗/poet.song.9000.json','["黄花夾徑疑無路，紅葉臨流巧勝春。", "前去重陽猶一日，不辭傾蓋盡蟻醪醇。"]'),
('fff53ec7-8177-4a4b-a2e4-2675017d2813','閏九月九日','晏殊','宋','宋诗','song-poetry','','[]','閏秋重九財政赤字佳辰，猶見黄花裛露新。',35,'全唐诗/poet.song.9000.json','["閏秋重九財政赤字佳辰，猶見黄花裛露新。", "更作登高亦何害，恨無彭澤苦吟人。"]'),
('d2bb00c4-2e58-4fc8-bdb7-2fb2692ea124','和至日北園讌集','晏殊','宋','宋诗','song-poetry','','[]','清曉融風肅桂堂，郡寮多暇舞筵張。',65,'全唐诗/poet.song.9000.json','["清曉融風肅桂堂，郡寮多暇舞筵張。", "臺高已驗雲容媚，日暖懸知刻漏成長。", "溪子弩寒千命中，蘭英酒熟百傳觴。", "官曹事集神都近，預拜需函慶一陽。"]'),
('55bd88c8-28dd-4384-a4f8-b17e4dca725c','奉和聖製冬至','晏殊','宋','宋诗','song-poetry','','[]','吉序冠三正，民時順盛成。',72,'全唐诗/poet.song.9000.json','["吉序冠三正，民時順盛成。", "歲穰千畝實，氣爽六符平。", "肆樂遵年律，迎長藹頌聲。", "雲濃燕雁度，雪霽楚蘭榮。", "異域梯航集，諸侯篚貢盈。", "堯仁敷萬有，同此一陽生。"]'),
('5b9c5976-aa95-49ff-ae64-b9ba526a8575','奉和聖製除夜  其一','晏殊','宋','宋诗','song-poetry','','[]','祕掖楯軒嚴萬戶，慶宵躔次會三辰。',65,'全唐诗/poet.song.9000.json','["祕掖楯軒嚴萬戶，慶宵躔次會三辰。", "丹闈難拿穆猶凝夕，佳氣葱瓏漸報春。", "調曆自將穹厚永，聖辭常與歲時新。", "送寒旁磔迎和令，率土羣生仰昊旻。"]'),
('ad673893-1177-4968-9d9e-cd115db2ce8d','奉和聖製除夜  其二','晏殊','宋','宋诗','song-poetry','','[]','珠躔回碧落，絳燎燭青規。',48,'全唐诗/poet.song.9000.json','["珠躔回碧落，絳燎燭青規。", "瑣闥瓊籤度，層臺玉漏移。", "納新皇澤普，順節聖情怡。", "萬宇長安陌，鄉儺集此時。"]'),
('aa67ce79-c926-4518-ad04-4f6000153da2','和三兄除夜','晏殊','宋','宋诗','song-poetry','','[]','星漢迴曾宇，塤箎集上都。',48,'全唐诗/poet.song.9000.json','["星漢迴曾宇，塤箎集上都。", "夜寒凝爆燎，春氣入屠蘇。", "九陌傳珂乘，千門促漏壺。", "此時開棣宴，仍在碧城隅。"]'),
('bbdf19e1-851e-4fcc-9c33-36e2161acbf1','次韻和致仕陳相公除夜','晏殊','宋','宋诗','song-poetry','','[]','從來歲除詠，託諷情非一。',48,'全唐诗/poet.song.9000.json','["從來歲除詠，託諷情非一。", "公在維師年，久諧歸政逸。", "辛盤具芳鬰，柏酒澄嘉栗。", "猶厭賀車煩，晨門效圭篳。"]'),
('5a81d935-619d-4232-ab86-81af44d64a52','春陰','晏殊','宋','宋诗','song-poetry','','[]','十二重環閟洞房，愔愔危樹俯迴塘。',64,'全唐诗/poet.song.9000.json','["十二重環閟洞房，愔愔危樹俯迴塘。", "風迷戲蜨閑無緒，露裛幽花冷自香。", "綺席醉吟銷桂酌，玉臺愁作澀銀簧。", "梅青麥綠江城路，更與登高望楚鄉。"]'),
('4075fe22-322d-47d3-9dfb-1bd684847946','賦得秋雨','晏殊','宋','宋诗','song-poetry','','[]','點滴行雲覆苑牆，飄蕭微影度迴塘。',64,'全唐诗/poet.song.9000.json','["點滴行雲覆苑牆，飄蕭微影度迴塘。", "秦聲未覺朱絃潤，楚夢先知薤葉涼。", "野水有波增澹碧，霜林無韻濕疏黄。", "螢稀燕寂高窗暮，正是西風玉漏長。"]'),
('b76855b9-30b1-4603-9ccd-08da6ea5a358','送凌侍郎歸鄉','晏殊','宋','宋诗','song-poetry','','["\u9001\u522b", "\u5199\u4eba", "\u8d5e\u9882"]','江南藩郡古宣城，碧落神仙擁使旌。',64,'全唐诗/poet.song.9000.json','["江南藩郡古宣城，碧落神仙擁使旌。", "津吏戒船東下穩，懸僚負弩晝歸榮。", "江山謝守高吟地，風月朱公故里情。", "曾預漢庭三獨坐，府中誰敢伴飛觥。"]'),
('586813b4-f96e-43b0-80c8-030d50ea1a6d','張太傅生日詩','晏殊','宋','宋诗','song-poetry','','[]','三陟槐庭二將壇，冊書文武載勳賢。',64,'全唐诗/poet.song.9000.json','["三陟槐庭二將壇，冊書文武載勳賢。", "辭榮尚峻經邦秩，養素方臨釣渭年。", "清會別開金谷墅，新吟多雜蕊珠篇。", "驚姜今日增華耀，海內簪紳共祝延。"]'),
('ff35f7f0-8bb0-4a7d-8493-be9983260454','巢父井','晏殊','宋','宋诗','song-poetry','','[]','稟生值堯年，率性在龐厚。',168,'全唐诗/poet.song.9000.json','["稟生值堯年，率性在龐厚。", "安巢一枝上，豈曰鶉居陋。", "潁波人洗耳，曾不污牛口。", "諒茲耕耒暇，鑿飲隈林藪。", "含飴鼓其腹，帝力予何有。", "遂令千載外，此地存遺甃。", "泓然逼喬木，宛若棲嵵舊。", "鄉人揭題榜，行旅諧瞻覯。", "我來觀古蹟，愕立徘徊久。", "凄其望清風，不獲見師友。", "願言𣂏一勺，拭面洗心垢。", "翹勤慕高躅，感慨陳卮酒。", "思齊胡可望，庶以寬容瞀。", "夙駕恨長途，憑高重回首。"]'),
('9c9f6bf6-ad6f-4599-ba3b-a163e638bd4f','轉運度支得青州資政黄素書韓吏部伯夷頌許昌相以以詩跋尾遂爲七言因而寄及謹用拙篇紀咏','晏殊','宋','宋诗','song-poetry','','[]','首陽垂範遠，吏部屬辭深。',48,'全唐诗/poet.song.9000.json','["首陽垂範遠，吏部屬辭深。", "染翰著嘉尚，系言光德音。", "褒崇亘千𥜥，精妙極雙金。", "題詠益珍秘，用昭賢彥心。"]'),
('b71dbf75-7af6-49e1-9d2f-7f8ac54679cb','次韻謝借觀五老圖','晏殊','宋','宋诗','song-poetry','','[]','道明回詔樂清閑，便向中朝脫冕冠。',64,'全唐诗/poet.song.9000.json','["道明回詔樂清閑，便向中朝脫冕冠。", "百日秉樞登相府，千年青史表旌標。", "泰運正隆嫌氣熱，乾綱初整畏冰寒。", "逍遙唱和多高致，儀象霜風俾後看。"]'),
('42ad69c3-a71d-4a10-bfed-f44c3907eded','贈李陽孫','晏殊','宋','宋诗','song-poetry','','[]','不忍與君別，憐君仁義人。',24,'全唐诗/poet.song.9000.json','["不忍與君別，憐君仁義人。", "三年官滿後，依舊一家貧。"]'),
('2b838c6f-0c98-4acc-8363-2326b265aa4b','棋盤石','晏殊','宋','宋诗','song-poetry','','[]','洞仙遺下石棋盤，人到壺天靜處看。',64,'全唐诗/poet.song.9000.json','["洞仙遺下石棋盤，人到壺天靜處看。", "十九路誰彈黑界，幾千年自带雲寒。", "面平可足流星勢，塵凈元無舊蘚瘢。", "乾雹聲中聞子響，不知還許採樵觀。"]'),
('4a817cbf-8d19-4c9b-8e1c-59698e1b2b6a','崇因寺','晏殊','宋','宋诗','song-poetry','','[]','卷簾山色眼前見，入夜濤聲枕上聞。',32,'全唐诗/poet.song.9000.json','["卷簾山色眼前見，入夜濤聲枕上聞。", "苔徑雨餘堆落葉，石樓風靜鎖寒雲。"]'),
('1f6dbde7-e6eb-4856-ad19-f7050aa02ff0','憶臨川舊遊','晏殊','宋','宋诗','song-poetry','','[]','仲子幽居杳藹間，迴環十畝盡林巒。',64,'全唐诗/poet.song.9000.json','["仲子幽居杳藹間，迴環十畝盡林巒。", "遊魚倒泝清泉急，乳雉驚飛夕燒乾。", "繫馬短亭乘草茁，攜壺芳榭值梅酸。", "浮生莫道今如昨，曷月朋簪爭此歡。"]'),
('1f6a3f9e-cf64-4cf8-af08-530584ea582c','題東湖涵虛閣','晏殊','宋','宋诗','song-poetry','','[]','水有支流樹有孫，重重門巷掛朱軒。',64,'全唐诗/poet.song.9000.json','["水有支流樹有孫，重重門巷掛朱軒。", "三君雅望標人傑，千里澄波隔世喧。", "西對戶庭徐孺宅，北傳鐘梵給孤園。", "欲知嗣續無窮勝，兩兩榮歸漢使轓。"]'),
('b79d9bb4-642f-486e-82a7-7598d7ca9b29','西垣榴花','晏殊','宋','宋诗','song-poetry','','[]','山木有甘實，托根清禁中。',24,'全唐诗/poet.song.9000.json','["山木有甘實，托根清禁中。", "歲芳搖落盡，獨自向炎風。"]'),
('9d1017ad-d3fa-412f-9d01-e05fcb1cac4b','送鉛山周尉','晏殊','宋','宋诗','song-poetry','','[]','風煙古上饒，屬邑寄山椒。',48,'全唐诗/poet.song.9000.json','["風煙古上饒，屬邑寄山椒。", "仇覽同棲棘，陶潛共折腰。", "安輿方就養，黄綬豈辭遙。", "善績青箱業，興廉有漢條。"]'),
('613229f9-b3dd-49c3-a5f1-7621f4c64728','過華夫書屋','晏殊','宋','宋诗','song-poetry','','[]','西齋輝赫亘山隅，嘉致清風世莫如。',160,'全唐诗/poet.song.9000.json','["西齋輝赫亘山隅，嘉致清風世莫如。", "鄉黨名流依絳帳，煙蘿幽境似仙居。", "趨庭子弟皆攀桂，彈鋏賓朋總食魚。", "汗簡傳經亞鄒魯，粉牌留詠盡嚴徐。", "杯盤互動先生饌，門巷應停長者車。", "墳籍豈惟精四部，絃歌常見習三餘。", "玳簪珠履延豪士，縹帙牙籤刊賜書。", "碧沼暮涼浮菡萏，紗窗秋靜漏蟾蜍。", "閑庭瀟灑移泉石，華表崢嶸冠里閭。", "我恨羈遊在芸閣，不陪諸彥曳長裾。"]'),
('96790f6f-b1dd-4f21-ae69-8d5d1fa6670c','紫竹花','晏殊','宋','宋诗','song-poetry','','[]','長夏幽居景不窮，花開芳砌翠成叢。',32,'全唐诗/poet.song.9000.json','["長夏幽居景不窮，花開芳砌翠成叢。", "窗南高臥追涼際，時有微香逗晚風。"]'),
('7e9beccc-adba-4737-85ef-e2f9e3f9d309','送瞿生還拜親','晏殊','宋','宋诗','song-poetry','','[]','門標楊氏闕，家有漢皇書。',72,'全唐诗/poet.song.9000.json','["門標楊氏闕，家有漢皇書。", "射策淹前志，鳴榔省舊居。", "仙山人罕到，幽境畫難如。", "雲竇開賓館，芝田足歲儲。", "修祠窮五際，爲學慕三餘。", "努力文明代，翹翹託乘車。"]'),
('b6b60174-9331-4d1b-952c-32aa28182072','白雲庵','晏殊','宋','宋诗','song-poetry','','[]','草庵何似清風樓，更在空中最上頭。',32,'全唐诗/poet.song.9000.json','["草庵何似清風樓，更在空中最上頭。", "眼界豁開無畛域，枯藤古木暮煙浮。"]'),
