('b9b9e0f6-fa7f-488e-9bbf-afc9828308b1','句  其八','宋綬','宋','宋诗','song-poetry','','[]','海國甌鄉浙水東，暫煩良守此憑熊。',16,'全唐诗/poet.song.9000.json','["海國甌鄉浙水東，暫煩良守此憑熊。"]'),
('f489ffed-90e4-4585-9328-7fce4caa1617','劍聯句','滕宗諒','宋','宋诗','song-poetry','','[]','聖人作神兵，以定天下厄。',288,'全唐诗/poet.song.9000.json','["聖人作神兵，以定天下厄。", "蚩尤發靈機，干將構雄績。", "槖籥天地開，鑪治陰陽闢。", "南帝輸火精，西皇降金液。", "炎炎崑岡熒，洶洶洪河擘。", "雷霆助意氣，日月淪精魄。", "神氣不在大，錯落就三尺。", "直淬靈溪泉，横磨太行石。", "雄雌威並立，晝夜光相射。", "提攜風雲生，指顧烟霞寂。", "堅剛正人心，耿介志士跡。", "初疑成夏鼎，魑魅世所適。", "又若引吳刀，犀象謂無隔。", "截波虬尾滑，脱浪鯨牙直。", "頑冰挂陰霤，皓月乘孤隙。", "河角起彗氣，雲罅露秋碧。", "曉鐔星斗爛，夜匣飛龍宅。", "舞酣霰雪回，彈俊球琳擊。", "鮮摇霅水光，膩刮湘山色。", "青蛟渴雨瘦，素虺蟠霜瘠。", "清音鏘以鳴，寒姿堅且澤。", "鬼類喪影響，佞黨摧肝腸。", "一旦會神武，四海屠兇逆。", "周王奉天討，商郊千里赤。"]'),
('70395610-f532-41d8-ace5-f6fd3af773a9','鶴聯句','滕宗諒','宋','宋诗','song-poetry','','[]','上霄降靈氣，鍾此千年禽。',288,'全唐诗/poet.song.9000.json','["上霄降靈氣，鍾此千年禽。", "幽閑靖節性，孤高伯夷心。", "頡頏紫霄垠，飄颻滄浪潯。", "岳湛有仙姿，鈞韶無俗音。", "毛滋月華淡，頂粹霞光深。", "目流泉客淚，翅垂羽人襟。", "騰漢雪千丈，點溪霜半尋。", "纖喙礪青鐵，修脛雕碧琳。", "巖棲干溪樹，澤飲卑蹄涔。", "鸞皇自塤箎，燕雀徒商參。", "獨翅聳瓊枝，羣舞傾瑤林。", "病餘霞雲叚，夢回松吹吟。", "靜嫌鸚鵡言，高笑鴛鴦淫。", "金精冷澄澈，玉格寒蕭森。", "潔白不我恃，腥羶非所任。", "稻粱不得已，蟣虱胡爲侵。", "天池憶鵬遊，雲羅傷鳯沈。", "風流超縞素，雅淡絕規箴。", "相親長道情，偶見銷煩襟。", "西漢惜馮唐，華皓欲投簪。", "南朝仰衛玠，清羸疑不禁。", "端如方直臣，處羣良足欽。", "介如廉退士，驚秋猶在陰。", "幾誚鷹隼鷙，覊韝俄見臨。"]'),
('4bf94bdd-ea3d-4e09-8f64-b029540c06fb','寄會稽范希文','滕宗諒','宋','宋诗','song-poetry','','[]','江山千里接仁封，都在東南秀氣中。',32,'全唐诗/poet.song.9000.json','["江山千里接仁封，都在東南秀氣中。", "借問玉皇香案吏，蓬萊何似水晶宮。"]'),
('a5416b5c-aab9-4ba1-8915-c8d30640e2dd','贈回道士','滕宗諒','宋','宋诗','song-poetry','','[]','華州回道士，來到岳陽城。',24,'全唐诗/poet.song.9000.json','["華州回道士，來到岳陽城。", "別我遊何處，秋空一劍橫。"]'),
('7f9e6c05-f7ba-42a4-ba5a-3b8e4059bcde','翠光亭','滕宗諒','宋','宋诗','song-poetry','','[]','千古江山好樹新，翠光亭上一傷春。',32,'全唐诗/poet.song.9000.json','["千古江山好樹新，翠光亭上一傷春。", "碧波無盡愁無盡，留與今人復後人。"]'),
('4c341b8a-ad2e-4e52-8cc6-817fc120a35b','石城寺','滕宗諒','宋','宋诗','song-poetry','','[]','山勢如城繞楚宮，幾人登賞我心同。',32,'全唐诗/poet.song.9000.json','["山勢如城繞楚宮，幾人登賞我心同。", "溪雲去作人間雨，澗水來生坐上風。"]'),
('935c94c2-4817-41fe-affe-c3cab8265a6c','遊茅山','滕宗諒','宋','宋诗','song-poetry','','[]','句曲山中古洞天，金堂玉室地相連。',32,'全唐诗/poet.song.9000.json','["句曲山中古洞天，金堂玉室地相連。", "方當蘧子知非日，已過茅君得道年。"]'),
('25b69f72-b6ef-485e-9189-395d7b649aa7','贈妓兜娘','滕宗諒','宋','宋诗','song-poetry','','[]','十載芳洲採白蘋，移舟弄水賞青春。',32,'全唐诗/poet.song.9000.json','["十載芳洲採白蘋，移舟弄水賞青春。", "當時自倚青春力，不信東風解誤人。"]'),
('28c7792b-3f4f-41dc-94d6-8b3fb94f3cbf','月','滕宗諒','宋','宋诗','song-poetry','','[]','黄金雙闕水晶宮，灧灧銀潢貫碧空。',32,'全唐诗/poet.song.9000.json','["黄金雙闕水晶宮，灧灧銀潢貫碧空。", "一曲霓裳羽衣舞，桂花如露濕天風。"]'),
('edbf3787-f37f-4f53-8eaa-30b7d1749fa0','白雲樓','滕宗諒','宋','宋诗','song-poetry','','[]','白雲樓危壓晴霓，樓下波光數毛髪。',128,'全唐诗/poet.song.9000.json','["白雲樓危壓晴霓，樓下波光數毛髪。", "雕甍刻桷出煙霞，萬瓦參差鵬翼截。", "蘭汀蕙浦入平蕪，天遠孤帆望中滅。", "屈平宋玉情不盡，千古依然在風月。", "漂零坐想十年舊，歲月飛馳爭列缺。", "青雲交友夢魂斷，白首漁樵誠契闊。", "安居環堵袁安老，泣抱荆珍卞和刖。", "折楊雖俚亦知名，猶欲樓中賡白雪。"]'),
