('e72d67a2-468b-4d6a-87b4-ca392f247e4a','山居書事','太上隱者','宋','宋诗','song-poetry','','[]','偶來松樹下，高枕石頭眠。',24,'全唐诗/poet.song.9000.json','["偶來松樹下，高枕石頭眠。", "山中無曆日，寒盡不知年。"]'),
('0b083bf8-4939-48cf-a64e-25e12eb7696c','臨蛻遺詩  其一','晏穎','宋','宋诗','song-poetry','','[]','兄也錯到底，猶誇將相才。',24,'全唐诗/poet.song.9000.json','["兄也錯到底，猶誇將相才。", "世緣何日了，了卻早歸來。"]'),
('cc24ecb2-e97c-4bae-a6b8-d12f9a586370','臨蛻遺詩  其二','晏穎','宋','宋诗','song-poetry','','[]','江外三千里，人間十八年。',24,'全唐诗/poet.song.9000.json','["江外三千里，人間十八年。", "此行誰復見，一鶴上遼天。"]'),
('16b3c4c8-a8dd-462c-bd71-365b0a0b490a','東池','孫錫','宋','宋诗','song-poetry','','[]','一片滄州景，寒光湛碧流。',48,'全唐诗/poet.song.9000.json','["一片滄州景，寒光湛碧流。", "有時雙鯉躍，盡日采鴛浮。", "綠荇千絲密，紅蕖萬朵稠。", "琴尊約佳客，乘月泛歸舟。"]'),
('a6cbe2d4-cf67-4867-b1a4-7a54a03ed0de','句','孫錫','宋','宋诗','song-poetry','','[]','句溪雖可鑒，未若宛溪清。',12,'全唐诗/poet.song.9000.json','["句溪雖可鑒，未若宛溪清。"]'),
('f6d10fa0-f303-4341-807f-b4e0be5d294e','嘲苗振','王逵','宋','宋诗','song-poetry','','[]','伯起雄豪世莫偕，官高祿重富於財。',64,'全唐诗/poet.song.9000.json','["伯起雄豪世莫偕，官高祿重富於財。", "田從汶上天生出，堂自明州地架來。", "十隻畫船風破浪，兩行紅粉夜傳杯。", "自憐憔悴東鄰叟，草舍茅簷真可咍。"]'),
('9f722d0d-e3c1-4ae7-b23d-10b8a3e35580','釣臺','王逵','宋','宋诗','song-poetry','','[]','一句能通萬世情，若非高位即嘉聲。',32,'全唐诗/poet.song.9000.json','["一句能通萬世情，若非高位即嘉聲。", "如何自古留題者，不悟嚴光解釣名。"]'),
('c470b119-8373-4a1f-b37e-8e152370ad55','萬山寺','王逵','宋','宋诗','song-poetry','','[]','衆狀皆窮險，茲形獨擅方。',48,'全唐诗/poet.song.9000.json','["衆狀皆窮險，茲形獨擅方。", "坦夷中砥礪，端正外青蒼。", "上帝圍棋局，炎君避暑牀。", "回嗟太行路，更近利名場。"]'),
('cb0626f4-c240-483a-9d14-156be57b3770','沖虛宮','王逵','宋','宋诗','song-poetry','','[]','修煉曾君些，傳聞固異常。',48,'全唐诗/poet.song.9000.json','["修煉曾君些，傳聞固異常。", "壇留皂筴樹，人去白雲鄉。", "龜得胎中息，神藏肘後方。", "遼東鶴未返，華表夜蒼蒼。"]'),
('2028a0a2-c42f-412a-99e7-676d6291ee81','上巳遊東禪詩','王逵','宋','宋诗','song-poetry','','[]','紫陌破清晨，雕鞍映畫輪。',48,'全唐诗/poet.song.9000.json','["紫陌破清晨，雕鞍映畫輪。", "因修洛陽禊，重憶永和春。", "錦繡荀香度，樓臺梵宇新。", "忙中得閑暇，來見解空人。"]'),
('f5fc8709-b6d9-4480-813a-4d1055c0f2c5','中元燕百丈小樓詩','王逵','宋','宋诗','song-poetry','','[]','薛老峰南更近西，小樓高閣與雲齊。',32,'全唐诗/poet.song.9000.json','["薛老峰南更近西，小樓高閣與雲齊。", "中山酒熟中元節，歸去從他醉似泥。"]'),
('e5ef9bf4-62cd-4e55-869b-980d79c223c0','鼇頂峰','王逵','宋','宋诗','song-poetry','','[]','眼看滄海近，身與白雲高。',24,'全唐诗/poet.song.9000.json','["眼看滄海近，身與白雲高。", "迴影連三島，盤根壓六鼇。"]'),
('6677a473-4667-44f3-843a-e687c731eed0','句','王逵','宋','宋诗','song-poetry','','[]','下臨廣陌三條闊，斜倚危樓百尺高。',16,'全唐诗/poet.song.9000.json','["下臨廣陌三條闊，斜倚危樓百尺高。"]'),
('807c2761-30c3-4477-a387-005f7e9475b6','題南山刻石詩','許給','宋','宋诗','song-poetry','','[]','聖主崇儒本，文宣教愈□。',168,'全唐诗/poet.song.9000.json','["聖主崇儒本，文宣教愈□。", "嚴祠加整葺，賢守□遵依。", "將欲更□□，先來相翠微。", "小山開亂石，幽谷駐涵暉。", "澤火爻符合，雷天象庶幾。", "□王儀凜凜，十哲貌頎頎。", "山溜侵廊滴，溪雲拂瓦飛。", "晞陽鷗鷺島，燈兔□魚磯。", "元氏魂應爽，□□道轉肥。", "靜思登彼岱，深想浴乎沂。", "風□巖根竹，泉滋石□□。", "□秋留□貌，□會集褒衣。", "忠恕□□學，□□□□□。", "文辭政如是，吾欲□□歸。"]'),
('4455bff8-465e-4539-8554-f7c9293fb133','遊靈巖','劉异','宋','宋诗','song-poetry','','[]','藥水標題不記年，奇花深洞舊通僊。',64,'全唐诗/poet.song.9000.json','["藥水標題不記年，奇花深洞舊通僊。", "山迴巨蔭常遮日，境絕纖埃別是天。", "碧照東西江浩渺，綠迷高下竹嬋娟。", "凭欄周覽翛然靜，金像香殘一炷煙。"]'),
('7fec91be-d302-4148-af14-308c4dbe8761','清溪','蕭貫','宋','宋诗','song-poetry','','[]','山開明月峽，水寫武陵溪。',24,'全唐诗/poet.song.9000.json','["山開明月峽，水寫武陵溪。", "地勝人堪隱，源深客自迷。"]'),
('fa748978-612b-4a08-a491-10b7c4b24690','齊山','蕭貫','宋','宋诗','song-poetry','','[]','秋風秋浦斷飛埃，路入齊山有梵臺。',32,'全唐诗/poet.song.9000.json','["秋風秋浦斷飛埃，路入齊山有梵臺。", "黄菊綻時君始至，紫微去後我重來。"]'),
('42bf289b-3245-4390-9e1c-675f04281c3f','句','蕭貫','宋','宋诗','song-poetry','','[]','十二峣關隱空綠，獸猊呼焰椒壁馥。',96,'全唐诗/poet.song.9000.json','["十二峣關隱空綠，獸猊呼焰椒壁馥。", "渴烏涓涓不相續，轆轤欲轉霏紅玉。", "百刻香殘隕蓮燭，九龍吐水漫寒漿。", "紅綃佩魚無左璫，兩兩趨走瞻扶桑。", "紅萍半圭山波面，回首觚稜九霞絢。", "鳴鞘聲從天上來，大劍高冠滿前殿。"]'),
('f20a6794-e9e9-4502-9546-e678b48ae0a0','偈','釋方會','宋','宋诗','song-poetry','','[]','踏著秤錘硬似鐵，痖子得夢向誰說。',32,'全唐诗/poet.song.9000.json','["踏著秤錘硬似鐵，痖子得夢向誰說。", "須彌頂上浪滔天，大洋海裏遭火爇。"]'),
('6b377ab4-dbb3-452f-b60e-6c5de0a59359','偈二首  其一','釋方會','宋','宋诗','song-poetry','','[]','楊歧一要，千聖同妙。',20,'全唐诗/poet.song.9000.json','["楊歧一要，千聖同妙。", "布施大衆，果然失照。"]'),
('c162d2ab-0219-46ab-9f72-0357fd569916','偈二首  其二','釋方會','宋','宋诗','song-poetry','','[]','楊歧一句，急著眼覷。',20,'全唐诗/poet.song.9000.json','["楊歧一句，急著眼覷。", "長連牀上，拈匙把筯。"]'),
('0b3112bd-f335-44b6-9649-b9b369042906','偈','釋方會','宋','宋诗','song-poetry','','[]','楊歧無旨的，種田博飯喫。',24,'全唐诗/poet.song.9000.json','["楊歧無旨的，種田博飯喫。", "說夢老瞿曇，何處覓蹤跡。"]'),
('c15d02c3-47e8-455f-a53d-b16addae9bd7','偈','釋方會','宋','宋诗','song-poetry','','[]','薄福住楊歧，年來氣力衰。',40,'全唐诗/poet.song.9000.json','["薄福住楊歧，年來氣力衰。", "寒風凋敗葉，猶喜故人歸。", "囉囉哩，拈上死柴頭，且向無煙火。"]'),
('df82902a-4560-4fb8-8bc0-9efd8a366ef8','偈','釋方會','宋','宋诗','song-poetry','','[]','楊歧乍住屋壁疏，滿牀盡布雪真珠。',32,'全唐诗/poet.song.9000.json','["楊歧乍住屋壁疏，滿牀盡布雪真珠。", "縮卻項，暗嗟吁，翻憶古人樹下居。"]'),
('7e5f6519-091e-4918-ab96-c84115ad81ab','偈','釋方會','宋','宋诗','song-poetry','','[]','雲蓋是事不如，說禪似吞栗蒲。',28,'全唐诗/poet.song.9000.json','["雲蓋是事不如，說禪似吞栗蒲。", "若向此處會得，佛法天地懸殊。"]'),
('53d01786-0c44-4ccb-8406-894581e688cc','偈','釋方會','宋','宋诗','song-poetry','','[]','釋迦老子著跌，偷笑雲蓋亂說。',28,'全唐诗/poet.song.9000.json','["釋迦老子著跌，偷笑雲蓋亂說。", "雖然世界坦平，也是將勤補拙。"]'),
('3c3029fb-24d9-4328-9698-d23ea0e34692','偈','釋方會','宋','宋诗','song-poetry','','[]','雪，雪，處處光輝明皎潔。',48,'全唐诗/poet.song.9000.json','["雪，雪，處處光輝明皎潔。", "黄河凍鎖絕纖流，赫日光中須迸裂。", "須迸裂，那吒頂上喫蒺藜，金剛脚下流出血。"]'),
('46416252-b7d4-4364-95b2-0a7d50d7e0f5','句  其一','釋方會','宋','宋诗','song-poetry','','[]','漁翁未擲釣，躍鱗衝浪來。',12,'全唐诗/poet.song.9000.json','["漁翁未擲釣，躍鱗衝浪來。"]'),
