('9e68aabc-6b84-4e21-8b97-14444989dead','送餘姚知縣陳最寺丞','鄭戩','宋','宋诗','song-poetry','','[]','美渥卿爲佐，清談縣得才。',48,'全唐诗/poet.song.9000.json','["美渥卿爲佐，清談縣得才。", "人從日邊別，舟渡鑑中來。", "食案資鮭稟，公田剩酒材。", "秋餘一憑檻，江海遍樓臺。"]'),
('891c74d6-c04d-4ced-b37b-8fe1d3ab206a','句','鄭戩','宋','宋诗','song-poetry','','[]','春到不擇地，石傍花自開。',12,'全唐诗/poet.song.9000.json','["春到不擇地，石傍花自開。"]'),
('b8bf03ad-d539-44c2-b407-b160ec2a689a','瀑布泉','陳肅','宋','宋诗','song-poetry','','[]','山高激迅湍，清振林下響。',36,'全唐诗/poet.song.9000.json','["山高激迅湍，清振林下響。", "飛雪濺千巖，白虹垂萬丈。", "來此坐移時，森然毛髪爽。"]'),
('703fd976-fda7-4cfe-b868-8fa39ec34e8e','桃源洞','陳肅','宋','宋诗','song-poetry','','[]','輕煙綠滿溪，夭桃紅夾岸。',36,'全唐诗/poet.song.9000.json','["輕煙綠滿溪，夭桃紅夾岸。", "春風吹百花，香逐春風散。", "花落與花開，年光不知換。"]'),
('7c6d4146-9e5d-4807-b1da-ec32035b8970','半山亭','陳肅','宋','宋诗','song-poetry','','[]','躡屐上高山，亭在半山側。',36,'全唐诗/poet.song.9000.json','["躡屐上高山，亭在半山側。", "猿鳥戲層臺，煙霞含秀色。", "復知名利心，到此堪俱息。"]'),
('e5053fc7-a0e2-4c82-9216-2054f86ab925','投龍潭','陳肅','宋','宋诗','song-poetry','','[]','流瀑落深潭，疊響如驚雷。',36,'全唐诗/poet.song.9000.json','["流瀑落深潭，疊響如驚雷。", "跳波夾亂石，突兀寒如堆。", "潭上片雲起，千山風雨來。"]'),
('f2fc9948-47ff-4cdb-8f7c-577776781016','七星杉','陳肅','宋','宋诗','song-poetry','','[]','峭石七星杉，凌雲勢森聳。',36,'全唐诗/poet.song.9000.json','["峭石七星杉，凌雲勢森聳。", "月照林影寒，風起龍勢動。", "高低松檜枝，環如衆星拱。"]'),
('94a86bdf-90d5-4900-81cf-73e4aeb8691b','蔡經宅','陳肅','宋','宋诗','song-poetry','','[]','巖扉生翠靄，石壁凌朱霞。',36,'全唐诗/poet.song.9000.json','["巖扉生翠靄，石壁凌朱霞。", "草木狀多怪，鸞鶴歸如家。", "誰嫌狡獪心，滿地投丹砂。"]'),
('90a0af51-d78c-4217-ac0b-b8b74c4eb1eb','碧蓮池','陳肅','宋','宋诗','song-poetry','','[]','愛此東南池，澄湛通泉脈。',36,'全唐诗/poet.song.9000.json','["愛此東南池，澄湛通泉脈。", "昔日碧蓮根，香英今變白。", "顔色本神仙，霞衣無定格。"]'),
('02cfe2e1-35c9-4bda-bf09-fa358ef96cd8','流水池','陳肅','宋','宋诗','song-poetry','','[]','積水環巨石，石面如砥平。',36,'全唐诗/poet.song.9000.json','["積水環巨石，石面如砥平。", "當知達者心，來此浮杯觥。", "酒中有賢聖，常願娛閑情。"]'),
('a4505f1d-5f3f-4e6c-be2d-06ce0db228da','蠟燭','孫復','宋','宋诗','song-poetry','','[]','六龍西走入崦嵫，寂寂華堂漏轉時。',32,'全唐诗/poet.song.9000.json','["六龍西走入崦嵫，寂寂華堂漏轉時。", "一寸丹心如見用，便爲灰燼亦無辭。"]'),
('5419ec68-f38b-4b04-91ff-2924637757fa','八月十四夜','孫復','宋','宋诗','song-poetry','','[]','銀漢無聲露暗垂，玉蟾初上欲圓時。',32,'全唐诗/poet.song.9000.json','["銀漢無聲露暗垂，玉蟾初上欲圓時。", "清樽素瑟宜先賞，明夜陰晴不可知。"]'),
('768c7e42-baf8-40b2-bd23-31544c143680','論學','孫復','宋','宋诗','song-poetry','','[]','冥觀天地何云爲，茫茫萬物爭蕃滋。',176,'全唐诗/poet.song.9000.json','["冥觀天地何云爲，茫茫萬物爭蕃滋。", "羽毛鱗介各異趣，披攘攫搏紛相隨。", "人亦其間一物爾，餓食渴飲無休時。", "苟非道義充其腹，何異鳥獸安鬚眉。", "人生在學勤始至，不勤求至無由期。", "孟軻荀卿揚雄氏，當時未必皆生知。", "因其鑽仰久不已，遂入聖域爭先馳。", "既學便當窮遠大，勿事聲病淫哇辭。", "斯文下衰吁已久，勉思駕說扶顛危。", "擊喑敺聾明大道，身與姬孔爲藩籬。", "是非豐顇若不學，慎無空使精神疲。"]'),
('8f1f056d-40ff-4b91-81a5-fe55bed0d4ec','中秋夜不見月','孫復','宋','宋诗','song-poetry','','[]','長記去年中秋玩月出草堂，冰輪直可鑑毫芒。',154,'全唐诗/poet.song.9000.json','["長記去年中秋玩月出草堂，冰輪直可鑑毫芒。", "是時家釀又新熟，呼童開席羅清觴。", "纖埃不起零露下，對此陶陶樂未央。", "自顧時逢堯舜世，上下清明無穢荒。", "吁嗟今夕何不幸，正逢屏翳恣猖狂。", "浮雲左右爭擁蔽，愛而不見涕沾裳。", "嫦娥無語縮頭何處坐，胡不開口走訴上帝旁。", "立召飛廉舉其職，驅除擁蔽揚清光。", "瑩然高照遙天外，免教萬國如瞽空倀倀。"]'),
('186242fc-3e42-4a18-b5ba-59db87711fa8','中秋歌','孫復','宋','宋诗','song-poetry','','[]','明月一歲中，影圓十二回。',168,'全唐诗/poet.song.9000.json','["明月一歲中，影圓十二回。", "如何今夕裏，爭賞羅樽罍。", "既愛盈盈色，更上高高臺。", "人心莫如此，試爲君言哉。", "月者水之精，秋者金之氣。", "金水性相生，五行分其事。", "則知天地間，相感各以類。", "水得金還盛，月因秋更清。", "氣類使之然，人誰不有情。", "可憐別夜色，一一皆銷聲。", "自昔詩家流，吟皆不到此。", "徒能狀光彩，豈解原終始。", "冥搜詎有得，燥吻真何以。", "請看退翁歌，其的能中矣。"]'),
('ad354a3b-26fd-4e90-aaab-fb5ba224f2ce','中秋月  其一','孫復','宋','宋诗','song-poetry','','[]','度度思真賞，幽期邈始還。',48,'全唐诗/poet.song.9000.json','["度度思真賞，幽期邈始還。", "金行分此夜，桂子落何山。", "座席清風裏，人家灝氣間。", "飲懷與吟興，徹曙兩非閑。"]'),
('293685b0-3eda-439c-8b19-5fdb90681c2e','中秋月  其二','孫復','宋','宋诗','song-poetry','','[]','十二度圓皆好看，就中圓極在中秋。',32,'全唐诗/poet.song.9000.json','["十二度圓皆好看，就中圓極在中秋。", "前峰獨上還吟翫，高興多於庾亮樓。"]'),
('262f7e56-8961-46d3-8ad9-4a276713ce43','又賦十五夜月','孫復','宋','宋诗','song-poetry','','[]','清賞年年恐失期，人人不覺望中衰。',32,'全唐诗/poet.song.9000.json','["清賞年年恐失期，人人不覺望中衰。", "素娥須信多靈藥，長見嬋娟似舊時。"]'),
('b5b95938-90f5-4949-93fc-61de464cdf13','題相思鋪壁','令狐挺','宋','宋诗','song-poetry','','[]','誰把相思號此河，塞垣車往來多。',31,'全唐诗/poet.song.9000.json','["誰把相思號此河，塞垣車往來多。", "只應自古征人淚，灑向空川作浪波。"]'),
('8b266f2e-9bed-4c8e-8fad-ab849d0bcda2','寄嘉興守令狐挺','張瑴','宋','宋诗','song-poetry','','[]','羨君席上碧雲句，吟盡江南煙雨村。',64,'全唐诗/poet.song.9000.json','["羨君席上碧雲句，吟盡江南煙雨村。", "豈惜笙歌連夜醉，且看風物逐春新。", "花開花落何時盡，閑是閑非愁殺人。", "何似陽臺雲畔曲，細聲拂拂下梁塵。"]'),
('2ecb4646-cc0b-49d4-9474-e346693e9b41','句  其一','葛宮','宋','宋诗','song-poetry','','[]','翩翻燕子朱門靜，狼藉梨花小院閑。',16,'全唐诗/poet.song.9000.json','["翩翻燕子朱門靜，狼藉梨花小院閑。"]'),
('277e1ddc-f6ef-45c7-a699-8c68fff4abb5','句  其二','葛宮','宋','宋诗','song-poetry','','[]','西樓月上簾簾靜，後苑花開院院香。',16,'全唐诗/poet.song.9000.json','["西樓月上簾簾靜，後苑花開院院香。"]'),
('13ef1ed5-eacf-45d3-9fc4-f9e36b0e3dc6','偈','釋省回','宋','宋诗','song-poetry','','[]','南番人泛船，塞北人搖艫。',24,'全唐诗/poet.song.9000.json','["南番人泛船，塞北人搖艫。", "波斯入大唐，須彌山作舞。"]'),
('ee49654a-c192-4797-9a27-2ddad739f5b1','辭衆偈','釋省回','宋','宋诗','song-poetry','','[]','九十二光陰，分明對衆說。',24,'全唐诗/poet.song.9000.json','["九十二光陰，分明對衆說。", "遠洞散寒雲，幽窗度殘月。"]'),
('277077cf-ed20-412d-b219-f8f212762f06','送張無夢歸天台','王從益','宋','宋诗','song-poetry','','[]','風馭去難留，將期汗漫遊。',72,'全唐诗/poet.song.9000.json','["風馭去難留，將期汗漫遊。", "入辭丹陛曉，重臥赤城秋。", "枕畔紅霞合，門前瀑布流。", "龍車款太帝，鶴信寄浮丘。", "醉引青鸞曲，閑披白鹿裘。", "夜來胡蝶夢，先已到瀛洲。"]'),
('7316796c-51ca-4c47-ba5a-5af23a5e6ce5','和梅公儀留題重光寺羅漢院贈憲上人','王益','宋','宋诗','song-poetry','','[]','曉剃吟髭雪半零，海窗曾咒鉢龍醒。',64,'全唐诗/poet.song.9000.json','["曉剃吟髭雪半零，海窗曾咒鉢龍醒。", "蚤知西竺能持法，應笑南僧不會經。", "雲氣晝閑侵麈柄，蘚痕春老上銅瓶。", "近來禪觀都無語，手指餘花滿寺庭。"]'),
('8f6edc5e-6f07-4d8f-b958-d2e5eca4ab26','和梅公儀新繁縣顯曜院','王益','宋','宋诗','song-poetry','','[]','梵宇蕭條白日長，苦空譚麈接藤牀。',64,'全唐诗/poet.song.9000.json','["梵宇蕭條白日長，苦空譚麈接藤牀。", "雲章酷愛休詩麗，蓮柄慵思遠社香。", "石髪雨梳雞苑寂，風梭春織鷲山涼。", "劫灰心火銷平盡，又聽鐘聲下講堂。"]'),
('52667eeb-88c3-4ffd-9b1c-6abb26355be0','留題清涼院','王益','宋','宋诗','song-poetry','','[]','背倚青峰面枕溪，濡毫新向壁間題。',64,'全唐诗/poet.song.9000.json','["背倚青峰面枕溪，濡毫新向壁間題。", "善根不撓金蓮合，凈界無塵水月齊。", "會啟苾蒭真樂境，花開簷蔔遠香畦。", "因思祖塔嘗遊處，更在龍蟠虎踞西。"]'),
('52401c30-427c-4635-ab83-8ec1d39f964b','靈谷','王益','宋','宋诗','song-poetry','','[]','靈谷神仙宅，言歸肆目新。',48,'全唐诗/poet.song.9000.json','["靈谷神仙宅，言歸肆目新。", "山光遠如畫，秋色老於人。", "世俗棋爭劫，人心海變塵。", "功成思范蠡，湖上一閑身。"]'),
('99771648-d936-448c-8c51-92400cdb754a','新繁縣東湖瑞蓮歌','王益','宋','宋诗','song-poetry','','[]','火雲爍盡天幕腥，水光弄碧涼無聲。',256,'全唐诗/poet.song.9000.json','["火雲爍盡天幕腥，水光弄碧涼無聲。", "荷華千柄拂煙際，傑然秀幹駢雙英。", "天敕少昊偏滋榮，宵零仙露饒金莖。", "嫋嫋飄風起天末，綠華璫珮來琤琤。", "觥觴式宴資擊賞，何人掞藻飛筆精。", "越國亭亭八百里，木蘭泛詠稱明媚。", "爭如錦水派繁江，孤根擢翠葩分膩。", "紫清合曜流霞暉，楚臺無夢朝雲飛。", "韓虢佳人新侍寵，溫泉宮裏賜霞衣。", "赫赫曦陽在東井，珍房萃作皇家慶。", "流火初晨復毓靈，連璧更疑唐傑盛。", "眇觀熙政接元和，嘉穀重榮田野歌。", "高宗昔慶劉仁表，五色卿雲世甚少。", "我今取喻進德流，優哉祥蓮出池沼。", "草萊泥滓俱棄捐，致君事業殊商皓。", "歸作臯夔稷卨臣，同心一德翊華勳。"]'),
('06f4412e-7da9-4615-ac17-b65cedf19715','睢陽五老圖','胡瑗','宋','宋诗','song-poetry','','[]','始同優烈晚同閑，五福俱全戴角冠。',64,'全唐诗/poet.song.9000.json','["始同優烈晚同閑，五福俱全戴角冠。", "典午山河遵大道，調元宗社對穹桓。", "羌夷誰敢窺中夏，朝士猜疑畏歲寒。", "肱股賡歌遺韻在，惟吾後進祇膺看。"]'),
('c80d31c2-23a0-4b42-a5b1-132368d9f097','石壁','胡瑗','宋','宋诗','song-poetry','','[]','李白好溪山，浩蕩旌川遊。',168,'全唐诗/poet.song.9000.json','["李白好溪山，浩蕩旌川遊。", "題詩汪氏壁，聲動桃花洲。", "英辭逸無繼，爾來三百秋。", "汪公亦蕃衍，宗支冠南州。", "其間新建居，林泉最清幽。", "竹聲滿道院，山光入書樓。", "仙氣既飄飄，儒風亦悠悠。", "子孫多俊異，詞行咸精修。", "我來至石壁，賞之不能休。", "酣味碧溪水，苦飲黄金甌。", "因羨汪君居，復思汪君投。", "遇景清興發，浩與天雲浮。", "斐章異繡段，灑翰非銀鈎。", "庶與謫仙詩，千古同風流。"]'),
('63aa40b2-04b9-4f16-bad9-4b0133ea6787','投機偈','釋義懷','宋','宋诗','song-poetry','','[]','一二三四五六七，萬仞峰頭獨足立。',32,'全唐诗/poet.song.9000.json','["一二三四五六七，萬仞峰頭獨足立。", "驪龍頷下奪明珠，一言勘破維摩詰。"]'),
('deb21d93-c2cb-4c30-9da9-a371eca9d2a2','偈','釋義懷','宋','宋诗','song-poetry','','[]','須彌頂上，不扣金鐘。',54,'全唐诗/poet.song.9000.json','["須彌頂上，不扣金鐘。", "畢鉢巖中，無人聚會。", "山僧倒騎佛殿，諸人反著草鞋。", "朝遊檀特，暮到羅浮。", "拄杖針筒，自家收取。"]'),
('f66a2094-a46c-4153-8319-c27290a9c94f','偈','釋義懷','宋','宋诗','song-poetry','','[]','蜀魄連宵叫，鵽鳭終夜啼。',24,'全唐诗/poet.song.9000.json','["蜀魄連宵叫，鵽鳭終夜啼。", "圓通門大啟，何事隔雲泥。"]'),
('88adbe87-6779-4e44-8b1d-51dce0ffad0a','偈','釋義懷','宋','宋诗','song-poetry','','["\u534e\u5c71"]','紅日照扶桑，寒雪封華嶽。',24,'全唐诗/poet.song.9000.json','["紅日照扶桑，寒雪封華嶽。", "三更過鐵圍，拶折驪龍角。"]'),
('8621e522-bc66-44db-a58c-dd772854ec71','書屏句','釋義懷','宋','宋诗','song-poetry','','[]','三分光陰二早過，靈臺一點不揩磨。',32,'全唐诗/poet.song.9000.json','["三分光陰二早過，靈臺一點不揩磨。", "區區逐日貪生去，喚不回頭怎奈何。"]'),
('7ac30b52-034f-4701-92a6-50af8944f6ed','句','釋義懷','宋','宋诗','song-poetry','','[]','衣穿瘦骨露，屋破看星眠。',12,'全唐诗/poet.song.9000.json','["衣穿瘦骨露，屋破看星眠。"]'),
('d83a4cdd-7953-4667-9549-fd6c4e8adacf','寄沖退處士章詧','釋真一子','宋','宋诗','song-poetry','','[]','未遂山中吟，時聞世上音。',48,'全唐诗/poet.song.9000.json','["未遂山中吟，時聞世上音。", "笑言失真詮，塵穢濁神襟。", "歸植南園芝，馳他北溟金。", "千日勤耕耘，自然生瑤琳。"]'),
('ab7cc653-da2a-4b2f-ac13-ff70fc64ba7f','頌','釋德遵','宋','宋诗','song-poetry','','[]','索火之機實快哉，藏鋒妙用少人猜。',32,'全唐诗/poet.song.9000.json','["索火之機實快哉，藏鋒妙用少人猜。", "要會我師親的旨，紅爐火盡不添柴。"]'),
('2e2a64bd-607d-44c8-a446-c110336370d5','偈','諸葛賡','宋','宋诗','song-poetry','','[]','上天下地極高深，幻化無蹤何處尋。',32,'全唐诗/poet.song.9000.json','["上天下地極高深，幻化無蹤何處尋。", "山靜白雲歸洞口，水清明月落波心。"]'),
('9f0f4003-965d-4ce3-beda-187c8951c247','乞休得旨謝恩','諸葛賡','宋','宋诗','song-poetry','','[]','三疏陳情始放歸，蕭蕭白髪解朝衣。',64,'全唐诗/poet.song.9000.json','["三疏陳情始放歸，蕭蕭白髪解朝衣。", "未營別業王官谷，先駕扁舟嚴子磯。", "視草龍螭猶眷戀，還家鷗鷺自光輝。", "老臣恩遇知何極，夢到天門覲紫薇。"]'),
('7469e51a-7c7f-4eed-89df-0cbed585e94d','歸休亭  其一','諸葛賡','宋','宋诗','song-poetry','','[]','小築危亭聚石淙，清溪環繞不通江。',64,'全唐诗/poet.song.9000.json','["小築危亭聚石淙，清溪環繞不通江。", "栽成傲骨梅千樹，呼出棲雲鶴一雙。", "垂釣艇乘新漲水，攤書光借夕陽窗。", "勳名事事皆堪避，只有詩情未肯降。"]'),
('49b15e6e-1e40-4107-ba7f-c838e410b3a0','歸休亭  其二','諸葛賡','宋','宋诗','song-poetry','','[]','日影初升竹半篙，一天晴色讀離騷。',64,'全唐诗/poet.song.9000.json','["日影初升竹半篙，一天晴色讀離騷。", "憑欄對客浮樽斝，隔水聽人正桔槔。", "拂去梁塵餞乳燕，掃歸松栗煮秋濤。", "柴門正對青青柳，浪說新詩欲擬陶。"]'),
('ea08cb8e-632f-4467-95d6-643a5ce28ad7','歸休亭  其三','諸葛賡','宋','宋诗','song-poetry','','[]','水國微茫境不凡，籜冠蘿带芰荷衫。',64,'全唐诗/poet.song.9000.json','["水國微茫境不凡，籜冠蘿带芰荷衫。", "雲歸洞口鹿常臥，葉落巢門鳥自啣。", "採藥道人過峭壁，汲泉童子下層巖。", "名山書卷封題處，多少煙霞護玉函。"]'),
('96f9ae8c-85d4-474a-af75-af9227fd8968','秋日得王介甫書','諸葛賡','宋','宋诗','song-poetry','','[]','數畝池塘一小亭，從容書札戶常扃。',64,'全唐诗/poet.song.9000.json','["數畝池塘一小亭，從容書札戶常扃。", "閑開松菊花三徑，時貯葠苓酒一瓶。", "望去春痕青到水，飛來鳬羽白連汀。", "是誰日落吹長嘯，猶有行人不忍聽。"]'),
('e8d0c70f-e406-4235-bcc3-7d2e09aacca3','句  其一','成銳','宋','宋诗','song-poetry','','[]','綵檻應無分，春風不借恩。',12,'全唐诗/poet.song.9000.json','["綵檻應無分，春風不借恩。"]'),
('abed903b-6c81-408d-a083-fa95bc0f3c7a','句  其二','成銳','宋','宋诗','song-poetry','','[]','馨香雖有艷，栽植未逢人。',12,'全唐诗/poet.song.9000.json','["馨香雖有艷，栽植未逢人。"]'),
('41fcead2-0aaf-4c8e-99b8-a2ddb4e50651','句  其三','成銳','宋','宋诗','song-poetry','','[]','憑高看漸遠，更上最高樓。',12,'全唐诗/poet.song.9000.json','["憑高看漸遠，更上最高樓。"]'),
('cb255cc8-9eab-4ac9-a698-a9d9c2001c00','詩一首','王軫','宋','宋诗','song-poetry','','[]','南篇司馬青衫濕，北句郎官白髪生。',32,'全唐诗/poet.song.9000.json','["南篇司馬青衫濕，北句郎官白髪生。", "堪與江黄永傳唱，離騷經外此歌聲。"]'),
('7fbe2476-5661-4674-adc6-141c00735ced','越中懷古','魏庭堅','宋','宋诗','song-poetry','','[]','句無亭下駐驂騑，鑑水寒光照客衣。',64,'全唐诗/poet.song.9000.json','["句無亭下駐驂騑，鑑水寒光照客衣。", "張翠鄂君舟上去，浣紗西子網中歸。", "禹祠草樹空春色，秦望風煙半夕暉。", "王謝勝遊何處問，茂林修竹尚依依。"]'),
('2a8a46e6-851a-43f0-a771-045d622e8e63','詩一首','路坦','宋','宋诗','song-poetry','','[]','百里傳呼號錄公，三年得替普天同。',32,'全唐诗/poet.song.9000.json','["百里傳呼號錄公，三年得替普天同。", "惟君四載過常例，更有何人繼後風。"]'),
('b9240c79-f630-4f87-9c44-9eefe5671f65','題真空閣','李熙輔','宋','宋诗','song-poetry','','[]','括蒼山上雲，山好雲亦好。',24,'全唐诗/poet.song.9000.json','["括蒼山上雲，山好雲亦好。", "可憐山下僧，看雲不知老。"]'),
('042547c0-61fc-405b-b646-8bf3d2732ad3','梅仙山丹井','曹文姬','宋','宋诗','song-poetry','','[]','鶴馭雲駢去不還，亂雲深處舊仙壇。',32,'全唐诗/poet.song.9000.json','["鶴馭雲駢去不還，亂雲深處舊仙壇。", "鑿開天外長生地，鍊出人間不死丹。"]'),
('197a4e40-d22d-43a2-9e2e-f8c119da24ff','送春','曹文姬','宋','宋诗','song-poetry','','[]','仙家無夏亦無秋，紅日清風滿翠樓。',32,'全唐诗/poet.song.9000.json','["仙家無夏亦無秋，紅日清風滿翠樓。", "況有碧霄歸路穩，可能同駕五雲遊。"]'),
('d0754961-fbca-48a4-b1a7-dedf5636c506','詩一首','任生','宋','宋诗','song-poetry','','[]','玉皇殿前掌書仙，一染塵心謫九天。',32,'全唐诗/poet.song.9000.json','["玉皇殿前掌書仙，一染塵心謫九天。", "莫怪濃香薰骨膩，霞衣曾惹御爐煙。"]'),
('11d416b6-1e65-448f-926a-e95247b8e9e2','瀑布','石延年','宋','宋诗','song-poetry','','[]','飛勢挂嶽頂，無時向此傾。',48,'全唐诗/poet.song.9000.json','["飛勢挂嶽頂，無時向此傾。", "玉虹垂地色，銀漢落天聲。", "萬丈寒雲濕，千巖暑氣清。", "滄浪何足羡，就此濯塵纓。"]'),
('e07aeeb9-6a82-4747-b4cc-9f84b15c2141','咏春','石延年','宋','宋诗','song-poetry','','[]','一氣回元運，恩含萬物深。',48,'全唐诗/poet.song.9000.json','["一氣回元運，恩含萬物深。", "陰陽造端數，天地發生心。", "有信來還逝，無私古到今。", "和風激遺暢，南轉入薫琴。"]'),
('2c0c5b21-a3cc-491e-bd1e-0927c0311b27','曹太尉西征','石延年','宋','宋诗','song-poetry','','[]','仁者雖無敵，王師尚有征。',120,'全唐诗/poet.song.9000.json','["仁者雖無敵，王師尚有征。", "獨乘金廏馬，都領鐡林兵。", "肅氣關河暮，屯煙部落晴。", "旗光秋燒合，甲色夜江横。", "士喜擊中鼓，虜疑聞後鉦。", "無私乃時雨，不殺是天聲。", "濯濯前誰拒，堂堂彼自傾。", "寒踰博望塞，春宴隗囂城。", "外使戎心伏，旁資帝道平。", "公還如畫像，爲贊學班生。"]'),
('21d630cd-4f18-413a-afbe-078210a71deb','贈劉潛歸陶丘','石延年','宋','宋诗','song-poetry','','[]','丈夫未大用，身與仁義閑。',72,'全唐诗/poet.song.9000.json','["丈夫未大用，身與仁義閑。", "可宜更聚散，風塵摧厥顔。", "君今歸柯澤，路出梁宋間。", "芒碭有吾廬，親老待我還。", "羡子先諧願，思親頭鬢斑。", "韶光苦不再，溝水長潺湲。"]'),
('a7477e0c-2d7a-41f9-955e-caf6d4542cfc','又','石延年','宋','宋诗','song-poetry','','[]','春老有時回，人老不再少。',52,'全唐诗/poet.song.9000.json','["春老有時回，人老不再少。", "草白有時榮，髮白不再好。", "人生不如春，髮生不如草。", "可堪送别春草前，青春未老人先老。"]'),
('4c6b7885-8972-4cdd-a4f1-666f90d32b73','金鄉張氏園亭','石延年','宋','宋诗','song-poetry','','[]','亭館連城敵謝家，四時園色鬬眀霞。',64,'全唐诗/poet.song.9000.json','["亭館連城敵謝家，四時園色鬬眀霞。", "窗迎西渭封侯竹，地接東陵隱士瓜。", "樂意相關禽對語，生香不斷樹交花。", "縱遊會約無留事，醉待参横月落斜。"]'),
('a572eac9-371c-4eb8-8537-bd81406d570b','秋夕北樓','石延年','宋','宋诗','song-poetry','','[]','秋霽露華清带水，月眀天色白連河。',32,'全唐诗/poet.song.9000.json','["秋霽露華清带水，月眀天色白連河。", "夜闌澄影星微動，瑟瑟層颸上下波。"]'),
('1725bd80-38f3-4da5-bc60-4e6b09617945','小桃','石延年','宋','宋诗','song-poetry','','[]','生色深紅綬带長，宮簾閑在井闌香。',32,'全唐诗/poet.song.9000.json','["生色深紅綬带長，宮簾閑在井闌香。", "母家昇上瑤池品，先得春風半面妝。"]'),
('e69d1192-27f8-43a6-8033-d75e95b8c32d','咏小桃','石延年','宋','宋诗','song-poetry','','[]','本分桃花寒食前，小桃長是上春天。',32,'全唐诗/poet.song.9000.json','["本分桃花寒食前，小桃長是上春天。", "二喬二趙俱傾國，女弟嬌强意自先。"]'),
('5798cea7-0b92-4720-b45f-da6f832f1ca8','送人遊杭','石延年','宋','宋诗','song-poetry','','[]','激激霜風吹墨貂，男兒醉别氣飄飄。',64,'全唐诗/poet.song.9000.json','["激激霜風吹墨貂，男兒醉别氣飄飄。", "五湖載酒期吳客，六代成詩倍楚橋。", "水荇漸青含晚意，江雲初白向春嬌。", "前秋亦擬錢塘去，共看龍山八月潮。"]'),
('2abe9a03-4722-4256-a760-ad1b48fc21b4','春日樓上','石延年','宋','宋诗','song-poetry','','[]','水樹春煙重，庭花午影圓。',24,'全唐诗/poet.song.9000.json','["水樹春煙重，庭花午影圓。", "人邊無限地，鳥外有餘天。"]'),
('d5a26ff4-85dc-4edb-b0ea-8dd2a9bdc984','春陰','石延年','宋','宋诗','song-poetry','','[]','寒食少天色，春風多柳花。',24,'全唐诗/poet.song.9000.json','["寒食少天色，春風多柳花。", "倚樓心目亂，不覺見棲鴉。"]'),
('78cd89a2-16ef-4c84-a963-977cef7c1d1d','榴花','石延年','宋','宋诗','song-poetry','','[]','王母庭前親見栽，張騫偷得下天來。',32,'全唐诗/poet.song.9000.json','["王母庭前親見栽，張騫偷得下天來。", "誰家巧婦殘針線，一撮生紅熨不開。"]'),
('8a75166b-6d36-4134-a36f-938b3742dbba','偶成','石延年','宋','宋诗','song-poetry','','[]','力振前文覺道孤，恥同流輩論榮枯。',64,'全唐诗/poet.song.9000.json','["力振前文覺道孤，恥同流輩論榮枯。", "動非仁義何如静，得見機關不似無。", "孔孟也應輕管晏，臯夔未必失唐虞。", "侯王重問吾何有，且自低心混世儒。"]'),
('1f14a3f0-eec1-4bef-a512-3fe473697cca','首陽','石延年','宋','宋诗','song-poetry','','[]','遜國同來訪聖謨，適觀争國誓師徒。',64,'全唐诗/poet.song.9000.json','["遜國同來訪聖謨，適觀争國誓師徒。", "恥生湯武干戈日，寜死唐虞揖讓區。", "大義充身安是餓，清魂有所未應無。", "始終天地亡前後，名骨雖雙此行孤。"]'),
('b0c5cd04-fe1b-45b2-857a-b0ee5cf15b38','寄尹師魯','石延年','宋','宋诗','song-poetry','','[]','十年一夢花空委，依舊河山損桃李。',64,'全唐诗/poet.song.9000.json','["十年一夢花空委，依舊河山損桃李。", "鴈聲北去燕南飛，高樓日日春風裏。", "眉黛石州山對起，嬌波淚落妝如洗。", "汾河不斷天南流，天色無情淡如水。"]'),
('ba681abd-871b-4124-9eaf-161a15f5056e','題趙平叔豹隱堂','石延年','宋','宋诗','song-poetry','','[]','熊非清渭逢何暮，龍卧南陽去不還。',32,'全唐诗/poet.song.9000.json','["熊非清渭逢何暮，龍卧南陽去不還。", "年少官游今郡守，蔚然惟在立談間。"]'),
('afbca6d0-1d07-419f-ab7e-39fda1ebef6f','登第後被黜戲作','石延年','宋','宋诗','song-poetry','','[]','無才且作三班借，請俸争如錄事參。',32,'全唐诗/poet.song.9000.json','["無才且作三班借，請俸争如錄事參。", "從此免稱鄉貢進，且須走馬東西南。"]'),
('c82ec19a-7609-4b65-83e4-2739904a74bb','過內官孫可久别業賦贈','石延年','宋','宋诗','song-poetry','','[]','南北占河潤，幽深在禁城。',48,'全唐诗/poet.song.9000.json','["南北占河潤，幽深在禁城。", "疊山知遠意，辭俸買閑名。", "閉戶斷蛛網，折花移鳥聲。", "誰人識高趣，朝野石渠生。"]'),
('8d5ad345-83df-45a7-821f-ad08128fdce4','古松','石延年','宋','宋诗','song-poetry','','[]','直氣森森恥屈盤，鐵衣生澀紫鱗乾。',64,'全唐诗/poet.song.9000.json','["直氣森森恥屈盤，鐵衣生澀紫鱗乾。", "影搖千尺龍蛇動，聲撼半天風雨寒。", "蒼蘚静緣離石上，綠蘿高附入雲端。", "報言帝座掄才者，便作明堂一柱看。"]'),
('cae0be48-341c-4c01-bba5-75f7fafdb406','籌筆驛','石延年','宋','宋诗','song-poetry','','[]','漢室虧皇象，乾坤未即寜。',216,'全唐诗/poet.song.9000.json','["漢室虧皇象，乾坤未即寜。", "奸臣與逆子，搖嶽復翻溟。", "權表分江域，曹袁鬬夏垌。", "虎奔咸逐逐，龍卧獨冥冥。", "從衆非無術，欺孤乃不經。", "惟思恢正道，直起復炎靈。", "管樂韜方略，關徐駭觀聽。", "一言俄逆至，三顧已忘形。", "南既清蠻土，東期赤魏庭。", "出師功自著，治國志誰銘。", "歷劫兵如水，臨秦策若瓴。", "舉聲將潰虜，横勢欲逾涇。", "仲達恥巾幗，辛毗嚴壁扃。", "可煩親細務，遽見墮長星。", "戰地悲陵谷，來賢賞德刑。", "意中流水遠，愁外舊山青。", "想像音徽在，侵尋毛骨醒。", "遲留慕英氣，沉歎撫青萍。"]'),
('82f57cd3-6eaf-44fc-aed0-960bb387c95b','寄題上虞蘇簿凝虛館','石延年','宋','宋诗','song-poetry','','[]','越基擅巖壑，虛館擇其尤。',72,'全唐诗/poet.song.9000.json','["越基擅巖壑，虛館擇其尤。", "丹甍煜孤飛，靈景邈四周。", "山高晴若陰，洞寒夏如秋。", "錦幄攬花發，玉環渠水流。", "閑臥真吏隱，乍登乃仙游。", "居之宜民思，毋爲茲宇羞。"]'),
('671d2f8e-cda2-474a-9fee-d54ebdb4e9ae','紅梅','石延年','宋','宋诗','song-poetry','','[]','梅好唯傷白，今紅是絕奇。',48,'全唐诗/poet.song.9000.json','["梅好唯傷白，今紅是絕奇。", "認桃無綠葉，辨杏有青枝。", "烘笑從人贈，酡顔任笛吹。", "未應嬌意急，發赤怒春遲。"]'),
('cf7727cf-2fd1-4e70-ad67-75154b7517c5','文種墓','石延年','宋','宋诗','song-poetry','','[]','至忠惜甘死，越塞一墳孤。',48,'全唐诗/poet.song.9000.json','["至忠惜甘死，越塞一墳孤。", "句踐非王者，陶朱亦丈夫。", "碑經山燒斷，樹带海潮枯。", "泉下伍員輩，相逢相弔無。"]'),
('ac5a96be-bd95-4a59-99a1-03695aa7c79c','鶯','石延年','宋','宋诗','song-poetry','','[]','何處傳新哢，間關出建章。',48,'全唐诗/poet.song.9000.json','["何處傳新哢，間關出建章。", "至清無奈玉，更巧莫如簧。", "谷口凄寒甚，花陰淑景長。", "上林棲處穩，慎勿近雕梁。"]'),
('21634bc1-2953-46d3-bf16-2e46a52524e7','燈花','石延年','宋','宋诗','song-poetry','','[]','迴鱗抱雙蒂，倒鳳吐丹榮。',48,'全唐诗/poet.song.9000.json','["迴鱗抱雙蒂，倒鳳吐丹榮。", "冰宇寒生暈，風疏動有聲。", "燼垂金藕細，影透玉荷清。", "斗帳依東壁，誰人夢不成。"]'),
('b83b6607-1e87-4734-a5c2-1a392c510338','潤州狠石','石延年','宋','宋诗','song-poetry','','[]','水光浮柱礎，天影带樓臺。',24,'全唐诗/poet.song.9000.json','["水光浮柱礎，天影带樓臺。", "觸石雲孤起，吹潮雨四來。"]'),
('f015d0d5-ff09-4384-8aa5-58901d0e0b82','贈人','石延年','宋','宋诗','song-poetry','','[]','六符搖斗極，八座冠文章。',24,'全唐诗/poet.song.9000.json','["六符搖斗極，八座冠文章。", "規憲存中府，勳庸入太常。"]'),
('1376efdb-3c99-4234-b151-5570dac2b917','叢菊','石延年','宋','宋诗','song-poetry','','[]','風勁香逾遠，天寒色更鮮。',24,'全唐诗/poet.song.9000.json','["風勁香逾遠，天寒色更鮮。", "秋天買不斷，無意學金錢。"]'),
('0654d204-d7da-4716-b865-508235828869','送鄭十學士戩通理越州','石延年','宋','宋诗','song-poetry','','[]','宸命陪分竹，仙資貴珥彤。',96,'全唐诗/poet.song.9000.json','["宸命陪分竹，仙資貴珥彤。", "入辭中殿閟，出貳式廉雄。", "過楚前封近，還吳舊業空。", "江山復清思，蓴膾起高風。", "海闊悲秦望，陵荒嘆禹功。", "樓澄鑑湖北，地險雪濤東。", "稽壑飛泉石，台基下桂叢。", "風流好吟醉，王謝有餘宮。"]'),
('85ab6e23-866b-4495-8f56-1b4498f8c8f5','和樞密侍郎因看海棠憶禁苑此花最盛','石延年','宋','宋诗','song-poetry','','[]','君看海棠格，羣花品詎同。',156,'全唐诗/poet.song.9000.json','["君看海棠格，羣花品詎同。", "嬌嬈情自富，蕭散艷非窮。", "蒨縠班吳苑，新羅碎蜀宮。", "錦窼盃裏影，繡段隟前烘。", "心亂香無數，莖柔動滿叢。", "意分巫峽雨，腰繫漢臺風。", "盛若霞藏日，鮮於血酒空。", "高低千點赤，深淺半開紅。", "妝指朱纔布，膏脣檀更融。", "色嬌無可壓，體瘦不成豐。", "枝重輕浮外，苞疏密間中。", "難勝蜂不定，易入蝶能通。", "杜甫句何略，薛能詩未工。"]'),
('b64a0c44-7a38-43a6-81f0-ebcc7e4a040e','詠梅','石延年','宋','宋诗','song-poetry','','[]','柔梢繁白玉鈿封，忍盡嬌心恨幾重。',64,'全唐诗/poet.song.9000.json','["柔梢繁白玉鈿封，忍盡嬌心恨幾重。", "姑射真人冰作體，廣寒仙女月爲容。", "江南春信香猶在，樓上晨妝粉不供。", "可惜東風晴未暖，洛川流雪更無蹤。"]'),
('8606eb85-b988-4e4e-952a-5ec881e2793b','送則師歸越','石延年','宋','宋诗','song-poetry','','[]','歸里懸心復苦形，生涯蓑笠伴銅瓶。',64,'全唐诗/poet.song.9000.json','["歸里懸心復苦形，生涯蓑笠伴銅瓶。", "魚隨洗缽衝遺粒，龍倚移舟識唪經。", "佛廟春遊湖樹暗，神濤晴渡越峰青。", "高才不獨江山助，王謝風流舊有靈。"]'),
('ee2e98ae-ab1a-476d-8de8-c594b8f6f448','南朝','石延年','宋','宋诗','song-poetry','','[]','南朝人物盡清賢，不是風流即放言。',32,'全唐诗/poet.song.9000.json','["南朝人物盡清賢，不是風流即放言。", "三百年間卻堪笑，絕無人可定中原。"]'),
