('2fc9be49-771e-438c-a81f-aac285f5632e','句  其二六','石延年','宋','宋诗','song-poetry','','[]','繁萼香瓊亂，殘英絳雪遺。',12,'全唐诗/poet.song.9000.json','["繁萼香瓊亂，殘英絳雪遺。"]'),
('8cd9af47-0d0c-4669-96ea-2356ad768853','句  其二七','石延年','宋','宋诗','song-poetry','','[]','更被陰晴長睡魔。',8,'全唐诗/poet.song.9000.json','["更被陰晴長睡魔。"]'),
('699f1e4b-f87c-4795-b93e-776ac202960c','句  其二八','石延年','宋','宋诗','song-poetry','','[]','苔磯清鏡裏。',6,'全唐诗/poet.song.9000.json','["苔磯清鏡裏。"]'),
('1b31e9d7-0ea6-454f-aec6-dd95524568ab','句  其二九','石延年','宋','宋诗','song-poetry','','[]','林泉是四鄰。',6,'全唐诗/poet.song.9000.json','["林泉是四鄰。"]'),
('9e76c48e-8bfd-4a07-8850-1906df79ec13','句  其三○','石延年','宋','宋诗','song-poetry','','[]','小萼裁成絳臘勻。',8,'全唐诗/poet.song.9000.json','["小萼裁成絳臘勻。"]'),
('d5891837-2a9c-4cca-b895-10db0c971262','小隱園詩','謝絳','宋','宋诗','song-poetry','','[]','僕本塵外士，功名若毫一。',48,'全唐诗/poet.song.9000.json','["僕本塵外士，功名若毫一。", "因尋小園隱，忽見羣芳發。", "昔夢宛可記，靈契方茲達。", "會須掛朝纓，歸弄巖前月。"]'),
('f9162c64-17d2-4729-a660-4b6d3c520e2f','雙松亭','謝絳','宋','宋诗','song-poetry','','[]','築居喜物外，披逕窮木末。',72,'全唐诗/poet.song.9000.json','["築居喜物外，披逕窮木末。", "層阜繞襟带，澄江見毫髪。", "芬芬山蜜熟，決決春泉活。", "林梢閃猿隕，石罅愸銜月。", "坐長百慮寂，望遠孤興發。", "何必較萬殊，吾自師吾達。"]'),
('df034272-c6cd-4fc2-9215-2df4adf69d65','答梅聖俞問隱','謝絳','宋','宋诗','song-poetry','','[]','聖俞一幅書，間我小隱居。',288,'全唐诗/poet.song.9000.json','["聖俞一幅書，間我小隱居。", "小隱詎有異，築室數畝餘。", "巖壑不峻崒，田園非美腴。", "所欲近丘墓，歲時來掃除。", "先人夢讀史，尊道本聖徒。", "絕筆于此詩，子孫無忽諸。", "刻石置中堂，且使過者趨。", "題牓爲服訓，義取銘盤盂。", "後嶺雙松亭，徑術何逶迂。", "下臨富春渚，萬象生有無。", "東偏作草舍，可以施琴壺。", "門前碧塘水，萬本栽荷蕖。", "風來觸香氣，長著人衣裾。", "澄水泱泱流，黍稻可勿枯。", "柔桑及美果，種廣莫記株。", "澗草不識名，野禽多異呼。", "坐此易歲晏，自與人世疏。", "在昔東陵侯，瓜壠猶親鋤。", "楊惲謝九列，種豆南山隅。", "余嘗有此志，來者安敢誣。", "誅茅實張本，解組當後圖。", "是時考槃賦，從我者騅歟。", "近來傅越石，趣尚若不殊。", "儻聞丘樊往，不顧升斗儲。"]'),
('6e55514a-d852-4cf0-a390-2e6bbaca413c','送餘姚知縣陳最寺丞  其一','謝絳','宋','宋诗','song-poetry','','[]','稍過山陰接甬東，正當兩國畫屏中。',64,'全唐诗/poet.song.9000.json','["稍過山陰接甬東，正當兩國畫屏中。", "巖巓僧井通江水，門外商帆落海風。", "盡日揮弦無一事，平時推轂有諸公。", "此行絕勝人人羨，莫恨猶懷五兩銅。"]'),
('4e3a38d6-fc19-4aa5-966b-c0343eb693d9','送餘姚知縣陳最寺丞  其二','謝絳','宋','宋诗','song-poetry','','[]','愧君來款關，話別憩林間。',48,'全唐诗/poet.song.9000.json','["愧君來款關，話別憩林間。", "不待風銷暑，聊因酒發顔。", "滄洲即欲往，清躅暫容攀。", "居者羨行者，寄聲思越山。"]'),
('66e378a7-8d3d-4b6d-861f-7990ce0db3a9','聯句','謝絳','宋','宋诗','song-poetry','','[]','古木含清吹，池上增晚涼。',96,'全唐诗/poet.song.9000.json','["古木含清吹，池上增晚涼。", "余懷本達曠，聯此傲羲皇。", "孤鷗可與狎，幽岸足以觴。", "幸有彭澤酒，便同永嘉堂。", "潘生起爲壽，王子齊陳章。", "林端見新月，草際聞寒螿。", "照水螢影亂，拂筵蓼花香。", "徘徊戀嘉境，坐使歸興忘。"]'),
('0068c191-7b1f-4170-9069-e9bd3f13672f','洛中冬夕道話有懷善慧大士聯句','謝絳','宋','宋诗','song-poetry','','[]','彼有上人者，妙談心所降。',72,'全唐诗/poet.song.9000.json','["彼有上人者，妙談心所降。", "達空知不二，觀行本無雙。", "久阻飄花席，因思響雪窗。", "社中雖得遠，方外自非龐。", "夢幻慚他劫，風塵厭此邦。", "終期親道樹，何必憶重江。"]'),
('da1af57f-78ad-4c27-9bc9-6609f55ec33e','約遊西溪信馬不覺行過據鞍聯句','謝絳','宋','宋诗','song-poetry','','[]','有意訪西溪，順塗吟思迷。',48,'全唐诗/poet.song.9000.json','["有意訪西溪，順塗吟思迷。", "及茲詢野老，已恨過芳蹊。", "醉客但多興，幽禽空自啼。", "無由駐金勒，林表日光低。"]'),
('0551b254-fb95-434a-9a3c-fce5ea085794','馬上口占送九舅入京城親聯句','謝絳','宋','宋诗','song-poetry','','[]','之子洛中來，芳樽喜暫開。',48,'全唐诗/poet.song.9000.json','["之子洛中來，芳樽喜暫開。", "人誇阿連少，吾愧士衡才。", "丹闕鳳皇去，清川鴻雁回。", "都門春色美，相送思悠哉。"]'),
('d898f528-64c7-4cf1-aa20-915c437186a8','玉麈尾寄傅尉越石聯句','謝絳','宋','宋诗','song-poetry','','[]','齋中獨何物，持之想見君。',96,'全唐诗/poet.song.9000.json','["齋中獨何物，持之想見君。", "惟茲玉麈尾，信美而有文。", "夫之善談道，亹亹詞如雲。", "在握昔同色，傾坐今離羣。", "況託懷袖好，曾親蕙蘭薰。", "常許助閑放，於焉探典墳。", "既乃阻清燕，復屈驅虻蚊。", "自殊白團扇，未畏秋葉紛。"]'),
('200b5d8a-8f4c-430d-afe9-e7696401832d','風瑟聯句','謝絳','宋','宋诗','song-poetry','','[]','竅竹漏天風，張弦擬嶧桐。',48,'全唐诗/poet.song.9000.json','["竅竹漏天風，張弦擬嶧桐。", "佳名從此得，妙響未曾窮。", "夜靜危臺上，人閑皎月中。", "依依聽不足，秋露滿蘭叢。"]'),
('8a928657-9e81-4b64-863d-0fd700a57a2e','來燕堂聯句','謝絳','宋','宋诗','song-poetry','','[]','賢侯謝郡歸，從遊樂吾黨。',240,'全唐诗/poet.song.9000.json','["賢侯謝郡歸，從遊樂吾黨。", "林泉富餘地，卜築疏陳莽。", "是時春正中，來燕音下上。", "若賀大廈成，喜留衆賓賞。", "得名因笑談，揮墨粲題榜。", "所夸賢豪盛，豈上池榭廣。", "人心樂且閑，鳥意頡而頏。", "吟罇敞花軒，醉枕酣風幌。", "輕雲薄藻棟，初日麗珠網。", "紅袂生暗香，清弦泛餘響。", "林深隱飛蓋，岸曲遲去槳。", "波光欄檻明，竹氣衣巾爽。", "虛容涼樾入，影與文漣蕩。", "晨飈轉綠蕙，夕雨滋膏壤。", "嘉辰喜盍朋，命駕期屢往。", "觴詠陶淑真，世俗豈吾倣。", "得以爲勝遊，蕭然散煩想。", "公子固好士，世德復可像。", "今此大基構，不圖專奉養。", "美哉風流存，來葉足師仰。"]'),
('2316b74a-af3b-4537-9f7a-dd5d83137074','句  其一','謝絳','宋','宋诗','song-poetry','','[]','王貌閑如鶴，黄吟苦似猿。',12,'全唐诗/poet.song.9000.json','["王貌閑如鶴，黄吟苦似猿。"]'),
('807ac253-72ab-46a7-92ea-cf0ded67b228','句  其二','謝絳','宋','宋诗','song-poetry','','[]','秋波下南浦，曉氣望西山。',12,'全唐诗/poet.song.9000.json','["秋波下南浦，曉氣望西山。"]'),
('db033747-0f22-41d4-871d-38db13ee80e2','題溪口廣慈寺','錢彥遠','宋','宋诗','song-poetry','','[]','寺跨長溪山四回，杉松微徑盡莓苔。',32,'全唐诗/poet.song.9000.json','["寺跨長溪山四回，杉松微徑盡莓苔。", "門前潮上不須看，常恐塵埃隨水來。"]'),
('4d743016-75af-4495-bfa0-b7715844309c','山中','釋祕演','宋','宋诗','song-poetry','','["\u5b64\u72ec", "\u5199\u666f", "\u5c71", "\u63cf\u5199\u5c71", "\u5199\u5c71"]','結茅鄰水石，澹寂益閑吟。',48,'全唐诗/poet.song.9000.json','["結茅鄰水石，澹寂益閑吟。", "久雨寒蟬少，空山落葉深。", "危樓乘月上，遠寺聽鍾尋。", "昨得江僧信，期來此息心。"]'),
('47b6596d-d0d5-450e-bca6-a0073e462cdb','淮上','釋祕演','宋','宋诗','song-poetry','','[]','危橋當古寺，閑倚喜同僧。',48,'全唐诗/poet.song.9000.json','["危橋當古寺，閑倚喜同僧。", "極浦霽秋雨，扁舟明夜燈。", "風沈入語遠，潮漲月華昇。", "萬事空凝念，其如總未能。"]'),
('e00f6a45-468f-4b6e-81c7-2c8858b6c937','賈希德','釋祕演','宋','宋诗','song-poetry','','[]','山東持木鐸，高識世難羣。',48,'全唐诗/poet.song.9000.json','["山東持木鐸，高識世難羣。", "覽照驚秋鬢，看碑見舊文。", "救時曾抗牘，退迹欲眠雲。", "帳外橫經者，清朝已立勳。"]'),
('bb638366-0ba0-43b1-8fd8-780618ff2d0b','寄四明教主','釋祕演','宋','宋诗','song-poetry','','[]','古疏傳深旨，清流照瘦顔。',48,'全唐诗/poet.song.9000.json','["古疏傳深旨，清流照瘦顔。", "四方來問道，半世不離山。", "養鶴憐終潔，看雲許共閑。", "仍聞焚幻質，幾欲別人間。"]'),
('9ff80917-c3fd-466e-92e0-a1d250e17db7','示光化軍寺壁','釋祕演','宋','宋诗','song-poetry','','[]','萬家雲樹水邊州，千里秋風一錫遊。',32,'全唐诗/poet.song.9000.json','["萬家雲樹水邊州，千里秋風一錫遊。", "晚渡無人過疏雨，亂峰寒翠入西樓。"]'),
('2cc55fab-836f-4097-acbc-6044176d241a','洛陽春','釋祕演','宋','宋诗','song-poetry','','[]','雨霽園林宿靄微，暖風遲日薦芳菲。',64,'全唐诗/poet.song.9000.json','["雨霽園林宿靄微，暖風遲日薦芳菲。", "池蒲露劍驚魚躍，簾額翻波礙鳥飛。", "好景正繁春未半，小桃初放蝶仍稀。", "閑中兩兩高陽輩，醉泥東君夜不歸。"]'),
('784ea511-fed8-427a-b110-7ff663a48396','遊古觀','釋祕演','宋','宋诗','song-poetry','','[]','參差宮殿倚青天，一別重來四十年。',64,'全唐诗/poet.song.9000.json','["參差宮殿倚青天，一別重來四十年。", "老檜掛巢時有鶴，亂雲藏洞久無仙。", "春移草色抽新带，雨養苔痕壓舊錢。", "兩兩相逢皆不合，落花流水石爐煙。"]'),
('f1450ab1-2070-482a-a68f-19385730e878','和同志','洪聖保','宋','宋诗','song-poetry','','[]','一箇巖寬萬物周，塵中擾擾到無由。',32,'全唐诗/poet.song.9000.json','["一箇巖寬萬物周，塵中擾擾到無由。", "儂家儘有居山意，問著依前隔數州。"]'),
('f427cf20-df7b-4568-8c43-ef5b140824cb','過吳江','王贄','宋','宋诗','song-poetry','','[]','吳江秋水灌平湖，水闊煙深恨有餘。',32,'全唐诗/poet.song.9000.json','["吳江秋水灌平湖，水闊煙深恨有餘。", "因想季鷹當日事，歸來未必爲蓴鱸。"]'),
('94f49ca1-3071-4ebe-b57e-e22ff895d888','和蔣潁叔涇溪','余良肱','宋','宋诗','song-poetry','','[]','畫舸夷猶紫翠間，暮雲如掃月如環。',32,'全唐诗/poet.song.9000.json','["畫舸夷猶紫翠間，暮雲如掃月如環。", "三山六刺須臾過，恰似嚴陵七里灘。"]'),
('8cd0766d-ad1f-4847-854f-e3d0659ee92d','雪後遊琅邪山聯句','刁繹','宋','宋诗','song-poetry','','[]','南溪約幽尋，西嶺極遐觀。',288,'全唐诗/poet.song.9000.json','["南溪約幽尋，西嶺極遐觀。", "初陽色朦朧，殘雪光汗漫。", "相望樓殿間，宛在雲霄半。", "泉聲减琤淙，山勢欲飛竄。", "岩寒雨花霏，谷暖煙絮亂。", "幽鳥度喬林，驚猿折枯幹。", "決決漲溪流，輝輝披野岸。", "蘭芽吐尚微，冰乳凝未泮。", "佛屋對峰尖，禪庵倚崖斷。", "軒窗愛虛豁，赤白從漫漶。", "行敲玉玲琅，松溜珠璀璨。", "寜将瓊礫分，未省蘭蒿判。", "行幽兔迹深，瞩遠鴉翅緩。", "登宜阮孚屐，隱稱嵇康鍛。", "結遊賢躅多，鑱石清詩爛。", "極目窮躋攀，投隙違羈絆。", "榮觀太帝書，暫憇飛仙館。", "石立翠屏張，霞收丹錦散。", "覘坐客爐擁，負暄僧衲換。", "選勝唯務得，陟危寜復憚。", "誰乘泛海槎，直欲傍銀漢。", "况有凌雲才，何妨舉風翰。", "景多苦冥搜，歡觧惬佳玩。", "乃情慰懸想，昔傳非謾讕。"]'),
('1efd873a-58ef-40d1-aed8-ca5a41a85e32','滁上間日陰晴聯句','刁繹','宋','宋诗','song-poetry','','[]','陰晴淮海氣何殊，一昔風光互惨舒。',160,'全唐诗/poet.song.9000.json','["陰晴淮海氣何殊，一昔風光互惨舒。", "大塊養春禆造化，繁雲間日蔽居諸。", "暖回沙磧催來鴈，寒徹冰池怯上魚。", "山色晦明如代謝，花枝涼曝似相於。", "朝暾忽蕩川原净，夕翳還籠井落疏。", "快適得朋釃醁酒，困眠無興讀殘書。", "虹霞灼灼飛琳館，煙靄濛濛襲隼旟。", "定與物情均燥濕，殆非星好有盈虚。", "連空雪意迷高桞，遶舍陽和坼嫩蔬。", "林外昏鴉啼野盡，城頭新月上簾初。"]'),
('83c74c04-ca86-4814-b8a9-509a318f581e','雨後城上種蜀葵效轆轤體聯句','刁繹','宋','宋诗','song-poetry','','[]','不惮移根遠，姑憐向日姿。',288,'全唐诗/poet.song.9000.json','["不惮移根遠，姑憐向日姿。", "春風從自得，夜雨况相資。", "敏速飛霜钁，婆娑擁碧枝。", "幽葩兹有待，雜卉漫多奇。", "野藿非余尙，庭蘭盍爾知。", "傾心安所守，衛足豈其私。", "得地何妨徙，干霄固可疑。", "采幢須夏節，綠餅與秋期。", "莫以藂生陋，唯其秀出宜。", "遷非拔茅進，愛豈揠苖爲。", "色解凌溪錦，花應當酒巵。", "遶欄窠尙小，傍砌影猶卑。", "援護情宜倍，栽培力已施。", "桃蹊容爛熳，竹逕聳参差。", "不待毛嬙妬，何嫌魯相辭。", "土培憂壓嫩，竹插爲扶欹。", "疏密齊行列，芳華遞疾遲。", "纖莖簪間導，繁蘂珥交垂。", "恐踐禽須逐，防侵草必夷。", "養完先固本，採折俟乘時。", "屢戒園夫守，頻煩墨客窺。", "拾來同地芥，吟就比江蘺。", "泛與蕭蒿長，偏饒雨露滋。", "何如君子德，修直任榮衰。"]'),
('c7552444-f346-4723-aefb-52042271b103','春集東園賦得翠字','刁約','宋','宋诗','song-poetry','','[]','託載東城隅，選勝名園地。',72,'全唐诗/poet.song.9000.json','["託載東城隅，選勝名園地。", "不問主人來，聊適尋春意。", "簪花照席光，藉草連袍翠。", "煙霏遠樹迷，風臘繁英墜。", "促行瀲灧觴，少駐雍容騎。", "四者信難並，安敢辭沉醉。"]'),
('fa4d942e-b2b8-4491-87f4-232f4f3d90cb','使契丹戲作','刁約','宋','宋诗','song-poetry','','[]','押燕移離畢，看房賀跋支。',24,'全唐诗/poet.song.9000.json','["押燕移離畢，看房賀跋支。", "餞行三匹裂，密賜十貔貍。"]'),
('4090cc55-2113-4af7-aa21-59d69d0d2f2e','遊五洩山','刁約','宋','宋诗','song-poetry','','[]','西源窮盡到東源，直注層崖五磴泉。',64,'全唐诗/poet.song.9000.json','["西源窮盡到東源，直注層崖五磴泉。", "真境無繇追汗漫，勝遊聊得弄潺湲。", "風生虎嘯層巖底，月上猿啼古木巓。", "祇待歸休林下去，來同靈默此安禪。"]'),
('01c15c05-d753-4b2c-a7d9-2b7fa18a0e35','過漁浦作','刁約','宋','宋诗','song-poetry','','[]','一水相望越與杭，渡頭人物見微茫。',64,'全唐诗/poet.song.9000.json','["一水相望越與杭，渡頭人物見微茫。", "翩翩商楫來谿口，隱隱耕犁入富陽。", "市肆凋疏隨浦盡，山峰重疊傍江長。", "民瞻熊輊咸相謂，太守經行此未嘗。"]'),
('be5b88fe-e376-42a2-b4ae-83781ceeb1be','過溪口廣慈院','刁約','宋','宋诗','song-poetry','','[]','賞徧林泉去未能，卻來溪口訪巖僧。',64,'全唐诗/poet.song.9000.json','["賞徧林泉去未能，卻來溪口訪巖僧。", "爲觀遠景尤奇處，更陟危亭最上層。", "雲吐前峰疑霈雨，泉飛別澗旋凝冰。", "陋容憔悴煩躬筆，待結錢唐九老朋。"]'),
('9a9044a3-b1ad-488a-8e10-5b186148aef5','方氏清芬閣','刁約','宋','宋诗','song-poetry','','[]','自別高居二紀餘，今朝重到懶踟躕。',32,'全唐诗/poet.song.9000.json','["自別高居二紀餘，今朝重到懶踟躕。", "山川勝景依然在，屈指交親一半無。"]'),
('856f6395-ff4e-4183-bb5d-44e5633aa5ed','嚴陵山','刁約','宋','宋诗','song-poetry','','[]','一染浮名十五春，強隨時態役天真。',32,'全唐诗/poet.song.9000.json','["一染浮名十五春，強隨時態役天真。", "何年卜築茲山下，卻笑區區世路人。"]'),
('f830cc31-2a29-4ad1-9463-51e71205e0fc','送梵才大師歸天台','刁約','宋','宋诗','song-poetry','','[]','京洛風塵弊客裾，故山歸去有精廬。',64,'全唐诗/poet.song.9000.json','["京洛風塵弊客裾，故山歸去有精廬。", "綴盂應供王城久，鏤管賡吟友社餘。", "衲擁蘭芽新賜服，帙收貝葉舊翻書。", "蕭然壁觀芝巖上，從此身名與世疏。"]'),
('7277ab72-33f6-43c2-bd97-46bd7be8ae33','如歸亭','刁約','宋','宋诗','song-poetry','','[]','松陵江上峻裁基，危岫前瞻小四圍。',64,'全唐诗/poet.song.9000.json','["松陵江上峻裁基，危岫前瞻小四圍。", "張翰鱸魚閑適興，莊周鷗鳥盡忘機。", "簷牙高啄千家繞，舟尾相銜數槳飛。", "倦客登臨聊永日，豁開雜思信如歸。"]'),
('5ad6a139-4044-436a-aec1-323090db18bb','如歸亭','吳感','宋','宋诗','song-poetry','','[]','五柳門南派水東，水邊亭上興無窮。',64,'全唐诗/poet.song.9000.json','["五柳門南派水東，水邊亭上興無窮。", "半窗山色來雲外，一枕荷香带雨中。", "繡被夜歌青翰檝，綠波春颺紫莖風。", "塵曹未竊江湖號，攜手闌干早晚同。"]'),
('124aa6b7-e9f8-4652-9009-83aace7ffde6','寄歐陽永叔謫夷陵','謝伯初','宋','宋诗','song-poetry','','[]','江流無險似瞿塘，滿峽猿聲斷旅腸。',128,'全唐诗/poet.song.9000.json','["江流無險似瞿塘，滿峽猿聲斷旅腸。", "萬里可堪入謫宦，經年應合鬢成霜。", "長官衫色江波綠，學士文華蜀錦張。", "異域化爲儒雅俗，遠民爭識校讎郎。", "才如夢得多爲累，情似安仁久悼亡。", "下國難留金馬客，新詩傳與竹枝娘。", "典辭懸待修青史，諫草當來集皂囊。", "莫謂明時暫遷謫，便將纓足濯滄浪。"]'),
('99933fb9-beb5-4e92-9271-96eb35fcdd2e','許昌公宇書懷呈歐陽永叔韓子華王介甫','謝伯初','宋','宋诗','song-poetry','','[]','十年趨競浪求營，因得閑曹減宦情。',64,'全唐诗/poet.song.9000.json','["十年趨競浪求營，因得閑曹減宦情。", "亂種黄花看野景，旋移高竹聽秋聲。", "驅馳賤事猶干祿，約勒清狂爲近名。", "早晚持竿釣鱸鱖，雙溪煙雨一舟橫。"]'),
('81faf912-500c-447f-ac74-03ed2b321011','句  其一','謝伯初','宋','宋诗','song-poetry','','[]','多情未老已白髪，野思到春如亂雲。',16,'全唐诗/poet.song.9000.json','["多情未老已白髪，野思到春如亂雲。"]'),
('7701e6c4-f264-412d-b2ca-39c5dced0dd5','句  其二','謝伯初','宋','宋诗','song-poetry','','[]','園林換葉梅初熟，池館無人燕學飛。',16,'全唐诗/poet.song.9000.json','["園林換葉梅初熟，池館無人燕學飛。"]'),
('fb3eabca-c6ef-474f-970b-fc9b5928aba3','存目  其一','謝伯初','宋','宋诗','song-poetry','','[]','詩題：原無詩題。',8,'全唐诗/poet.song.9000.json','["詩題：原無詩題。"]'),
('b886d03b-f101-4fc2-b639-c2f88acc4ca7','存目  其二','謝伯初','宋','宋诗','song-poetry','','[]','首句：移家尚恐青山淺，隱几惟知白日長。',19,'全唐诗/poet.song.9000.json','["首句：移家尚恐青山淺，隱几惟知白日長。"]'),
('a3a7eed8-6025-4e93-aa4b-309e8f9a886c','存目  其三','謝伯初','宋','宋诗','song-poetry','','[]','出處：宋阮閱《詩話總龜》前集卷一三引《古今詩話》。',25,'全唐诗/poet.song.9000.json','["出處：宋阮閱《詩話總龜》前集卷一三引《古今詩話》。"]'),
('1327e42a-ce4f-4569-a111-f1edf3e6bb6f','存目  其四','謝伯初','宋','宋诗','song-poetry','','[]','附注：據宋司馬光《傳家集》卷八《寄贈致仕劉都官諷》詩末自註及《溫公續詩話》所載，此二句係范鎮（景仁）詩，《古今詩話》誤以范景仁爲謝景山。',68,'全唐诗/poet.song.9000.json','["附注：據宋司馬光《傳家集》卷八《寄贈致仕劉都官諷》詩末自註及《溫公續詩話》所載，此二句係范鎮（景仁）詩，《古今詩話》誤以范景仁爲謝景山。"]'),
('ed3db0c6-5b26-410a-a853-366572374d23','櫻桃','謝希孟','宋','宋诗','song-poetry','','[]','穀雨櫻桃落，薰風柳带斜。',24,'全唐诗/poet.song.9000.json','["穀雨櫻桃落，薰風柳带斜。", "舜弦新曲在，休唱後庭花。"]'),
('1c78586f-6d13-4816-a0e9-d325826179de','詠芍藥','謝希孟','宋','宋诗','song-poetry','','[]','好是一時艷，本無千歲期。',24,'全唐诗/poet.song.9000.json','["好是一時艷，本無千歲期。", "所以謔相贈，載之在聲詩。"]'),
('af43b397-a356-4767-bb3c-41a653d5f9d4','句  其一','謝希孟','宋','宋诗','song-poetry','','[]','爲花雖可期，論德亦終鮮。',12,'全唐诗/poet.song.9000.json','["爲花雖可期，論德亦終鮮。"]'),
('190b0aa7-0e5e-4677-8387-a218db1e6fc3','句  其二','謝希孟','宋','宋诗','song-poetry','','[]','句牽主人衣，一步行不得。',12,'全唐诗/poet.song.9000.json','["句牽主人衣，一步行不得。"]'),
('133838b5-b471-4a0b-a298-e0fa36b34e56','句  其三','謝希孟','宋','宋诗','song-poetry','','[]','薰薰麝臍烈，灼灼猩血殷。',12,'全唐诗/poet.song.9000.json','["薰薰麝臍烈，灼灼猩血殷。"]'),
('961f5175-3bcb-4a96-811c-fa09d90801b7','句  其四','謝希孟','宋','宋诗','song-poetry','','[]','樹既摧爲薪，花亦落爲塵。',12,'全唐诗/poet.song.9000.json','["樹既摧爲薪，花亦落爲塵。"]'),
('9f3bdb18-7e54-4b0f-b448-115d7ea95224','句  其五','謝希孟','宋','宋诗','song-poetry','','[]','艷陽一何好，零落千載冤。',12,'全唐诗/poet.song.9000.json','["艷陽一何好，零落千載冤。"]'),
('5d446347-ca31-4fbb-b5a6-13bd176129a5','句  其六','謝希孟','宋','宋诗','song-poetry','','[]','盜者得其便，掉頭笑且歌。',12,'全唐诗/poet.song.9000.json','["盜者得其便，掉頭笑且歌。"]'),
('6e7125c1-ad63-4761-8b8b-48e7baae0433','句  其七','謝希孟','宋','宋诗','song-poetry','','[]','卞子真賞季，莊生夢還怯。',12,'全唐诗/poet.song.9000.json','["卞子真賞季，莊生夢還怯。"]'),
('0ed9073d-c3b9-4deb-a9b7-a2211a7c0b1e','題希夷堂贈周道正','王珏','宋','宋诗','song-poetry','','[]','仙骨清冷道氣濃，餌芝深建括蒼東。',64,'全唐诗/poet.song.9000.json','["仙骨清冷道氣濃，餌芝深建括蒼東。", "醉遊鼇頂三山綠，吟對神爐九轉紅。", "千古遺音生指下，一天星斗在壺中。", "蕭然不許塵埃到，顧我頻來興未窮。"]'),
('d0926959-e717-42b5-a06f-ddc839a684fb','延平天慶觀','王初','宋','宋诗','song-poetry','','[]','劍化江邊彩構新，層臺不染玉梯塵。',64,'全唐诗/poet.song.9000.json','["劍化江邊彩構新，層臺不染玉梯塵。", "千章隱篆標龍簡，一曲空歌降鳳鈞。", "嵐氣濕衣雲葉晚，天香飄戶月枝春。", "盟金早晚聞仙語，學種三芝伴羽人。"]'),
('a0389623-75b8-419e-a7bc-a268b33d9f19','青帝','王初','宋','宋诗','song-poetry','','[]','青帝邀春隔歲還，月娥孀獨夜漫漫。',64,'全唐诗/poet.song.9000.json','["青帝邀春隔歲還，月娥孀獨夜漫漫。", "韓憑舞羽身猶在，素女商弦調未殘。", "終古蘭巖棲偶鶴，從來玉谷有離鸞。", "幾時幽恨飄然斷，共待天池一水乾。"]'),
('3b2d5122-11f7-44e6-b6e4-3ae8503f2302','書秋','王初','宋','宋诗','song-poetry','','[]','千里南雲度塞鴻，秋雲無跡淡平空。',64,'全唐诗/poet.song.9000.json','["千里南雲度塞鴻，秋雲無跡淡平空。", "人間玉嶺清霄月，天上銀河白晝風。", "潘賦登山魂易斷，楚歌遺佩怨何窮。", "往來未得如張翰，欲膾霜鯨碧海東。"]'),
('877b55cc-baec-47da-8671-4b89bf0835b5','自和書秋','王初','宋','宋诗','song-poetry','','[]','隴首斜飛避弋鴻，頹雲蕭索見層空。',64,'全唐诗/poet.song.9000.json','["隴首斜飛避弋鴻，頹雲蕭索見層空。", "漢宮夜結雙莖露，閶闔涼生六幕風。", "湘女怨弦愁不禁，鄂君香被夢難窮。", "江邊兩槳連歌渡，驚散遊魚蓮葉東。"]'),
('a023bfc7-886e-429a-b61a-d0a5f1e03b11','立春後作','王初','宋','宋诗','song-poetry','','[]','東君珂珮響珊珊，青馭多時下九關。',32,'全唐诗/poet.song.9000.json','["東君珂珮響珊珊，青馭多時下九關。", "方信玉霄千萬里，春風猶未到人間。"]'),
('db568cf3-37e1-461a-a00d-8402c951b6bb','春日詠梅花  其一','王初','宋','宋诗','song-poetry','','[]','靚妝纔罷粉痕新，迢遞風回散玉塵。',32,'全唐诗/poet.song.9000.json','["靚妝纔罷粉痕新，迢遞風回散玉塵。", "若遣有情應悵望，翠兼殘雪又兼春。"]'),
('62ffcff8-bde1-46ee-9ec1-249f872c63ca','春日詠梅花  其二','王初','宋','宋诗','song-poetry','','[]','青帝來時值遠芳，殘花殘雪尚交光。',32,'全唐诗/poet.song.9000.json','["青帝來時值遠芳，殘花殘雪尚交光。", "隔年擬待春消息，得見春風已斷腸。"]'),
('bc59172e-efa3-430a-92a8-28168fb79282','七夕','王初','宋','宋诗','song-poetry','','[]','榆葉飄零碧漢流，玉蟾珠露兩清秋。',32,'全唐诗/poet.song.9000.json','["榆葉飄零碧漢流，玉蟾珠露兩清秋。", "仙家若有單棲恨，莫向銀臺半夜游。"]'),
('f7a6fed0-584a-41b8-b68a-ee6153780084','送陳校勘入宿','王初','宋','宋诗','song-poetry','','[]','日落風回卷碧霓，方蓬一夜拆龍泥。',32,'全唐诗/poet.song.9000.json','["日落風回卷碧霓，方蓬一夜拆龍泥。", "銀臺級級連清漢，桂子香濃月杵低。"]'),
('362809c2-9c12-49b0-8c1e-fa7e94207ccf','即夕','王初','宋','宋诗','song-poetry','','[]','風幌涼生白袷衣，星榆纔亂絳河低。',32,'全唐诗/poet.song.9000.json','["風幌涼生白袷衣，星榆纔亂絳河低。", "月明休近相思樹，恐有韓憑一處棲。"]'),
('d0997cdc-7177-4926-89bc-f2e2fc8e1344','雪霽','王初','宋','宋诗','song-poetry','','[]','星榆葉葉晝離披，雲粉千重凝不飛。',32,'全唐诗/poet.song.9000.json','["星榆葉葉晝離披，雲粉千重凝不飛。", "崑玉樓臺珠樹密，夜來誰向月中歸。"]'),
('7a67943e-ec5f-47e2-9df1-bb214c50afd3','舟次汴堤','王初','宋','宋诗','song-poetry','','[]','曲岸蘭八雁飛起，野客維舟碧煙裏。',32,'全唐诗/poet.song.9000.json','["曲岸蘭八雁飛起，野客維舟碧煙裏。", "竿頭五兩轉天風，白日楊花滿流水。"]'),
('da391709-6c36-4ad5-bc43-d83e550ee445','大滌洞天留題','王稷','宋','宋诗','song-poetry','','[]','山深九鎖路逶迤，坡仙骨朽名不磨。',64,'全唐诗/poet.song.9000.json','["山深九鎖路逶迤，坡仙骨朽名不磨。", "秦皇塞海墮渺茫，漢殿拂雲今嵯峨。", "洞府有真扃地戶，玉泉飛瀑來天河。", "此山神造壽國脈，庇民洪福方滋多。"]'),
('74ed2030-fcc5-43db-ac54-b0638326b01f','蟄龍潭','張沃','宋','宋诗','song-poetry','','[]','蟄龍潭裏蟄，潭上風波急。',24,'全唐诗/poet.song.9000.json','["蟄龍潭裏蟄，潭上風波急。", "一旦飛上天，魚蝦不能及。"]'),
('73d36032-45da-4b89-8a0f-14ae29833258','陽朔山','宋咸','宋','宋诗','song-poetry','','[]','獨起獨高雄入漢，相耀相映翠成堆。',64,'全唐诗/poet.song.9000.json','["獨起獨高雄入漢，相耀相映翠成堆。", "若非羣玉崑西至，即是三峰海上來。", "疑有洞天通日月，絕無樵路到塵埃。", "如何得似巨靈手，擘向天家對鳳臺。"]'),
('87c944f4-7c7a-4e2b-a39c-f586ccd80727','上元','宋咸','宋','宋诗','song-poetry','','[]','連甍珠閣迷仙閬，幾處星樓接絳河。',32,'全唐诗/poet.song.9000.json','["連甍珠閣迷仙閬，幾處星樓接絳河。", "寶馬縱橫浮市照，香塵撩亂夾春和。"]'),
('1a491661-1a4f-4959-804e-e84ffa768bc5','牡丹  其一','宋咸','宋','宋诗','song-poetry','','[]','輕霧欲籠藏暮碧，斷霞初怨誤朝紅。',48,'全唐诗/poet.song.9000.json','["輕霧欲籠藏暮碧，斷霞初怨誤朝紅。", "即時苦待千枝爛，計日先愁一樹空。", "外客定聞瓊宴賞，護春長把錦帷蒙。"]'),
('48ca9e2d-44cc-408c-9c3b-e167fd38a5dd','牡丹  其二','宋咸','宋','宋诗','song-poetry','','[]','何須羣玉南頭見，都似沉香北畔移。',48,'全唐诗/poet.song.9000.json','["何須羣玉南頭見，都似沉香北畔移。", "護地寶欄方自整，尋春珠蓋有誰知。", "鶯迷舊樹棲猶晚，人樂新英賞未遲。"]'),
('97514620-678f-44b1-942b-3f501aac3b67','桂','宋咸','宋','宋诗','song-poetry','','[]','多應譙國山邊種，豈是嫦娥月裏香。',32,'全唐诗/poet.song.9000.json','["多應譙國山邊種，豈是嫦娥月裏香。", "願爲兒孫積陰德，東堂時占一枝芳。"]'),
('84e1720d-2087-4d7b-8487-27d5e24a2da7','句  其一','宋咸','宋','宋诗','song-poetry','','[]','寶花初爛欲連枝。',8,'全唐诗/poet.song.9000.json','["寶花初爛欲連枝。"]'),
