('ae64fc0f-ae8e-4b15-9a9d-8ab6c91bcf9b','句  其三','宋咸','宋','宋诗','song-poetry','','[]','豈是嫦娥月裏香。',8,'全唐诗/poet.song.9000.json','["豈是嫦娥月裏香。"]'),
('778414ef-4e65-409b-96ba-eaa774053bc8','句  其四','宋咸','宋','宋诗','song-poetry','','[]','居疑與世分。',6,'全唐诗/poet.song.9000.json','["居疑與世分。"]'),
('00998049-9837-4ab6-be22-76207e61a77d','句  其五','宋咸','宋','宋诗','song-poetry','','[]','虛白自爲鄰。',6,'全唐诗/poet.song.9000.json','["虛白自爲鄰。"]'),
('70a97dd5-6027-4a7a-bafa-a22320bf8bee','虎跑泉','李喬','宋','宋诗','song-poetry','','[]','虎丘巖畔識泉根，股引瓊腴此處分。',64,'全唐诗/poet.song.9000.json','["虎丘巖畔識泉根，股引瓊腴此處分。", "品絕未應容易得，地靈難使等閑聞。", "聲寒夜雜林間籟，氣潤朝隨谷口雲。", "十和清篇盈麗軸，強牽己句不成文。"]'),
('87f69805-0a2e-4b01-a0ad-e01317ad2635','句','蔡仲昌','宋','宋诗','song-poetry','','[]','高城倒影下無地，秋水涵空長有天。',16,'全唐诗/poet.song.9000.json','["高城倒影下無地，秋水涵空長有天。"]'),
('0d8ff4d9-c836-4413-8c5f-c5b67ce9199a','弔宿州妓張溫卿','黄孝先','宋','宋诗','song-poetry','','[]','人生第一莫多情，眼看仙花結不成。',32,'全唐诗/poet.song.9000.json','["人生第一莫多情，眼看仙花結不成。", "爲報兩京才子道，好將詩句哭溫卿。"]'),
('4e3d91f6-15d1-443c-919e-5b900c71f34a','留題清渭樓','黄孝先','宋','宋诗','song-poetry','','[]','黄公愛山不知休，終日不下清渭樓。',64,'全唐诗/poet.song.9000.json','["黄公愛山不知休，終日不下清渭樓。", "與官落得官下隱，愛山不得山中遊。", "朝看暮看山更好，古人今人空自老。", "天生定分不可移，白雲悠悠寄懷抱。"]'),
('3a0c4ff4-2df4-4544-bf73-eec75193359a','詩一首','黄孝先','宋','宋诗','song-poetry','','[]','天寒霜落雁來棲，歲晚川空雁不歸。',32,'全唐诗/poet.song.9000.json','["天寒霜落雁來棲，歲晚川空雁不歸。", "江海一身多少事，清風明月我沾衣。"]'),
('2730780d-295b-421a-a876-26d29eae9273','句  其一','黄孝先','宋','宋诗','song-poetry','','[]','風簷燕引五六子，露井榴開三四花。',16,'全唐诗/poet.song.9000.json','["風簷燕引五六子，露井榴開三四花。"]'),
('b9d96f6d-ef4b-4dc7-b9f8-f62aaa65e479','句  其二','黄孝先','宋','宋诗','song-poetry','','[]','日者未知裴令貴，世人爭笑禰生狂。',16,'全唐诗/poet.song.9000.json','["日者未知裴令貴，世人爭笑禰生狂。"]'),
('c0842708-e189-4b76-b53b-7bf538d6d459','句  其三','黄孝先','宋','宋诗','song-poetry','','[]','恩同花上露，留得不多時。',12,'全唐诗/poet.song.9000.json','["恩同花上露，留得不多時。"]'),
('80d79899-95ef-486e-b78d-eeb9c02ca05a','三仙祠','楊佐','宋','宋诗','song-poetry','','[]','勝蹟傳來不記來，昔聞嘗駐漢神仙。',64,'全唐诗/poet.song.9000.json','["勝蹟傳來不記來，昔聞嘗駐漢神仙。", "碑因蘇蝕無完字，址爲藤迷失舊阡。", "巖屋鐙懸松外月，石鑪香散竹間煙。", "翻思穀穗遺人日，陳迹寥寥一惘然。"]'),
('55b7cb5a-3ed1-4580-822e-1027a74404f2','四登科詩','楊申','宋','宋诗','song-poetry','','[]','榮第時皆有，通家得者稀。',48,'全唐诗/poet.song.9000.json','["榮第時皆有，通家得者稀。", "德星一門聚，晝錦四人歸。", "苦學酬身世，佳名播帝畿。", "效官修政術，此去展才徽。"]'),
('b931aff9-3bc8-4f49-b9f9-9e13e0750b78','刺桐城','呂造','宋','宋诗','song-poetry','','[]','閩海雲霞繞刺桐，往年城郭爲誰封。',32,'全唐诗/poet.song.9000.json','["閩海雲霞繞刺桐，往年城郭爲誰封。", "鷓鴣啼困悲前事，荳蔻香銷減舊容。"]'),
('30c84051-c461-4d9d-81a6-47cc99e4caf0','垗上亭落成','周珣','宋','宋诗','song-poetry','','[]','天上歸來兩鬚星，閑中搆得小茅亭。',32,'全唐诗/poet.song.9000.json','["天上歸來兩鬚星，閑中搆得小茅亭。", "東風爲我添生意，漸放階前草色青。"]'),
('eb65da38-03a6-4cd0-8714-bb8a4e6fa93f','和樞密侍郎因看海棠憶禁苑此花最盛','郭稹','宋','宋诗','song-poetry','','[]','朱欄明媚照橫塘，芳樹交加枕短牆。',64,'全唐诗/poet.song.9000.json','["朱欄明媚照橫塘，芳樹交加枕短牆。", "傳得東君深意態，染成西蜀好風光。", "破紅枝上仍施粉，繁翠陰中旋撲香。", "應爲無詩怨工部，至今含露作啼妝。"]'),
('a11f8ca2-70f3-4d52-b213-7a64fac61e52','朱萼亭侍宴','郭稹','宋','宋诗','song-poetry','','[]','九重香輦出，三月御庭開。',48,'全唐诗/poet.song.9000.json','["九重香輦出，三月御庭開。", "聖酒鸞杯酌，宮花羯鼓催。", "鶯聲壓歌管，山色滿亭臺。", "睿賞歡無極，叨陪愧不才。"]'),
('537af491-3c9c-42ea-971f-cc24ef198220','聞延州警','郭稹','宋','宋诗','song-poetry','','[]','塞日兵前慘，城煙戰後無。',48,'全唐诗/poet.song.9000.json','["塞日兵前慘，城煙戰後無。", "分明千帝紀，況乃畔天都。", "桂玉京師湧，金湯鄜路孤。", "遲迴思廟筭，端坐愧龍圖。"]'),
('29099faf-221d-48c0-bce2-e22c6da76700','茅山書院','侯遺','宋','宋诗','song-poetry','','[]','精舍依巖壑，蕭條自卜居。',48,'全唐诗/poet.song.9000.json','["精舍依巖壑，蕭條自卜居。", "山花紅躑躅，庭樹綠栟櫚。", "荷鍤朝芸隴，分鐙夜讀書。", "浮雲蒼狗幻，一笑不關余。"]'),
('dd60c802-7751-4a76-b805-5130a99f0f2a','昭潭十愛  其一','梅摯','宋','宋诗','song-poetry','','[]','我愛昭州水，湘漓共一源。',48,'全唐诗/poet.song.9000.json','["我愛昭州水，湘漓共一源。", "本無泥滓污，去有棹歌喧。", "沃野藤溪道，浮琛玉海門。", "有時新雨漲，多半是君恩。"]'),
('ae7be2f4-e1d1-44bb-b688-dcf983a32809','昭潭十愛  其二','梅摯','宋','宋诗','song-poetry','','[]','我愛昭州士，平居富塾庠。',48,'全唐诗/poet.song.9000.json','["我愛昭州士，平居富塾庠。", "興賢尊漢詔，論秀美周鄉。", "藝苑蒲開堞，書堂縹結囊。", "蟾宫前後進，一一手間香。"]'),
('61dd1045-cbf1-4fdc-bf2c-b2d85428a60f','昭潭十愛  其三','梅摯','宋','宋诗','song-poetry','','[]','我愛昭州觀，裁基壓大溪。',48,'全唐诗/poet.song.9000.json','["我愛昭州觀，裁基壓大溪。", "一樓雲駐隱，雙表鶴歸迷。", "金剜先朝語，鸞驚舊使題。", "皇恩新雨露，祈福爲蒸黎。"]'),
('ceb91ff9-6ec7-48e6-8032-c9bfc74bff83','昭潭十愛  其四','梅摯','宋','宋诗','song-poetry','','[]','我愛昭州寺，東西占景開。',48,'全唐诗/poet.song.9000.json','["我愛昭州寺，東西占景開。", "門臨九峰列，僧自五天來。", "講次花飄席，齋餘鳥下臺。", "萬民共行樂，終宴首慵迴。"]'),
('8e0cdae5-9c7c-47d9-8142-dfdd39ba1457','昭潭十愛  其五','梅摯','宋','宋诗','song-poetry','','[]','我愛昭州路，優游不險﨑。',48,'全唐诗/poet.song.9000.json','["我愛昭州路，優游不險﨑。", "九疑通舜野，八桂遶秦祠。", "亭堠相望處，漁樵有讓時。", "政無牙虎鬬，莫信義山詩。"]'),
('b010b84b-9374-40a0-8051-f2cc2c09524c','昭潭十愛  其六','梅摯','宋','宋诗','song-poetry','','[]','我愛昭州角，嗚呼右郡衙。',48,'全唐诗/poet.song.9000.json','["我愛昭州角，嗚呼右郡衙。", "萬愁縈桂水，一曲阻梅花。", "調古湘雲葉，聲乾嶺月斜。", "今愁并古恨，吹起落誰家。"]'),
('53d7d0bf-23ef-4b9b-b57c-dd3f2c215e1b','昭潭十愛  其七','梅摯','宋','宋诗','song-poetry','','[]','我愛昭州月，閑宵入綺樓。',48,'全唐诗/poet.song.9000.json','["我愛昭州月，閑宵入綺樓。", "凉生荔浦樹，冷熨桂江秋。", "朱户千家啟，浮雲萬里收。", "誰誇魏公子，飛上鄴門遊。"]'),
('2948dbb6-9a64-4da7-9c72-d610e8f1996d','昭潭十愛  其八','梅摯','宋','宋诗','song-poetry','','[]','我愛昭州樂，供官不在多。',48,'全唐诗/poet.song.9000.json','["我愛昭州樂，供官不在多。", "薰風齊樂聖，淑氣且宣和。", "謁廟知神格，鋪筵喜客過。", "聲邊無一事，對酒漫高歌。"]'),
('729834fc-bf02-4068-99c5-3eadb8bdb28f','昭潭十愛  其九','梅摯','宋','宋诗','song-poetry','','[]','我愛昭州酒，千家不禁燒。',48,'全唐诗/poet.song.9000.json','["我愛昭州酒，千家不禁燒。", "縹醪一爵舉，瘴霧四時消。", "紅葉和雲踏，青帘傍水招。", "化濃民自醉，鼓腹日歌堯。"]'),
('3c995c48-3922-4d0c-9b15-1ebb89e96c77','昭潭十愛  其一○','梅摯','宋','宋诗','song-poetry','','[]','我愛昭州果，西東此擅珍。',48,'全唐诗/poet.song.9000.json','["我愛昭州果，西東此擅珍。", "荔枝登宴美，桂子薦盤新。", "映樹珠含影，承牙玉溜津。", "二行遊宦樂，滿腹嶺南春。"]'),
('63f48cf6-2fbe-4959-aae9-3b23a0815acc','北軒敧枕','梅摯','宋','宋诗','song-poetry','','[]','苦無勤瘁補臺綱，西院西頭冷峭房。',32,'全唐诗/poet.song.9000.json','["苦無勤瘁補臺綱，西院西頭冷峭房。", "今日鈴齋一敧枕，清風不敢傲羲皇。"]'),
('f5763aa0-4dcd-4f7f-8093-5b7e3cb4209e','題南園  其一','梅摯','宋','宋诗','song-poetry','','[]','長洲茂范足珍材，剩買前山活翠栽。',32,'全唐诗/poet.song.9000.json','["長洲茂范足珍材，剩買前山活翠栽。", "客土不疏承帝力，幾多臣節共安來。"]'),
('84b920f2-611f-4389-a89a-54be05229377','題南園  其二','梅摯','宋','宋诗','song-poetry','','[]','長洲茂苑占幽奇，巖榭珍臺入翠微。',64,'全唐诗/poet.song.9000.json','["長洲茂苑占幽奇，巖榭珍臺入翠微。", "園李露濃三色秀，徑桃煙暖一香飛。", "月臨夕樹烏頻遶，風揭珠簾燕未歸。", "弭蓋暫歡成結戀，斜陽憑欄獨依依。"]'),
('5d029a90-01c2-474f-8dda-03f46b50fc5a','過白頭橋','梅摯','宋','宋诗','song-poetry','','[]','白頭橋奈白頭何，舊德如存故老歌。',32,'全唐诗/poet.song.9000.json','["白頭橋奈白頭何，舊德如存故老歌。", "不特輿梁起遺愛，大都才美服人多。"]'),
('313271d4-78dd-4d76-8c76-f45391e87998','海仙花','梅摯','宋','宋诗','song-poetry','','[]','泥根捧入故吳宮，暖力迎隨带漸紅。',32,'全唐诗/poet.song.9000.json','["泥根捧入故吳宮，暖力迎隨带漸紅。", "栽近木蘭殊有意，留連文酒繫春風。"]'),
('1ff745cb-919a-42b4-8fc1-63bf19a96a7a','新橘','梅摯','宋','宋诗','song-poetry','','[]','千頭霜熟摘來新，包貢虔修望紫宸。',32,'全唐诗/poet.song.9000.json','["千頭霜熟摘來新，包貢虔修望紫宸。", "他日功成許高退，社中還結素封人。"]'),
('ab6c1452-6005-4acc-b570-0f55a55c3691','五日公宴','梅摯','宋','宋诗','song-poetry','','[]','虎符新合晚芳天，良會難並樂與賢。',32,'全唐诗/poet.song.9000.json','["虎符新合晚芳天，良會難並樂與賢。", "心愧白公求治切，下車三月始開筵。"]'),
('01a48b42-4243-4957-949a-8f8adfdc7eab','酬張無夢','梅摯','宋','宋诗','song-poetry','','[]','一夢浮生無夢身，先生真是古之真。',32,'全唐诗/poet.song.9000.json','["一夢浮生無夢身，先生真是古之真。", "蕊函裁得瑤章祕，還寄吳門吏隱人。"]'),
('d38be753-27ca-44a7-96a1-206560ff54ff','琵琶亭','梅摯','宋','宋诗','song-poetry','','[]','陶令歸來爲逸賦，樂天謫宦起悲歌。',32,'全唐诗/poet.song.9000.json','["陶令歸來爲逸賦，樂天謫宦起悲歌。", "有弦應被無弦笑，何況臨弦泣更多。"]'),
('5ffdb7bd-2628-432b-9663-e42fe511ec6e','秀峰院','梅摯','宋','宋诗','song-poetry','','[]','影借金田潤，香隨璧月流。',24,'全唐诗/poet.song.9000.json','["影借金田潤，香隨璧月流。", "遠疑元帝植，近想誌公遊。"]'),
('69d363c3-3753-481c-8d55-6e4a557697a8','新繁縣顯曜院','梅摯','宋','宋诗','song-poetry','','[]','繡地縈回寶勢長，遍遊寧倦徙胡床。',64,'全唐诗/poet.song.9000.json','["繡地縈回寶勢長，遍遊寧倦徙胡床。", "禪齋不顧幡風影，講席亂飛花雨香。", "苔陣暗連僧榻古，蕉旗低映佛窗涼。", "我來懶上東臺上，目送霜楸感北堂。"]'),
('63edb972-6698-4c88-9c0d-ea1f5732d308','登普賢閣觀桄榔樹留小詩','梅摯','宋','宋诗','song-poetry','','[]','壯年薄宦守西甌，一瞬流光三十秋。',32,'全唐诗/poet.song.9000.json','["壯年薄宦守西甌，一瞬流光三十秋。", "今見桄榔兩嘉樹，恍如重到海邊遊。"]'),
('7ffc60f1-9d9d-44a3-8099-23b6d71ad244','新繁縣法要院孫太古壁畫羅漢','梅摯','宋','宋诗','song-poetry','','[]','絕藝知君少，誰憐太古蹤。',48,'全唐诗/poet.song.9000.json','["絕藝知君少，誰憐太古蹤。", "佳名吾黨出，逸格彼蒼鐘。", "山狖遙偷菓，田衣半剝茸。", "鄉人當保此，此畫世無重。"]'),
('e1c7cf48-e81d-40f6-8b0a-9d8a95f979d9','留別新繁縣靈慶院僧智公','梅摯','宋','宋诗','song-poetry','','[]','粉里歸來十二春，憐師心依我心淳。',32,'全唐诗/poet.song.9000.json','["粉里歸來十二春，憐師心依我心淳。", "他時行滿重相見，兜率天上第幾人。"]'),
('864f317c-ba5e-425b-8cc1-06558c419c1b','觀舊題再書  其一','梅摯','宋','宋诗','song-poetry','','[]','方丈前詩映後詩，更無塵點碧紗圍。',32,'全唐诗/poet.song.9000.json','["方丈前詩映後詩，更無塵點碧紗圍。", "老僧相顧應相笑，不似揚州刺史裏。"]'),
('e429f362-df44-4665-b41d-8c4a1007d71a','觀舊題再書  其二','梅摯','宋','宋诗','song-poetry','','[]','二十年前扣寺閣，粉牆題記墨猶存。',32,'全唐诗/poet.song.9000.json','["二十年前扣寺閣，粉牆題記墨猶存。", "重來樹老無花處，又見闍梨白首孫。"]'),
('c2e42dce-129f-4c93-a73e-93338bda808f','新繁縣秘藏院留別鄉知','梅摯','宋','宋诗','song-poetry','','[]','佛住三朝恐愛生，人歸一歲豈無情。',32,'全唐诗/poet.song.9000.json','["佛住三朝恐愛生，人歸一歲豈無情。", "鄉親鄉友銷魂地，岷水分爲隴水聲。"]'),
('52646418-6091-4b93-bc45-e33273b3cc21','靈巖','梅摯','宋','宋诗','song-poetry','','[]','煙抱千峰碧玉堆，一巖一穴漢天開。',32,'全唐诗/poet.song.9000.json','["煙抱千峰碧玉堆，一巖一穴漢天開。", "畜雲洩雨通靈派，長與蒼生救旱來。"]'),
('699ee666-252e-4478-8ef8-6f99ba1c602f','和王益留題清涼院','梅摯','宋','宋诗','song-poetry','','[]','一水明如罨畫溪，清涼佳勝古標題。',64,'全唐诗/poet.song.9000.json','["一水明如罨畫溪，清涼佳勝古標題。", "香隨講雨天花爛，聲入幡風地籟齊。", "暫到已能知覺路，縱遊何必理禪畦。", "謝公公退多行樂，五里鳴騶出縣西。"]'),
('44e5082e-74f3-4fc0-9c06-6422013079aa','留題重光寺羅漢院贈憲上人','梅摯','宋','宋诗','song-poetry','','[]','人盡遊方證佛心，師心無着外三乘。',64,'全唐诗/poet.song.9000.json','["人盡遊方證佛心，師心無着外三乘。", "蓮花結社新吟遠，玉紙抄經舊價騰。", "藥杵半和鈴索響，茶煙輕共衲靈蒸。", "我來與話高僧事，冷笑支公學養鷹。"]'),
('1242222f-0135-46ac-b735-b84e95c38e67','踏青','梅摯','宋','宋诗','song-poetry','','[]','綺場紛紛十里賒，望中煙景半春華。',64,'全唐诗/poet.song.9000.json','["綺場紛紛十里賒，望中煙景半春華。", "人遊寶歷青絲騎，路隘土橋金犢車。", "錄襯鳳頭垂逕草，紅攢鷁首照汀花。", "夕陽敲鐙餘歡在，不惜鸘裘認酒家。"]'),
('2888a9ad-199a-41bc-8ce5-17dd6cd16113','自和寒食韻','梅摯','宋','宋诗','song-poetry','','[]','龜堞春遊徑路賒，青青踏去冒煙華。',64,'全唐诗/poet.song.9000.json','["龜堞春遊徑路賒，青青踏去冒煙華。", "翠停舴艋客尋寺，紅缷羃䍦人上車。", "亭落五重沽卓酒，釵行十二步潘花。", "乘歡醉盡高陽侶，倒載歸來不認家。"]'),
('07ae8187-fc74-4436-aa41-ff299ab03f6f','和王益新繁縣東湖瑞蓮歌','梅摯','宋','宋诗','song-poetry','','[]','東湖七月湖水平，鱗波暗織簫籟聲。',272,'全唐诗/poet.song.9000.json','["東湖七月湖水平，鱗波暗織簫籟聲。", "中有植蓮一萬本，紅漪相照摛繁英。", "地靈氣粹不我測，雙葩倏如同一莖。", "黄姑織女渡銀漢，蜺旗鳳葆羅空青。", "又認英皇立湘渚，翠華不返凝怨慕。", "五十哀弦頓曉聲，駢首低昂泣珠露。", "是時主人集宴喜，湖光侵筵霞脚膩。", "朋簪峨峨盡才子，椽筆交輝雲藻麗。", "酒酣倚欄惜紅暉，炳素徘徊縈不飛。", "魏宮甄后晝方寢，彷彿有人持玉衣。", "此邑古來無異政，室家瘡痏何由慶。", "三年鼠竊例皆然，以薪救火火彌盛。", "自公柅車政克和，載途鼓腹騰謳歌。", "歌公用心日皎皎，不獨于今古應少。", "因感珍芳兩兩開，玉貫珠聯當縣沼。", "況我與公高適道，芝歌肯迹商山皓。", "嘉謀嘉猷思入陳，願將此類歸華勳。"]'),
('b3a1ec19-61d5-472d-baf1-d3b53746afac','酬贈王益舜良殿丞  其一','梅摯','宋','宋诗','song-poetry','','[]','才地淵宏筆力恢，三年粉社幸遊陪。',64,'全唐诗/poet.song.9000.json','["才地淵宏筆力恢，三年粉社幸遊陪。", "八吟麗賦憑高得，三詠雕觸選勝開。", "三苑早容收樸樕，蘭池嘗許試虺尵。", "海棠風裏甘棠政，只恐星趨節召回。"]'),
('0fc1e2d5-258b-40e3-a6a7-6cf47b2b7178','酬贈王益舜良殿丞  其二','梅摯','宋','宋诗','song-poetry','','[]','風度幽閑識宇高，暫分明寄握牛刀。',64,'全唐诗/poet.song.9000.json','["風度幽閑識宇高，暫分明寄握牛刀。", "賈生學贍思儀漢，李白才多合繼騷。", "步武即看峨豸角，對揚幾見擲麟毫。", "琴齋頌罷吟魂遠，時夢鈞天醉碧桃。"]'),
('0ea64d92-e2d1-4516-ac0b-0458995a49a3','留別東郡諸僚友  其一','梅摯','宋','宋诗','song-poetry','','[]','霽雨浮空漲海流，蟲沙龍蜃各優遊。',32,'全唐诗/poet.song.9000.json','["霽雨浮空漲海流，蟲沙龍蜃各優遊。", "津涯浩蕩雖難測，不見驚瀾曾覆舟。"]'),
('661e27ac-7ff1-4f19-9e07-90f906190d8b','留別東郡諸僚友  其二','梅摯','宋','宋诗','song-poetry','','[]','白璧紫金爲世寶，賢愚知貴莫能名。',32,'全唐诗/poet.song.9000.json','["白璧紫金爲世寶，賢愚知貴莫能名。", "廟堂祭器杯盤物，隨處得之光彩生。"]'),
('c2c125fa-29ab-460c-a4d3-2a9ac34aa3cd','留別東郡諸僚友  其三','梅摯','宋','宋诗','song-poetry','','[]','楚國良金百鍊精，深藏求售價連城。',32,'全唐诗/poet.song.9000.json','["楚國良金百鍊精，深藏求售價連城。", "豈徒豐獄吹毛利，兼有秦臺照膽明。"]'),
('c028d59e-e45f-45f8-ab11-4dfbf74c0cad','留別東郡諸僚友  其四','梅摯','宋','宋诗','song-poetry','','[]','祖帳飄揚堤柳邊，北來飛蓋稱翩翩。',32,'全唐诗/poet.song.9000.json','["祖帳飄揚堤柳邊，北來飛蓋稱翩翩。", "追隨不忍輕言別，回首城樓沒晚煙。"]'),
('ea1745c7-31ed-4b9c-ad89-fd93b91138ca','留別東郡諸僚友  其五','梅摯','宋','宋诗','song-poetry','','[]','空府同來賢大夫，短亭門外即長途。',32,'全唐诗/poet.song.9000.json','["空府同來賢大夫，短亭門外即長途。", "不辭爛醉尊前倒，明日此觀重得無。"]'),
('000fa204-0132-4b4e-bb34-2184cf9acc1f','歸雁亭','梅摯','宋','宋诗','song-poetry','','[]','東風楊柳杏花飛，曾伴先生酒巵。',62,'全唐诗/poet.song.9000.json','["東風楊柳杏花飛，曾伴先生酒巵。", "前輩風流那復見，小亭煙雨漫相思。", "城邊春草路南北，山下河梁人別離。", "一尺短書湘水闊，年年愁絕雁時。"]'),
('73f61a36-e70f-480d-b48b-29f70286151c','偶書小詩寄永螄內翰','梅摯','宋','宋诗','song-poetry','','[]','酒戶棋兵孰與儕，月宵曾遇六天街。',32,'全唐诗/poet.song.9000.json','["酒戶棋兵孰與儕，月宵曾遇六天街。", "南燕到後懷君遠，時入樓東畫舫齋。"]'),
('9cd313d7-b099-40ed-9537-abf4cb945a16','句  其一','梅摯','宋','宋诗','song-poetry','','[]','寺僧日扣粧鐘起，園客時翻輦路耕。',16,'全唐诗/poet.song.9000.json','["寺僧日扣粧鐘起，園客時翻輦路耕。"]'),
('b1c716ee-bf38-42ba-8431-0b46a1e19b2b','句  其二','梅摯','宋','宋诗','song-poetry','','[]','堂有虛白閑。',6,'全唐诗/poet.song.9000.json','["堂有虛白閑。"]'),
('b1c96dbb-40a8-4aa3-a140-a56b23a86e59','句  其三','梅摯','宋','宋诗','song-poetry','','[]','珠峰塔影孤。',6,'全唐诗/poet.song.9000.json','["珠峰塔影孤。"]'),
('ca359a0c-6d33-445f-a479-ac44c8fefbcb','海棠  其一','石揚休','宋','宋诗','song-poetry','','[]','化工裁翦用功專，濯錦江頭價最偏。',64,'全唐诗/poet.song.9000.json','["化工裁翦用功專，濯錦江頭價最偏。", "酷愛幾思憑畫手，難題渾覺挫詩權。", "艷凝絳纈深深染，樹認紅綃密密連。", "因想當年武平一，枝枝眷賜侍臣先。"]'),
('b38c3280-391d-4996-ba7f-d20c180a67df','海棠  其二','石揚休','宋','宋诗','song-poetry','','[]','開盡夭桃落盡梨，淺荂深萼照華池。',64,'全唐诗/poet.song.9000.json','["開盡夭桃落盡梨，淺荂深萼照華池。", "都緣西蜀盤根遠，豈是東君屬意遲。", "煙慘別容曛宿酒，露凝啼臉失臙脂。", "須知賈相風流甚，曾許神仙品格奇。"]'),
('a7346e53-3563-4396-8462-9b5b882669c8','謝文瑩師攜琴見訪','石揚休','宋','宋诗','song-poetry','','[]','鄭衛湮俗耳，正聲追不回。',48,'全唐诗/poet.song.9000.json','["鄭衛湮俗耳，正聲追不回。", "誰傳廣陵操，老盡嶧陽材。", "古意爲師復，清風尋我來。", "幽陰竹軒下，重約月明開。"]'),
('35133676-c37e-4ba8-8adb-d56e059a1300','句','石揚休','宋','宋诗','song-poetry','','[]','皇朝四十三龍首，身到黄扉止四人。',16,'全唐诗/poet.song.9000.json','["皇朝四十三龍首，身到黄扉止四人。"]'),
('03d1700a-a74e-4b5b-bdae-a636b202ca5e','述懷','劉沆','宋','宋诗','song-poetry','','[]','虎生三日便窺牛，獵犬寧能掉尾求。',64,'全唐诗/poet.song.9000.json','["虎生三日便窺牛，獵犬寧能掉尾求。", "若不去登黄閣貴，便須來伴赤松游。", "奴顔婢舌誠堪恥，羊狠狼貪自合羞。", "現尺太阿星斗煥，何時去取魏齊頭。"]'),
('ee0e59f1-0098-439f-a1d1-c2085b144b48','小孤山','劉沆','宋','宋诗','song-poetry','','[]','擎天有八柱，一柱此焉存。',48,'全唐诗/poet.song.9000.json','["擎天有八柱，一柱此焉存。", "石聳千尋勢，波留四面痕。", "江湖中作鎮，風浪裏盤根。", "平地安然者，饒他五嶽尊。"]'),
('f93a9812-8b02-4eb7-a38e-2019de4d3ef5','送鄉人尹鑑登第歸','劉沆','宋','宋诗','song-poetry','','[]','少年相款老相逢，鄉舉雖同遇不同。',64,'全唐诗/poet.song.9000.json','["少年相款老相逢，鄉舉雖同遇不同。", "我已位塵三事後，君方名列五科中。", "榮登莫計名高下，宦達須由善始終。", "若到鄉關人見問，爲言歸思滿秋風。"]'),
('b04308f2-35e7-4ed6-8090-ceb698d65d81','聰明泉','劉沆','宋','宋诗','song-poetry','','[]','義山山下有靈泉，泉號聰明自古傳。',32,'全唐诗/poet.song.9000.json','["義山山下有靈泉，泉號聰明自古傳。", "四百年中三出相，不才何幸繼前賢。"]'),
('5d72258c-552e-41d1-9b5a-89b8554acb55','句','劉沆','宋','宋诗','song-poetry','','[]','三月內方有，百花中更無。',12,'全唐诗/poet.song.9000.json','["三月內方有，百花中更無。"]'),
('a91ea2df-5df1-4339-903b-3fb1c1daf0b3','宿靈巖寺','張揆','宋','宋诗','song-poetry','','[]','再見祇園樹，流光二十年。',48,'全唐诗/poet.song.9000.json','["再見祇園樹，流光二十年。", "依然山水地，況是雪霜天。", "閣影移寒日，鐘聲出暝煙。", "微官苦奔走，一宿亦前緣。"]'),
('0caa1dbe-1b30-44bf-967a-51e163d84a3b','賀兩府入東西府','張掞','宋','宋诗','song-poetry','','[]','五仙同日集蓬萊，玉宇珠簾次第開。',64,'全唐诗/poet.song.9000.json','["五仙同日集蓬萊，玉宇珠簾次第開。", "乍向壺中窺日月，猶疑海上見樓臺。", "光生金鉉調元地，榮極璿樞命世才。", "共荷盡賢天地寵，定知霖雨及時來。"]'),
('1cdbad84-7089-4ee0-b904-1ac3e8bec587','題資福院平綠軒','張掞','宋','宋诗','song-poetry','','[]','禪窗虛敞瞰西南，野色溪光接畫簷。',32,'全唐诗/poet.song.9000.json','["禪窗虛敞瞰西南，野色溪光接畫簷。", "雲去碧天無間斷，一眉依約見山尖。"]'),
('13c605f1-d5d4-454c-8ae6-36814698c711','靜照堂','張掞','宋','宋诗','song-poetry','','[]','牛斗光芒下，江山形勝中。',48,'全唐诗/poet.song.9000.json','["牛斗光芒下，江山形勝中。", "招提萬法本，靜照一堂空。", "花木含春意，門庭話古風。", "支郎乞詩什，愧匪雅南工。"]'),
('0df8a863-fd35-4ac6-a13a-f3ec8645de00','留題靈巖寺','張掞','宋','宋诗','song-poetry','','[]','再見祇園樹，流光二十年。',48,'全唐诗/poet.song.9000.json','["再見祇園樹，流光二十年。", "依然山水地，況是雪霜天。", "閣影移寒日，鐘聲出暝煙。", "粗官苦奔走，一宿亦前緣。"]'),
('e18b5d4e-9ed2-45f7-a7fc-3c5427ad2831','送議公詳公詩','張掞','宋','宋诗','song-poetry','','[]','峨峨日觀出雲層，西麓靈庵寄佛乘。',64,'全唐诗/poet.song.9000.json','["峨峨日觀出雲層，西麓靈庵寄佛乘。", "金地闕人安大衆，玉京選士得高僧。", "霜刀斷腕羣魔伏，鈿軸存心奧義增。", "顧我舊山泉石美，湔除諸惡賴賢能。"]'),
('52ce3588-b065-40d8-a310-41dde659cbaa','敕差靈巖寺主大師詳公赴寺','張掞','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','黄紙除書下九天，岱宗西麓鎮金田。',64,'全唐诗/poet.song.9000.json','["黄紙除書下九天，岱宗西麓鎮金田。", "鷲峰肅肅臻多士，蘭社熙熙撫衆賢。", "像室光華輝曉日，禪心清凈擢秋蓮。", "山泉自此增高潔，雲集十方結勝緣。"]'),
('7837d09f-f650-4d9f-abb9-d2794b38ff0b','閑居有感','李宗易','宋','宋诗','song-poetry','','[]','進退荷君恩，孤懷豈易論。',48,'全唐诗/poet.song.9000.json','["進退荷君恩，孤懷豈易論。", "以閑銷日月，何力報乾坤。", "架上書千卷，花前酒一尊。", "相持兩成癖，此外盡忘言。"]'),
('0518d530-20fb-43f3-a986-a068a3308ea6','靜居','李宗易','宋','宋诗','song-poetry','','[]','大都心足身還足，祇恐身閑心未閑。',32,'全唐诗/poet.song.9000.json','["大都心足身還足，祇恐身閑心未閑。", "但得心閑隨處樂，不須朝市雨雲山。"]'),
('d4203598-7971-4570-9e00-bbbe1ba65232','重建羊太傅祠和王原叔句','李宗易','宋','宋诗','song-poetry','','[]','叔子祠荒歲已深，異時賢守重登臨。',64,'全唐诗/poet.song.9000.json','["叔子祠荒歲已深，異時賢守重登臨。", "峴山岑寂瞻風概，漢水靈長想德音。", "奉詔始聞新締茸，有知那復嘆湮沈。", "又刊翠琰留南夏，先後功名照古今。"]'),
('cd1f19b9-67c6-4669-9859-37ab8f08494c','句  其一','李兌','宋','宋诗','song-poetry','','[]','高鳥翔雲外。',6,'全唐诗/poet.song.9000.json','["高鳥翔雲外。"]'),
('4e833f65-7341-43d4-877d-09e43e4485db','句  其二','李兌','宋','宋诗','song-poetry','','[]','煙浮平野碧。',6,'全唐诗/poet.song.9000.json','["煙浮平野碧。"]'),
('a109a9fb-7151-4630-88c8-289eab7b5d78','句  其三','李兌','宋','宋诗','song-poetry','','[]','未敢嘆途窮。',6,'全唐诗/poet.song.9000.json','["未敢嘆途窮。"]'),
('68f673b9-f87a-46a0-bcef-a4e2736f97df','句  其四','李兌','宋','宋诗','song-poetry','','[]','萬壑初收雨。',6,'全唐诗/poet.song.9000.json','["萬壑初收雨。"]'),
('9727cf02-39c3-4d73-ba40-2448158693e8','句  其五','李兌','宋','宋诗','song-poetry','','[]','日抹平山紅。',6,'全唐诗/poet.song.9000.json','["日抹平山紅。"]'),
('e3e2ea6a-ce9f-4f9f-a8b9-0ce0614ad651','句  其六','李兌','宋','宋诗','song-poetry','','[]','何處不遲留。',6,'全唐诗/poet.song.9000.json','["何處不遲留。"]'),
('324924cb-4489-4f81-adc9-44fab91bf79f','與杜秀才','李先','宋','宋诗','song-poetry','','[]','南極多老人，及見九代孫。',48,'全唐诗/poet.song.9000.json','["南極多老人，及見九代孫。", "君今古儋州，氣質清且溫。", "今年八十二，頗覺行步奔。", "白鬚映紅頰，疑是羲皇人。"]'),
('92039723-03b8-4cf3-8101-730ec398166f','句','李先','宋','宋诗','song-poetry','','[]','寧舍濟川航。',6,'全唐诗/poet.song.9000.json','["寧舍濟川航。"]'),
('2e97312c-9613-4623-81b4-9ba8ced5b86e','宴集','胡宿','宋','宋诗','song-poetry','','[]','鬰陶倦煩暑，爽豁逢蕭辰。',72,'全唐诗/poet.song.9000.json','["鬰陶倦煩暑，爽豁逢蕭辰。", "開樽有歡伯，傾坐得嘉賓。", "雕盤薦肥羜，寶刀膾霜鱗。", "清談屏世務，善謔到天真。", "須言燭可繼，莫訴杯行頻。", "至道諒在己，外物不關身。"]'),
('c22efeb3-bfd8-4183-bc6f-fdba8b5e3e9e','雜興','胡宿','宋','宋诗','song-poetry','','[]','嚴霜沾百草，不問菊與蘭。',48,'全唐诗/poet.song.9000.json','["嚴霜沾百草，不問菊與蘭。", "行觀秀色萎，坐使芳意殘。", "有酒聊自把，無萱良鮮歡。", "安得青精飯，爲駐顔如丹。"]'),
('30c0ce5c-b07e-4b57-9362-3bba283e3ea8','怨思','胡宿','宋','宋诗','song-poetry','','[]','陰蟲思衰草，羈雌啼空林。',72,'全唐诗/poet.song.9000.json','["陰蟲思衰草，羈雌啼空林。", "盛秋授寒服，獨夜搗清砧。", "影孤隨月瘦，肌薄怯霜侵。", "平生託義分，夢想在容音。", "山頭憐化石，陌上重辭金。", "安得兩黄鵠，因之傳此心。"]'),
('5760de22-d1f5-4994-b0c3-0eb56c997725','怨詩楚調示龐主簿及鄧治中','胡宿','宋','宋诗','song-poetry','','[]','我生豈不辰，貧賤亦偶然。',120,'全唐诗/poet.song.9000.json','["我生豈不辰，貧賤亦偶然。", "讀書飯脫粟，差可樂餘年。", "藝麻室南端，種桑屋東偏。", "弱婦事紡績，丁男長力田。", "瓶儲苟不乏，安用三百廛。", "老翁飽食罷，日晏尚高眠。", "豈知天地間，陵谷有變遷。", "獨恨生苦晚，不在羲皇前。", "嘗聞父老言，醉鄉隔烽烟。", "安得盈觴酒，時復中聖賢。"]'),
('80bd4043-4331-4583-91b2-29e41aab56c8','碧樓','胡宿','宋','宋诗','song-poetry','','[]','中條何峨峨，映我縹碧瓦。',36,'全唐诗/poet.song.9000.json','["中條何峨峨，映我縹碧瓦。", "汾水望飛雲，參旂眺綠野。", "美哉山與河，河流疾于馬。"]'),
('44de8c77-56ce-4a24-8414-74a1f16c4ddf','讀僧長吉詩','胡宿','宋','宋诗','song-poetry','','[]','生民類能言，茲文特淵邈。',288,'全唐诗/poet.song.9000.json','["生民類能言，茲文特淵邈。", "精韞在希微，幽通資寫託。", "狀物無遁形，舒情有至樂。", "自非妙解機，誰抽神奧籥。", "大士棲綠巖，門前即台嶽。", "翠屏何峨峨，千仞拂寥廓。", "芝朮被諸峰，煙霞興衆壑。", "中安仁智居，旁研華竺學。", "觀法識非空，了心無少著。", "人境既相於，神明信超若。", "作詩三百篇，平淡猶古樂。", "于言雖未忘，在理已能覺。", "天質自然美，亦如和氏璞。", "貯之古錦囊，訪我杼山郭。", "杼山空崔嵬，然公久寂寞。", "中間三百年，寂寞無人作。", "何意正始音，緒餘在清角。", "山旁夏欲休，林英春稍落。", "吟登蒼卞餘，歸夢華頂數。", "駕言整巾瓶，仍前侶猿鶴。", "誰言雲無心，還依故山泊。", "顧予禽鹿姿，繆此縻人爵。", "居常眩韶音，幾駭頓金絡。", "比將親椒蘭，端欲甘藜藿。"]'),
('5b64ddda-c780-4692-85e1-7ca6970352ac','池臺','胡宿','宋','宋诗','song-poetry','','[]','層臺遲夕娟，清池弄秋水。',36,'全唐诗/poet.song.9000.json','["層臺遲夕娟，清池弄秋水。", "蟾明桂樹間，魚躍蓮葉底。", "如何惠莊津，乃在蒲城裏。"]'),
('b7209f95-22a6-4326-909c-a373c40330e3','遠行','胡宿','宋','宋诗','song-poetry','','[]','古有悲秋篇，遠行第三句。',72,'全唐诗/poet.song.9000.json','["古有悲秋篇，遠行第三句。", "人情重辭家，客意倦長路。", "征馬陟前岡，栖烏集喬樹。", "慘淡層陰生，號呼勁風怒。", "匣琴徒自携，杯酒與誰遇。", "衣带緩于前，衣香非復故。"]'),
('0222af26-0579-437e-83a0-c43ab06f9180','遊矚','胡宿','宋','宋诗','song-poetry','','[]','旻宇斗澄霽，池臺始登臨。',72,'全唐诗/poet.song.9000.json','["旻宇斗澄霽，池臺始登臨。", "幽芳無艷質，爽籟有真音。", "閒雲乍明滅，寒鶒忽浮沈。", "青山晴好望，白道細堪尋。", "疏蟬嘒急管，躍鯉應鳴琴。", "微風獵椒桂，快哉一披襟。"]'),
('f9131bde-3702-48d5-ab27-437a107740f0','野廬','胡宿','宋','宋诗','song-poetry','','[]','休舍松石間，外物不可必。',36,'全唐诗/poet.song.9000.json','["休舍松石間，外物不可必。", "一馬究微言，五禽治生術。", "仁智得所廬，吉祥來此室。"]'),
('b79aab1a-ff76-4141-a96a-f950314095d5','珍禽亭','胡宿','宋','宋诗','song-poetry','','[]','仁人坐高齋，忘機宅真粹。',36,'全唐诗/poet.song.9000.json','["仁人坐高齋，忘機宅真粹。", "魚鳥沐餘恩，樹石蒙善氣。", "珍哉島上禽，託身良得地。"]'),
('b5d0d87b-76c6-4aa2-a8e9-d64f5826e553','靜齋','胡宿','宋','宋诗','song-poetry','','[]','鈴閣侍衛稀，幕府文書省。',36,'全唐诗/poet.song.9000.json','["鈴閣侍衛稀，幕府文書省。", "石上試真茶，松間移小鼎。", "吏師所至清，仁者本便靜。"]'),
('cc9bd3ae-5f56-43cb-b24d-b1c0554ea12d','惜花亭','胡宿','宋','宋诗','song-poetry','','[]','層陰養花天，亭榭多春色。',36,'全唐诗/poet.song.9000.json','["層陰養花天，亭榭多春色。", "午氣入衣香，東風吹酒力。", "睠戀冶城遊，黄金良易得。"]'),
('4bb22744-1c03-4664-b2e4-af19131493cc','寄題齋館','胡宿','宋','宋诗','song-poetry','','[]','東南有仙人，玉案經近侍。',228,'全唐诗/poet.song.9000.json','["東南有仙人，玉案經近侍。", "爲愛飛來峰，翻然下平地。", "白雲相與栖，絳雪居嘗餌。", "日作冷泉游，時尋徑山醉。", "徑山有五峰，參差標紫翠。", "西山玉芝巖，縹緲多雲氣。", "巖間名勝僧，除館待公至。", "施樹得楩楠，開軒對松桂。", "啼鳥傍簷楹，鳴泉落階砌。", "蘚徑闊三條，籃輿時一詣。", "汲井試茶腴，援琴和松吹。", "榮啟老來歌，華胥午間睡。", "追隨支許遊，嘯詠羲皇治。", "武林賢主人，官儀斗樞貴。", "同是老成人，俱懷方外志。", "流水與斷墁，神交復心契。", "數幅伻山圖，三伏挂廳事。", "長謠紫芝曲，遠寄青霞意。", "他年羾赤霄，定挹浮丘袂。"]'),
('199c8abf-51db-4a16-8c12-8ec87c903c1d','題飲光亭','胡宿','宋','宋诗','song-poetry','','[]','林風引石溜，席上清且寒。',36,'全唐诗/poet.song.9000.json','["林風引石溜，席上清且寒。", "主人白羽扇，觴客水精盤。", "絃歌泛宮羽，酒面生波瀾。"]'),
('bd9b817d-59c3-4eaf-b079-4415f6744597','送客','胡宿','宋','宋诗','song-poetry','','[]','秋意不自適，況復登河梁。',72,'全唐诗/poet.song.9000.json','["秋意不自適，況復登河梁。", "眷言送歸客，徙倚見斜陽。", "雜珮解席上，斑騅嘶路傍。", "風雲感素節，絃管思清商。", "菊殘餘老蕊，蕙晚非新香。", "何以致叩叩，臨行持一觴。"]'),
('2e530192-eda8-4911-b0ac-d2382f2bc0d7','邊思','胡宿','宋','宋诗','song-poetry','','[]','勁氣初折膠，奔書聞插羽。',84,'全唐诗/poet.song.9000.json','["勁氣初折膠，奔書聞插羽。", "寒金刁斗鳴，夕火兜零舉。", "霜威畫角雄，月思清笳苦。", "驃騎出鏖兵，輕車前確虜。", "一鼓繫名王，三捷獻英主。", "天山掛雕弓，玉塞休强弩。", "龍額近封侯，華堂盛歌舞。"]'),
('904df000-0c7c-4c37-8c70-4b810f0679a0','彭山贈貫之','胡宿','宋','宋诗','song-poetry','','[]','彭山隔重湖，落日見孤塔。',120,'全唐诗/poet.song.9000.json','["彭山隔重湖，落日見孤塔。", "揚舲入空曠，煙樹散鵝鴨。", "山中老臞仙，萬頃纖芥納。", "乘風落珠唾，暝色遠相答。", "平生爾汝分，磁鐵契已狎。", "萬緣一笑空，箇處無剩法。", "方舟過谷隠，風雨寒霎霎。", "黎明带星歸，尚及齋鼓踏。", "臨岐戒後會，梅熟新秧插。", "期我散縑楮，莫忘鷗盟歃。"]'),
('e235f0f6-6212-4eef-8e6d-7bf727c4c631','謝御書飛白扇子歌','胡宿','宋','宋诗','song-poetry','','[]','聖皇多才復多藝，包犧徒云造書契。',321,'全唐诗/poet.song.9000.json','["聖皇多才復多藝，包犧徒云造書契。", "坦然制作侔日星，煥有文章賁天地。", "太宗飛白入于神，玉堂四字標奇勢。", "寶跗一學造其精，聖祖神孫知善繼。", "萬幾餘力表全能，三紀體仁成至治。", "金壺貯墨奉嚴禋絃，往年大揭明堂門。", "素龍鱗角儼欲舉，白鳳翅翼行將翻。", "八會遼邈不可見，六書細碎何足論。", "仁慈原廟多珍榜，河漢黼黻輝朝昏。", "天公常敕六丁護，在在處處祥煙屯。", "邇英叨籍侍清切，浴蘭每歲逢佳節。", "鮫人海底織冰綃，宮工天上裁紈雪。", "彌綸寶箑已珍華，泛灑神毫益精絕。", "紛如薄霧翳靈芝，淡若輕雲拂初日。", "免令常侍登御牀，就降王人頒睿札。", "玉璽封題光姓名，孤臣拜手歡且榮。", "暘炎扇暍昭慈眷，夙夜安民彰聖情。", "九門纔傳妙墨出，三殿已覺薰風生。", "標章有愧參鴻碩，視草無能裨聖明。", "短歌莫盡形容美，微志聊依頌嘆聲。"]'),
('c43e9809-9089-49b1-8e1d-6783b13c797f','早春','胡宿','宋','宋诗','song-poetry','','[]','燠沐陽和盛，蒼筤老色濃。',48,'全唐诗/poet.song.9000.json','["燠沐陽和盛，蒼筤老色濃。", "大明消積雪，青靄遍諸峰。", "遠浪浮赬鯉，驚雷起蟄龍。", "去年南去雁，薊北又相逢。"]'),
('3aa2990a-ae72-4f37-864d-bc7991870dfa','津橋晚望','胡宿','宋','宋诗','song-poetry','','[]','徙倚津橋上，蒼凉樹幄中。',48,'全唐诗/poet.song.9000.json','["徙倚津橋上，蒼凉樹幄中。", "江雲數峰黑，山日半規紅。", "菖葉深依水，蘭苕迥得風。", "雩壇春服就，歸思羨沂童。"]'),
('dd1502cb-f983-4b43-a116-4308e493cf41','井桐','胡宿','宋','宋诗','song-poetry','','[]','一水清無底，雙桐碧有情。',48,'全唐诗/poet.song.9000.json','["一水清無底，雙桐碧有情。", "銀牀翻晝影，玉虎墮秋聲。", "露葉游絲斷，風枝宿鳥驚。", "隔簾人不寐，又送月西傾。"]'),
('c2023c2c-bb26-4345-be86-607eb360117b','春晚郊野','胡宿','宋','宋诗','song-poetry','','[]','岸幘坐前楹，天圍極望青。',48,'全唐诗/poet.song.9000.json','["岸幘坐前楹，天圍極望青。", "月華開嶺霧，風影碎池星。", "重露驚棲鶴，幽叢带暗螢。", "塵機心久息，寧待據梧瞑。"]'),
('f76020f5-447e-42dd-82fe-943db0c54ff9','舟次江口','胡宿','宋','宋诗','song-poetry','','[]','香吹生蘭渚，飛霜下荻州。',48,'全唐诗/poet.song.9000.json','["香吹生蘭渚，飛霜下荻州。", "月波清浸夜，天幕冷垂秋。", "遠嶼迎潮沒，寒烟護水浮。", "沖歌來澤畔，知是採菱舟。"]'),
('467dd520-435b-4d9c-9cf1-32996fa09cf3','賦江皋','胡宿','宋','宋诗','song-poetry','','[]','目睇蘭臯上，春波泛早暉。',48,'全唐诗/poet.song.9000.json','["目睇蘭臯上，春波泛早暉。", "畫船人競渡，繡羽雉交飛。", "島樹殘潮落，汀花宿霧稀。", "短亭迷酒市，官柳綠依依。"]'),
('ae7c47dc-2ca1-49dd-9bea-b94d33b915dc','西郊二首  其一','胡宿','宋','宋诗','song-poetry','','[]','高樓十二曲，倚遍到斜暉。',48,'全唐诗/poet.song.9000.json','["高樓十二曲，倚遍到斜暉。", "天幕清無翳，溪雲凍不飛。", "斷岡殘燒盡，遠樹宿禽歸。", "久憶蓮華社，鐘聲隔翠微。"]'),
('178028d1-9760-46c1-9bd2-3420f0af6883','西郊二首  其二','胡宿','宋','宋诗','song-poetry','','[]','遠籟生寒野，平蕪弄夕陽。',48,'全唐诗/poet.song.9000.json','["遠籟生寒野，平蕪弄夕陽。", "天寒空鳥道，水落見魚梁。", "島樹風仍蕩，汀葭日映黄。", "津樓慵極目，杳杳白雲鄉。"]');
